import type { Metadata } from "next";
import Script from "next/script";
import "./globals.css";

const GA_ID = process.env.NEXT_PUBLIC_GA_ID;

export const metadata: Metadata = {
  title: "Goon | A Private Members Club — Coming Soon",
  description:
    "Goon is an exclusive private members club in West Hollywood delivering authentic old European aristocratic luxury for high-net-worth gay and lesbian individuals. The Last Great Sanctuary. Coming soon.",
};

export default function RootLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <html lang="en">
      <body className="antialiased">
        {GA_ID && (
          <>
            <Script
              src={`https://www.googletagmanager.com/gtag/js?id=${GA_ID}`}
              strategy="afterInteractive"
            />
            <Script id="ga4-init" strategy="afterInteractive">
              {`window.dataLayer = window.dataLayer || [];
function gtag(){dataLayer.push(arguments);}
gtag('js', new Date());
gtag('config', '${GA_ID}');`}
            </Script>
          </>
        )}
        {children}
      </body>
    </html>
  );
}

import type { Config } from "tailwindcss";

const config: Config = {
  content: [
    "./pages/**/*.{js,ts,jsx,tsx,mdx}",
    "./components/**/*.{js,ts,jsx,tsx,mdx}",
    "./app/**/*.{js,ts,jsx,tsx,mdx}",
  ],
  theme: {
    extend: {
      colors: {
        charcoal: "#121212",
        "rich-black": "#0A0A0A",
        gold: "#C9A96E",
        "muted-text": "#A3A3A3",
      },
      fontFamily: {
        inter: ["Inter", "sans-serif"],
        playfair: ['"Playfair Display"', "serif"],
      },
    },
  },
  plugins: [],
};

export default config;

@tailwind base;
@tailwind components;
@tailwind utilities;

@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Playfair+Display:ital,wght@0,400;0,500;0,600;0,700;1,400;1,500&display=swap');

html {
  scroll-behavior: smooth;
}

body {
  background-color: #0A0A0A;
  color: #FFFFFF;
  font-family: 'Inter', sans-serif;
}

/* Gold gradient text utility */
.text-gold-gradient {
  background: linear-gradient(135deg, #C9A96E 0%, #E2C992 50%, #C9A96E 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* Subtle gold border glow */
.gold-glow {
  box-shadow: 0 0 20px rgba(201, 169, 110, 0.1);
}

/* Divider line */
.gold-divider {
  height: 1px;
  background: linear-gradient(90deg, transparent, #C9A96E, transparent);
}

/* Custom scrollbar */
::-webkit-scrollbar {
  width: 6px;
}
::-webkit-scrollbar-track {
  background: #0A0A0A;
}
::-webkit-scrollbar-thumb {
  background: #333;
  border-radius: 3px;
}
::-webkit-scrollbar-thumb:hover {
  background: #C9A96E;
}

/* Input focus ring */
input:focus {
  outline: none;
