"use client";

import { useState } from "react";

export default function Waitlist() {
  const [email, setEmail] = useState("");
  const [status, setStatus] = useState<
    "idle" | "loading" | "success" | "error"
  >("idle");
  const [message, setMessage] = useState("");

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!email) return;

    setStatus("loading");

    try {
      const res = await fetch("/api/waitlist", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email }),
      });

      const data = await res.json();

      if (res.ok) {
        setStatus("success");
        setMessage(data.message || "Your application has been received.");
        setEmail("");
      } else {
        setStatus("error");
        setMessage(data.error || "Something went wrong.");
      }
    } catch {
      setStatus("error");
      setMessage("Network error. Please try again.");
    }
  }

  return (
    <section id="waitlist" className="py-24 px-6 bg-[#1C1C1E]">
      <div className="max-w-xl mx-auto text-center">
        <p className="font-inter text-[#B8894D] text-sm tracking-[0.25em] uppercase mb-4">
          Founding Membership
        </p>
        <h2 className="font-playfair text-4xl md:text-5xl font-semibold text-[#F5F0EB] mb-4">
          Request an Invitation
        </h2>
        <p className="font-inter text-base text-[#F5F0EB]/70 mb-10 leading-relaxed">
          Founding membership is limited. Leave your address and you will be the
          first invited when the doors of Goon open in West Hollywood. No spam,
          no public list — only a quiet note when the house is ready.
        </p>

        <form onSubmit={handleSubmit} className="flex flex-col sm:flex-row gap-3">
          <input
            type="email"
            required
            value={email}
            onChange={(e) => {
              setEmail(e.target.value);
              if (status !== "idle") setStatus("idle");
            }}
            placeholder="your@email.com"
            className="flex-1 bg-[#6B1D2F]/15 border border-[#B8894D]/25 rounded-sm px-5 py-4 text-[#F5F0EB] font-inter placeholder:text-[#F5F0EB]/40 focus:border-[#B8894D] transition-colors"
          />
          <button
            type="submit"
            disabled={status === "loading"}
            className="border border-[#B8894D] text-[#B8894D] px-8 py-4 rounded-sm font-inter text-sm tracking-[0.2em] uppercase hover:bg-[#B8894D] hover:text-[#1C1C1E] transition-all duration-300 disabled:opacity-50"
          >
            {status === "loading" ? "Sending..." : "Request Founding Membership"}
          </button>
        </form>

        {message && (
          <p
            className={`mt-6 font-inter text-sm ${
              status === "success" ? "text-[#B8894D]" : "text-[#6B1D2F]"
            }`}
          >
            {message}
          </p>
        )}
      </div>
    </section>
  );
}

import { NextResponse } from "next/server";
import { readFile, writeFile } from "fs/promises";
import { existsSync } from "fs";
import path from "path";

const DATA_FILE = path.join(process.cwd(), "data", "waitlist.json");

interface WaitlistEntry {
  email: string;
  subscribedAt: string;
}

async function loadEntries(): Promise<WaitlistEntry[]> {
  try {
    if (!existsSync(DATA_FILE)) return [];
    const raw = await readFile(DATA_FILE, "utf-8");
    return JSON.parse(raw);
  } catch {
    return [];
  }
}

async function saveEntries(entries: WaitlistEntry[]) {
  const dir = path.dirname(DATA_FILE);
  if (!existsSync(dir)) {
    const { mkdir } = await import("fs/promises");
    await mkdir(dir, { recursive: true });
  }
  await writeFile(DATA_FILE, JSON.stringify(entries, null, 2));
}

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { email } = body;

    if (!email || typeof email !== "string") {
      return NextResponse.json(
        { error: "A valid email address is required." },
        { status: 400 }
      );
    }

    const normalized = email.trim().toLowerCase();
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(normalized)) {
      return NextResponse.json(
        { error: "Please enter a valid email address." },
        { status: 400 }
      );
    }

    const entries = await loadEntries();

    if (entries.some((e) => e.email === normalized)) {
      return NextResponse.json(
        { message: "You're already on the waitlist. We'll be in touch." },
        { status: 200 }
      );
    }

    entries.push({ email: normalized, subscribedAt: new Date().toISOString() });
    await saveEntries(entries);

    return NextResponse.json(
      { message: "Welcome to the waitlist. We'll be in touch soon." },
      { status: 201 }
    );
  } catch {
    return NextResponse.json(
      { error: "Something went wrong. Please try again." },
      { status: 500 }
    );
  }
}

export async function GET() {
  try {
    const entries = await loadEntries();
    return NextResponse.json({ count: entries.length });
  } catch {
    return NextResponse.json({ count: 0 });
  }
}

"use client";

import { useState } from "react";

// UI-only gate. The charter PDF itself is a placeholder (#) per spec.
const CHARTER_PASSPHRASE = "founding-charter";

export default function Charter() {
  const [pass, setPass] = useState("");
  const [unlocked, setUnlocked] = useState(false);
  const [error, setError] = useState(false);

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (pass.trim().toLowerCase() === CHARTER_PASSPHRASE) {
      setUnlocked(true);
      setError(false);
    } else {
      setError(true);
    }
  }

  return (
    <section id="charter" className="py-24 px-6 bg-[#141415]">
      <div className="max-w-xl mx-auto text-center">
        <p className="font-inter text-[#B8894D] text-sm tracking-[0.25em] uppercase mb-4">
          The Founding Charter
        </p>
        <h2 className="font-playfair text-4xl md:text-5xl font-semibold text-[#F5F0EB] mb-6">
          Read the charter.
        </h2>
        <p className="font-inter text-base text-[#F5F0EB]/65 mb-10 leading-relaxed">
          The Founding Charter outlines the principles, privileges, and
          obligations of Goon&rsquo;s first members. It is reserved for those
          who hold the passphrase — shared privately with invited founding
          applicants.
        </p>

        {unlocked ? (
          <a
            href="#placeholder"
            download
            className="inline-flex items-center gap-3 border border-[#B8894D] text-[#B8894D] px-10 py-4 rounded-sm font-inter text-sm tracking-[0.2em] uppercase hover:bg-[#B8894D] hover:text-[#1C1C1E] transition-all duration-300"
          >
            <svg
              className="w-4 h-4"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M12 3v12m0 0l-4-4m4 4l4-4M4 21h16"
              />
            </svg>
            Download Charter (PDF)
          </a>
        ) : (
          <form
            onSubmit={handleSubmit}
            className="flex flex-col sm:flex-row gap-3"
          >
            <input
              type="password"
              required
              value={pass}
              onChange={(e) => {
                setPass(e.target.value);
                if (error) setError(false);
              }}
              placeholder="Passphrase"
              aria-label="Charter passphrase"
              className="flex-1 bg-[#4B2A2C]/15 border border-[#B8894D]/25 rounded-sm px-5 py-4 text-[#F5F0EB] font-inter placeholder:text-[#F5F0EB]/40 focus:border-[#B8894D] transition-colors"
            />
            <button
              type="submit"
              className="border border-[#B8894D] text-[#B8894D] px-8 py-4 rounded-sm font-inter text-sm tracking-[0.2em] uppercase hover:bg-[#B8894D] hover:text-[#1C1C1E] transition-all duration-300"
            >
              Unlock
            </button>
          </form>
        )}

        {error && (
          <p className="mt-6 font-inter text-sm text-[#6B1D2F]">
            That passphrase is not recognized. Founding applicants receive it by
            invitation.
          </p>
        )}
      </div>
    </section>
  );
}

const faqs = [
  {
    q: "What are the membership criteria?",
    a: "Goon is a private members club for verified high-net-worth gay and lesbian individuals. Prospective members submit a request, complete identity verification, and are reviewed before an invitation is extended. This is how we keep Goon what it is — a sanctuary, not a venue.",
  },
  {
    q: "Where is Goon located?",
    a: "Goon is being forged in West Hollywood — a private physical house, not a pop-up. The exact address is shared only with verified members, by design. Public access is not part of the model.",
  },
  {
    q: "When does Goon open?",
    a: "We are honest: there is no fixed opening date yet. The house is being built now, and founding members on the waitlist will be the first invited when the doors open. We will not promise a date we cannot keep.",
  },
  {
    q: "How much does membership cost?",
    a: "Membership is tiered from $1,200 to $3,500 per year, graduated by the level of access and founding privileges you wish to hold. Dues are transparent and disclosed in full during the invitation process — there are no hidden fees.",
  },
];

export default function FAQ() {
  return (
    <section id="faq" className="py-24 px-6 bg-[#1C1C1E]">
      <div className="max-w-3xl mx-auto">
        <div className="text-center mb-16">
          <p className="font-inter text-[#B8894D] text-sm tracking-[0.25em] uppercase mb-4">
            Questions, answered honestly
          </p>
          <h2 className="font-playfair text-4xl md:text-5xl font-semibold text-[#F5F0EB] mb-6">
            Before you apply
          </h2>
          <div className="gold-divider w-24 mx-auto" />
        </div>

        <div className="space-y-4">
          {faqs.map((f) => (
            <details
              key={f.q}
              className="group border border-[#B8894D]/20 bg-[#141415]/60 rounded-sm px-6 py-5 open:border-[#B8894D]/50 transition-colors"
            >
              <summary className="flex items-center justify-between cursor-pointer list-none">
                <span className="font-playfair text-lg text-[#F5F0EB] pr-4">
                  {f.q}
                </span>
                <span className="text-[#B8894D] text-xl shrink-0 transition-transform group-open:rotate-45">
                  +
                </span>
              </summary>
              <p className="font-inter text-sm text-[#F5F0EB]/70 leading-relaxed mt-4">
                {f.a}
              </p>
            </details>
          ))}
        </div>
      </div>
    </section>
  );
}

const benefits = [
  {
    title: "Identity-Verified Sanctuary",
    body: "Membership is extended only to verified high-net-worth LGBTQ+ individuals. The result is a private house where you are surrounded by peers — never a room to explain or defend.",
    icon: "✦",
  },
  {
    title: "Old European Aristocratic Ambiance",
    body: "Burgundy velvet, dark wood, polished brass, and cream linen. An atmosphere drawn from the great European houses — quiet, unhurried, and entirely yours.",
    icon: "◆",
  },
  {
    title: "Curated Cultural Events",
    body: "Members-only salons, intimate performances, and gatherings programmed with care — a calendar shaped to deepen the character of the house and the community within it.",
    icon: "⬡",
  },
  {
    title: "Tiered Membership · $1,200–$3,500/yr",
    body: "A graduated membership shaped to your relationship with the house — from associate access to full founding privileges. Dues are transparent; the experience is not.",
    icon: "◈",
  },
];

export default function Benefits() {
  return (
    <section id="vision" className="py-24 px-6 bg-[#1C1C1E]">
      <div className="max-w-6xl mx-auto">
        <div className="text-center mb-16">
          <p className="font-inter text-[#B8894D] text-sm tracking-[0.25em] uppercase mb-4">
            What We&rsquo;re Building
          </p>
          <h2 className="font-playfair text-4xl md:text-5xl font-semibold text-[#F5F0EB] mb-6">
            A sanctuary, deliberately forged.
          </h2>
          <p className="font-inter text-base text-[#F5F0EB]/65 max-w-2xl mx-auto leading-relaxed">
            Goon is a private members club built on the belief that true luxury
            is belonging. Every detail of the house is shaped to deliver an
            authentic old European aristocratic experience — for those who
            understand the difference.
          </p>
          <div className="gold-divider w-24 mx-auto mt-8" />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          {benefits.map((b) => (
            <div
              key={b.title}
              className="border border-[#B8894D]/20 bg-[#4B2A2C]/10 p-8 rounded-sm hover:border-[#B8894D]/50 transition-colors duration-300"
            >
              <div className="text-[#B8894D] text-2xl mb-4">{b.icon}</div>
              <h3 className="font-playfair text-lg font-semibold text-[#F5F0EB] mb-3 leading-snug">
                {b.title}
              </h3>
              <p className="font-inter text-sm text-[#F5F0EB]/70 leading-relaxed">
                {b.body}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

