  role: UserRole;
  email: string;
}

export const TIER_PRICES: Record<MembershipTier, number> = {
  basic: 120000,
  premium: 220000,
  vip: 350000,
};

export const TIER_LABELS: Record<MembershipTier, string> = {
  basic: "Basic",
  premium: "Premium",
  vip: "VIP",
};

export const INDUSTRIES = [
  "Tech",
  "Finance",
  "Law",
  "Entertainment",
  "Fashion",
  "Wellness",
