] as const;

import { MembershipTier } from "./types";

export function formatCurrency(cents: number): string {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(cents / 100);
}

export function tierAnnualLabel(tier: MembershipTier): string {
  const map: Record<MembershipTier, string> = {
    basic: "$1,200/yr",
    premium: "$2,200/yr",
    vip: "$3,500/yr",
  };
  return map[tier];
}

export function formatDate(iso: string): string {
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return iso;
  return d.toLocaleDateString("en-US", {
    year: "numeric",
    month: "short",
    day: "numeric",
  });
}

export function formatDateTime(iso: string): string {
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return iso;
  return d.toLocaleString("en-US", {
    year: "numeric",
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
  });
}

export function lastInitial(lastName: string): string {
  return lastName?.trim()?.charAt(0)?.toUpperCase() ?? "";
}

export function classNames(...parts: Array<string | false | undefined | null>): string {
  return parts.filter(Boolean).join(" ");
}

