// ---- accessors ----

export async function findUserByEmail(email: string): Promise<User | null> {
  const db = await load();
  const norm = email.trim().toLowerCase();
  return db.users.find((u) => u.email === norm) ?? null;
}

export async function findUserById(id: string): Promise<User | null> {
  const db = await load();
  return db.users.find((u) => u.id === id) ?? null;
}

export async function getProfile(id: string): Promise<Profile | null> {
  const db = await load();
  return db.profiles.find((p) => p.id === id) ?? null;
}

export async function createProfile(p: Profile): Promise<void> {
  await write((db) => {
    db.profiles.push(p);
  });
}

export async function updateProfile(
  id: string,
  patch: Partial<Profile>
): Promise<Profile | null> {
  return write((db) => {
    const idx = db.profiles.findIndex((p) => p.id === id);
    if (idx === -1) return null;
    db.profiles[idx] = {
      ...db.profiles[idx],
      ...patch,
      id,
      email: db.profiles[idx].email, // email immutable here
      updated_at: new Date().toISOString(),
    };
    return db.profiles[idx];
  });
}

export async function deleteProfile(id: string): Promise<void> {
  await write((db) => {
    db.users = db.users.filter((u) => u.id !== id);
    db.profiles = db.profiles.filter((p) => p.id !== id);
    db.rsvps = db.rsvps.filter((r) => r.user_id !== id);
    db.payments = db.payments.filter((p) => p.user_id !== id);
  });
}

export async function listVerifiedProfiles(): Promise<Profile[]> {
  const db = await load();
  return db.profiles.filter((p) => p.status === "verified");
}

export async function listAllProfiles(): Promise<Profile[]> {
  const db = await load();
  return db.profiles;
}

export async function createUser(
  email: string,
  password: string,
  role: "member" | "admin" = "member"
): Promise<User> {
  const hash = await bcrypt.hash(password, 10);
  const user: User = {
    id: crypto.randomUUID(),
    email: email.trim().toLowerCase(),
    password_hash: hash,
    role,
    created_at: new Date().toISOString(),
  };
  await write((db) => {
    db.users.push(user);
  });
  return user;
}

// ---- events ----

export async function listEvents(): Promise<EventRow[]> {
  const db = await load();
  return [...db.events].sort(
    (a, b) => new Date(a.date_time).getTime() - new Date(b.date_time).getTime()
  );
}

export async function getEvent(id: string): Promise<EventRow | null> {
  const db = await load();
  return db.events.find((e) => e.id === id) ?? null;
}

export async function createEvent(
  e: Omit<EventRow, "id" | "created_at" | "updated_at">
): Promise<EventRow> {
  const row: EventRow = {
    ...e,
    id: crypto.randomUUID(),
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString(),
  };
  await write((db) => {
    db.events.push(row);
  });
  return row;
}

export async function deleteEvent(id: string): Promise<void> {
  await write((db) => {
    db.events = db.events.filter((e) => e.id !== id);
    db.rsvps = db.rsvps.filter((r) => r.event_id !== id);
  });
}

// ---- rsvps ----

export async function getRsvp(eventId: string, userId: string): Promise<Rsvp | null> {
  const db = await load();
  return db.rsvps.find((r) => r.event_id === eventId && r.user_id === userId) ?? null;
}

export async function countGoing(eventId: string): Promise<number> {
  const db = await load();
  return db.rsvps.filter((r) => r.event_id === eventId && r.status === "going").length;
}

export async function toggleRsvp(
  eventId: string,
  userId: string
): Promise<Rsvp> {
  return write((db) => {
    const existing = db.rsvps.find(
      (r) => r.event_id === eventId && r.user_id === userId
    );
    if (existing) {
      existing.status = existing.status === "going" ? "not_going" : "going";
      return existing;
    }
    const r: Rsvp = {
      id: crypto.randomUUID(),
      event_id: eventId,
      user_id: userId,
      status: "going",
      created_at: new Date().toISOString(),
    };
    db.rsvps.push(r);
    return r;
  });
}

// ---- payments ----

export async function listPayments(userId: string): Promise<Payment[]> {
  const db = await load();
  return db.payments
    .filter((p) => p.user_id === userId)
    .sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
}

export async function listAllPayments(): Promise<Payment[]> {
  const db = await load();
  return [...db.payments].sort(
    (a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
  );
}

export async function createPayment(
  userId: string,
  tier: MembershipTier,
  amount: number,
  stripeSessionId: string | null,
  status: "paid" | "refunded" | "cancelled"
): Promise<Payment> {
  const payment: Payment = {
    id: crypto.randomUUID(),
    user_id: userId,
    tier,
    amount,
    stripe_session_id: stripeSessionId,
    status,
    created_at: new Date().toISOString(),
  };
  await write((db) => {
    db.payments.push(payment);
  });
  return payment;
}

export async function touchLastActive(userId: string): Promise<void> {
  await write((db) => {
    const p = db.profiles.find((pr) => pr.id === userId);
    if (p) p.last_active = new Date().toISOString();
  });
}

