"use client";

import { createContext, useCallback, useContext, useEffect, useState, ReactNode } from "react";

type ToastKind = "success" | "error" | "info";
interface Toast {
  id: number;
  kind: ToastKind;
  message: string;
}

interface ToastContextValue {
  toast: (message: string, kind?: ToastKind) => void;
}

const ToastContext = createContext<ToastContextValue | null>(null);

export function useToast() {
  const ctx = useContext(ToastContext);
  if (!ctx) return { toast: () => undefined };
  return ctx;
}

const accent: Record<ToastKind, string> = {
  success: "border-brass text-brass",
  error: "border-[#8B3A3A] text-[#C97A7A]",
  info: "border-ivory/40 text-ivory",
};

export function ToastProvider({ children }: { children: ReactNode }) {
  const [toasts, setToasts] = useState<Toast[]>([]);

  const toast = useCallback((message: string, kind: ToastKind = "info") => {
    const id = Date.now() + Math.random();
    setToasts((t) => [...t, { id, kind, message }]);
  }, []);

  useEffect(() => {
    if (toasts.length === 0) return;
    const timers = toasts.map((t) =>
      setTimeout(() => setToasts((cur) => cur.filter((c) => c.id !== t.id)), 3500)
    );
    return () => timers.forEach(clearTimeout);
  }, [toasts]);

  return (
    <ToastContext.Provider value={{ toast }}>
      {children}
      <div className="fixed bottom-6 right-6 z-50 flex flex-col gap-2 max-w-sm">
        {toasts.map((t) => (
          <div
            key={t.id}
            className={`bg-charcoal-soft border ${accent[t.kind]} px-5 py-3 font-satoshi text-sm`}
            role="status"
          >
            {t.message}
          </div>
        ))}
      </div>
    </ToastContext.Provider>
  );
}

"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useState } from "react";
import { classNames } from "@/lib/utils";
import { signOut } from "@/lib/actions";

interface SidebarProps {
  isAdmin: boolean;
  memberName: string;
}

const items = [
  { href: "/dashboard", label: "Home", icon: "shield" },
  { href: "/dashboard/profile", label: "Profile", icon: "user" },
  { href: "/dashboard/directory", label: "Directory", icon: "users" },
  { href: "/dashboard/events", label: "Events", icon: "calendar" },
  { href: "/dashboard/payments", label: "Payments", icon: "card" },
];

const adminItem = { href: "/admin", label: "Admin", icon: "cog" };

function Icon({ name }: { name: string }) {
  const common = {
    fill: "none" as const,
    stroke: "currentColor",
    viewBox: "0 0 24 24",
    strokeWidth: 1.5,
    strokeLinecap: "round" as const,
    strokeLinejoin: "round" as const,
    className: "w-5 h-5",
  };
  switch (name) {
    case "shield":
      return (
        <svg {...common}>
          <path d="M12 3l7 3v6c0 4.5-3 7.5-7 9-4-1.5-7-4.5-7-9V6l7-3z" />
        </svg>
      );
    case "user":
      return (
        <svg {...common}>
          <circle cx="12" cy="8" r="4" />
          <path d="M4 21c0-4 4-6 8-6s8 2 8 6" />
        </svg>
      );
    case "users":
      return (
        <svg {...common}>
          <circle cx="9" cy="8" r="3.5" />
          <path d="M2 21c0-3.5 3-5.5 7-5.5s7 2 7 5.5" />
          <path d="M16 5.5a3.5 3.5 0 010 6M22 21c0-3-2-5-5-5.5" />
        </svg>
      );
    case "calendar":
      return (
        <svg {...common}>
          <rect x="3" y="5" width="18" height="16" rx="1" />
          <path d="M3 9h18M8 3v4M16 3v4" />
        </svg>
      );
    case "card":
      return (
        <svg {...common}>
          <rect x="2" y="5" width="20" height="14" rx="1" />
          <path d="M2 10h20M6 15h4" />
        </svg>
      );
    case "cog":
      return (
        <svg {...common}>
          <circle cx="12" cy="12" r="3.5" />
          <path d="M12 2v3M12 19v3M2 12h3M19 12h3M5 5l2 2M17 17l2 2M19 5l-2 2M7 17l-2 2" />
        </svg>
      );
    default:
      return null;
  }
}

export default function Sidebar({ isAdmin, memberName }: SidebarProps) {
  const pathname = usePathname();
  const [open, setOpen] = useState(false);

  const allItems = isAdmin ? [...items, adminItem] : items;

  const nav = (
    <nav className="flex flex-col gap-1 px-3 py-6">
      {allItems.map((item) => {
        const active =
          pathname === item.href ||
          (item.href !== "/dashboard" && pathname.startsWith(item.href));
        return (
          <Link
            key={item.href}
            href={item.href}
            onClick={() => setOpen(false)}
            className={classNames(
              "flex items-center gap-3 px-4 py-3 font-satoshi text-sm tracking-wide transition-colors border-l-2",
              active
                ? "text-brass border-brass bg-brass/5"
                : "text-ivory/60 border-transparent hover:text-ivory hover:bg-ivory/5"
            )}
          >
            <Icon name={item.icon} />
            {item.label}
          </Link>
        );
      })}
      <form action={signOut} className="mt-2">
        <button
          type="submit"
          className="w-full flex items-center gap-3 px-4 py-3 font-satoshi text-sm tracking-wide text-ivory/40 border-l-2 border-transparent hover:text-[#C97A7A] transition-colors"
        >
          <svg {...{
            fill: "none",
            stroke: "currentColor",
            viewBox: "0 0 24 24",
            strokeWidth: 1.5,
            strokeLinecap: "round",
            strokeLinejoin: "round",
            className: "w-5 h-5",
          }}>
            <path d="M9 21H5a2 2 0 01-2-2V5a2 2 0 012-2h4M16 17l5-5-5-5M21 12H9" />
          </svg>
          Sign Out
        </button>
      </form>
    </nav>
  );

  return (
    <>
      {/* Mobile top bar with menu toggle */}
      <div className="md:hidden flex items-center justify-between border-b border-ivory/10 bg-charcoal px-5 py-4 sticky top-0 z-30">
        <Link href="/dashboard" className="font-playfair text-2xl text-ivory">
          Goon
        </Link>
        <button
          aria-label="Toggle navigation"
          onClick={() => setOpen((o) => !o)}
          className="text-brass p-2"
        >
