import { SignJWT, jwtVerify } from "jose";
import { cookies } from "next/headers";
import bcrypt from "bcryptjs";
import { NextResponse } from "next/server";
import {
  createUser,
  createProfile,
  findUserByEmail,
  getProfile,
  touchLastActive,
} from "./db";
import { SessionUser, UserRole } from "./types";

export const SESSION_COOKIE = "goon_session";
const COOKIE_MAX_AGE = 60 * 60 * 24 * 30; // 30 days

function secret(): Uint8Array {
  const raw =
    process.env.JWT_SECRET ||
    process.env.SECRET_KEY ||
    "goon-dev-secret-change-in-production-please";
  return new TextEncoder().encode(raw);
}

export async function signSession(payload: SessionUser): Promise<string> {
  return new SignJWT({ ...payload })
    .setProtectedHeader({ alg: "HS256" })
    .setIssuedAt()
    .setExpirationTime(`${COOKIE_MAX_AGE}s`)
    .sign(secret());
}

export async function verifySession(token: string): Promise<SessionUser | null> {
  try {
    const { payload } = await jwtVerify(token, secret());
    const userId = payload.userId as string | undefined;
    const role = payload.role as UserRole | undefined;
    const email = payload.email as string | undefined;
    if (!userId || !role || !email) return null;
    return { userId, role, email };
  } catch {
    return null;
  }
}

export async function getSession(): Promise<SessionUser | null> {
  const store = cookies();
  const token = store.get(SESSION_COOKIE)?.value;
  if (!token) return null;
  return verifySession(token);
}

export async function requireUser(): Promise<SessionUser> {
  const session = await getSession();
  if (!session) {
    throw new RedirectError("/login");
  }
  return session;
}

export async function requireAdmin(): Promise<SessionUser> {
  const session = await requireUser();
  if (session.role !== "admin") {
    throw new RedirectError("/dashboard");
  }
  return session;
}

export class RedirectError {
  constructor(public destination: string) {}
}

/** Set the session cookie on a NextResponse (used by login/signup/logout routes). */
export function setSessionCookie(
  res: NextResponse,
  token: string
): NextResponse {
  res.cookies.set(SESSION_COOKIE, token, {
    httpOnly: true,
    sameSite: "lax",
    secure: process.env.NODE_ENV === "production",
    path: "/",
    maxAge: COOKIE_MAX_AGE,
  });
  return res;
}

export function clearSessionCookie(res: NextResponse): NextResponse {
  res.cookies.set(SESSION_COOKIE, "", {
    httpOnly: true,
    sameSite: "lax",
    secure: process.env.NODE_ENV === "production",
    path: "/",
    maxAge: 0,
  });
  return res;
}

/** Authenticate email+password against the local user store. Returns session payload or throws. */
export async function authenticate(
  email: string,
  password: string
): Promise<SessionUser> {
  const user = await findUserByEmail(email);
  if (!user) {
    throw new AuthError("No account found for that email.");
  }
  const ok = await bcrypt.compare(password, user.password_hash);
  if (!ok) {
    throw new AuthError("Incorrect password. Please try again.");
  }
  return { userId: user.id, role: user.role, email: user.email };
}

/** Returns the current user's profile, or null (caller decides whether to redirect to onboarding). */
export async function getCurrentProfile() {
  const session = await getSession();
  if (!session) return { session: null, profile: null };
  const profile = await getProfile(session.userId);
  return { session, profile };
}

export async function ensureDemoAccount(): Promise<SessionUser> {
  const existing = await findUserByEmail("demo@demo.app");
  if (existing) {
    return { userId: existing.id, role: existing.role, email: existing.email };
  }
  const user = await createUser("demo@demo.app", "demo123", "member");
  await createProfile({
    id: user.id,
    first_name: "Aurelia",
    last_name: "Vance",
    email: user.email,
    phone: "+1 (310) 555-0148",
    occupation: "Creative Director",
    industry: "Fashion",
    bio: "Visiting member exploring the salon.",
    pronouns: "she/her",
    languages: ["English", "Italian"],
    avatar_url: null,
    status: "verified",
    membership_tier: "premium",
    join_date: user.created_at,
    last_active: user.created_at,
    created_at: user.created_at,
    updated_at: user.created_at,
  });
  return { userId: user.id, role: user.role, email: user.email };
}

export async function registerUser(input: {
  email: string;
  password: string;
  firstName: string;
  lastName: string;
}): Promise<SessionUser> {
  const existing = await findUserByEmail(input.email);
  if (existing) {
    throw new AuthError("An account with that email already exists.");
  }
  const user = await createUser(input.email, input.password, "member");
  await createProfile({
    id: user.id,
    first_name: input.firstName,
    last_name: input.lastName,
    email: user.email,
    phone: null,
    occupation: null,
    industry: null,
    bio: null,
    pronouns: null,
    languages: [],
    avatar_url: null,
    status: "pending",
    membership_tier: null,
    join_date: user.created_at,
    last_active: user.created_at,
    created_at: user.created_at,
    updated_at: user.created_at,
  });
  return { userId: user.id, role: user.role, email: user.email };
}

export async function recordActivity(session: SessionUser): Promise<void> {
  await touchLastActive(session.userId).catch(() => undefined);
}

export class AuthError extends Error {}
