import Stripe from "stripe";
import { MembershipTier, TIER_PRICES } from "./types";

const STRIPE_SECRET_KEY = process.env.STRIPE_SECRET_KEY;

export const isStripeConfigured = Boolean(STRIPE_SECRET_KEY);

export const TIER_PRICE_IDS: Record<MembershipTier, string | undefined> = {
  basic: process.env.STRIPE_PRICE_BASIC,
  premium: process.env.STRIPE_PRICE_PREMIUM,
  vip: process.env.STRIPE_PRICE_VIP,
};

export function stripeClient(): Stripe | null {
  if (!isStripeConfigured) return null;
  return new Stripe(STRIPE_SECRET_KEY!, {
    apiVersion: "2024-12-18.acacia" as Stripe.LatestApiVersion,
  });
}

export function tierAmount(tier: MembershipTier): number {
  return TIER_PRICES[tier];
}

/**
 * Creates a Stripe Checkout Session when Stripe is configured.
 * Returns null when running without Stripe credentials — callers should use the
 * demo checkout path in that case so the product stays explorable.
 */
export async function createCheckoutSession(opts: {
  tier: MembershipTier;
  userId: string;
  userEmail: string;
  successUrl: string;
  cancelUrl: string;
}): Promise<{ url: string; sessionId: string } | null> {
  const stripe = stripeClient();
  const priceId = TIER_PRICE_IDS[opts.tier];
  if (!stripe || !priceId) return null;

  const session = await stripe.checkout.sessions.create({
    mode: "payment",
    customer_email: opts.userEmail,
    line_items: [{ price: priceId, quantity: 1 }],
    client_reference_id: opts.userId,
    metadata: { tier: opts.tier, user_id: opts.userId },
    success_url: opts.successUrl,
    cancel_url: opts.cancelUrl,
  });

  return { url: session.url!, sessionId: session.id };
}

export function verifyWebhookSignature(rawBody: string, signature: string): Stripe.Event | null {
  const secret = process.env.STRIPE_WEBHOOK_SECRET;
  const stripe = stripeClient();
  if (!stripe || !secret) return null;
  try {
    return stripe.webhooks.constructEvent(rawBody, signature, secret);
  } catch {
    return null;
  }
}
