import { NextResponse } from "next/server";
import {
  authenticate,
  clearSessionCookie,
  recordActivity,
  setSessionCookie,
  signSession,
  getSession,
} from "@/lib/auth";
import { AuthError } from "@/lib/auth";

export async function GET() {
  const session = await getSession();
  return NextResponse.json({ session });
}

export async function POST(request: Request) {
  let body: { email?: string; password?: string; redirect?: string };
  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: "Invalid request." }, { status: 400 });
  }
  const email = body.email?.trim();
  const password = body.password;
  if (!email || !password) {
    return NextResponse.json(
      { error: "Email and password are required." },
      { status: 400 }
    );
  }
  try {
    const sessionUser = await authenticate(email, password);
    const token = await signSession(sessionUser);
    const res = NextResponse.json({
      ok: true,
      redirect: body.redirect || "/dashboard",
    });
    setSessionCookie(res, token);
    recordActivity(sessionUser).catch(() => undefined);
    return res;
  } catch (err) {
    if (err instanceof AuthError) {
      return NextResponse.json({ error: err.message }, { status: 401 });
    }
    return NextResponse.json(
      { error: "Something went wrong. Please try again." },
      { status: 500 }
    );
  }
}

export async function DELETE() {
  const res = NextResponse.json({ ok: true, redirect: "/" });
  clearSessionCookie(res);
  return res;
}

import { NextResponse } from "next/server";
import { AuthError, registerUser, setSessionCookie, signSession } from "@/lib/auth";

export async function POST(request: Request) {
  let body: {
    firstName?: string;
    lastName?: string;
    email?: string;
    password?: string;
    confirm?: string;
  };
  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: "Invalid request." }, { status: 400 });
  }

  const firstName = body.firstName?.trim();
  const lastName = body.lastName?.trim();
  const email = body.email?.trim();
  const password = body.password;
  const confirm = body.confirm;

  if (!firstName || !lastName) {
    return NextResponse.json({ error: "Your full name is required." }, { status: 400 });
  }
  if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
    return NextResponse.json({ error: "A valid email is required." }, { status: 400 });
  }
  if (!password || password.length < 8) {
    return NextResponse.json(
      { error: "Password must be at least 8 characters." },
      { status: 400 }
    );
  }
  if (password !== confirm) {
    return NextResponse.json({ error: "Passwords do not match." }, { status: 400 });
  }

  try {
    const sessionUser = await registerUser({ email, password, firstName, lastName });
    const token = await signSession(sessionUser);
    const res = NextResponse.json({ ok: true, redirect: "/onboarding" });
    setSessionCookie(res, token);
    return res;
  } catch (err) {
    if (err instanceof AuthError) {
      return NextResponse.json({ error: err.message }, { status: 409 });
    }
    return NextResponse.json(
      { error: "Something went wrong. Please try again." },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { ensureDemoAccount, setSessionCookie, signSession, recordActivity } from "@/lib/auth";

/** One-click demo login. Seeds the demo account if missing, then starts a session. */
export async function POST() {
  const sessionUser = await ensureDemoAccount();
  const token = await signSession(sessionUser);
  const res = NextResponse.json({ ok: true, redirect: "/dashboard" });
  setSessionCookie(res, token);
  recordActivity(sessionUser).catch(() => undefined);
  return res;
}

import { NextResponse } from "next/server";
import { isSupabaseConfigured, createServerSupabase } from "@/lib/supabase";

/**
 * Forgot-password request.
 * - When Supabase is configured, sends a real password-reset email.
 * - In demo mode (no Supabase), returns a success message so the flow does not dead-end.
 */
export async function POST(request: Request) {
  let body: { email?: string };
  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: "Invalid request." }, { status: 400 });
  }
  const email = body.email?.trim();
  if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
    return NextResponse.json({ error: "A valid email is required." }, { status: 400 });
  }

  if (isSupabaseConfigured) {
    const supabase = createServerSupabase();
    await supabase!.auth.resetPasswordForEmail(email, {
      redirectTo: `${process.env.NEXT_PUBLIC_SITE_URL || ""}/login?reset=1`,
    });
  }
  // Always respond positively to avoid account enumeration; in demo mode no email is sent.
  return NextResponse.json({
    ok: true,
    message:
      "If an account exists for that address, a reset link is on its way.",
  });
}

import { NextResponse } from "next/server";
import { getCurrentProfile, requireUser } from "@/lib/auth";
import { deleteProfile, getProfile, updateProfile } from "@/lib/db";
import { INDUSTRIES, MembershipTier } from "@/lib/types";

const TIERS: MembershipTier[] = ["basic", "premium", "vip"];
const STATUSES = ["pending", "verified", "suspended"] as const;

export async function GET() {
  const session = await requireUser().catch(() => null);
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  const profile = await getProfile(session.userId);
  return NextResponse.json({ profile });
}

export async function PUT(request: Request) {
  const session = await requireUser().catch(() => null);
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  let body: Record<string, unknown>;
  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: "Invalid request." }, { status: 400 });
  }

  const patch: Record<string, unknown> = {};

  const str = (v: unknown): string | null =>
    typeof v === "string" && v.trim() ? v.trim() : null;

  if (body.first_name !== undefined) patch.first_name = str(body.first_name) ?? "";
  if (body.last_name !== undefined) patch.last_name = str(body.last_name) ?? "";
  if (body.phone !== undefined) patch.phone = str(body.phone);
  if (body.occupation !== undefined) patch.occupation = str(body.occupation);
  if (body.industry !== undefined) {
    const ind = str(body.industry);
    if (ind && !INDUSTRIES.includes(ind as (typeof INDUSTRIES)[number])) {
      return NextResponse.json({ error: "Invalid industry." }, { status: 400 });
    }
    patch.industry = ind;
  }
  if (body.bio !== undefined) patch.bio = str(body.bio);
  if (body.pronouns !== undefined) patch.pronouns = str(body.pronouns);
  if (body.languages !== undefined) {
    const langs = Array.isArray(body.languages)
      ? body.languages.filter((l): l is string => typeof l === "string").map((l) => l.trim()).filter(Boolean)
      : [];
    patch.languages = langs;
  }
  if (body.avatar_url !== undefined) patch.avatar_url = str(body.avatar_url);

  // Membership tier is set via payments only; users cannot self-assign.
  const updated = await updateProfile(session.userId, patch);
  if (!updated) return NextResponse.json({ error: "Profile not found." }, { status: 404 });
  return NextResponse.json({ profile: updated });
}

export async function DELETE() {
  const session = await requireUser().catch(() => null);
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  await deleteProfile(session.userId);
  const res = NextResponse.json({ ok: true, redirect: "/" });
  res.cookies.set("goon_session", "", { path: "/", maxAge: 0, httpOnly: true, sameSite: "lax" });
  return res;
}

export { STATUSES };

import { NextResponse } from "next/server";
import { requireUser } from "@/lib/auth";
import { listVerifiedProfiles } from "@/lib/db";
import { lastInitial } from "@/lib/utils";

export async function GET(request: Request) {
  const session = await requireUser().catch(() => null);
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const { searchParams } = new URL(request.url);
  const q = searchParams.get("q")?.trim().toLowerCase() || "";
  const industry = searchParams.get("industry")?.split(",").filter(Boolean) || [];
  const tier = searchParams.get("tier")?.split(",").filter(Boolean) || [];

  let members = await listVerifiedProfiles();

  // Exclude the viewer themselves from results (discretion-first).
  members = members.filter((m) => m.id !== session.userId);

  if (q) {
    members = members.filter((m) => {
      const haystack = [
        m.first_name,
        m.last_name,
        m.occupation ?? "",
        m.industry ?? "",
        m.bio ?? "",
      ]
        .join(" ")
        .toLowerCase();
      return haystack.includes(q);
    });
  }
  if (industry.length) {
    members = members.filter((m) => m.industry && industry.includes(m.industry));
  }
  if (tier.length) {
    members = members.filter((m) => m.membership_tier && tier.includes(m.membership_tier));
  }

  // Privacy: first name + last initial only; no full last names, no company names.
  const safe = members.map((m) => ({
    id: m.id,
    first_name: m.first_name,
    last_initial: lastInitial(m.last_name),
    occupation: m.occupation,
    industry: m.industry,
    membership_tier: m.membership_tier,
    pronouns: m.pronouns,
    languages: m.languages,
    bio: m.bio,
    avatar_url: m.avatar_url,
    status: m.status,
  }));

  return NextResponse.json({ members: safe, total: safe.length });
}

import { NextResponse } from "next/server";
import { requireUser } from "@/lib/auth";
import { createEvent, listEvents } from "@/lib/db";

export async function GET(request: Request) {
  const session = await requireUser().catch(() => null);
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  const { searchParams } = new URL(request.url);
  const tab = searchParams.get("tab") || "upcoming";
  const now = Date.now();
  const events = await listEvents();
  const filtered = events.filter((e) =>
    tab === "past"
      ? new Date(e.date_time).getTime() < now
      : new Date(e.date_time).getTime() >= now
  );
  return NextResponse.json({ events: filtered });
}

export async function POST(request: Request) {
  const session = await requireUser().catch(() => null);
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  if (session.role !== "admin") {
    return NextResponse.json({ error: "Forbidden." }, { status: 403 });
  }

  let body: {
    name?: string;
    description?: string;
    location?: string;
    date_time?: string;
    capacity?: number;
    rsvp_deadline?: string;
  };
  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: "Invalid request." }, { status: 400 });
  }

  const name = body.name?.trim();
  const location = body.location?.trim();
  const dateTime = body.date_time;
  const rsvpDeadline = body.rsvp_deadline;
  const capacity = Number(body.capacity);

  if (!name || !location || !dateTime || !rsvpDeadline) {
    return NextResponse.json(
      { error: "Name, location, date/time and RSVP deadline are required." },
      { status: 400 }
    );
  }
  if (!Number.isFinite(capacity) || capacity <= 0) {
    return NextResponse.json({ error: "Capacity must be a positive number." }, { status: 400 });
  }
  if (new Date(rsvpDeadline).toString() === "Invalid Date" || new Date(dateTime).toString() === "Invalid Date") {
    return NextResponse.json({ error: "Invalid date or time." }, { status: 400 });
  }

  const event = await createEvent({
    name,
    description: body.description?.trim() || null,
    location,
    date_time: new Date(dateTime).toISOString(),
    capacity,
    rsvp_deadline: new Date(rsvpDeadline).toISOString(),
    created_by: session.userId,
  });

  return NextResponse.json({ event }, { status: 201 });
}

import { NextResponse } from "next/server";
import { requireUser } from "@/lib/auth";
import { countGoing, deleteEvent, getEvent, getRsvp } from "@/lib/db";

export async function GET(
  request: Request,
  { params }: { params: { id: string } }
) {
  const session = await requireUser().catch(() => null);
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  const event = await getEvent(params.id);
  if (!event) return NextResponse.json({ error: "Event not found." }, { status: 404 });
  const [going, myRsvp] = await Promise.all([
    countGoing(event.id),
    getRsvp(event.id, session.userId),
  ]);
  const deadlinePassed = new Date(event.rsvp_deadline).getTime() < Date.now();
  const full = going >= event.capacity;
  return NextResponse.json({ event, goingCount: going, myRsvp, deadlinePassed, full });
}

export async function DELETE(
  request: Request,
  { params }: { params: { id: string } }
) {
  const session = await requireUser().catch(() => null);
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  if (session.role !== "admin") {
    return NextResponse.json({ error: "Forbidden." }, { status: 403 });
  }
  const event = await getEvent(params.id);
  if (!event) return NextResponse.json({ error: "Event not found." }, { status: 404 });
  await deleteEvent(params.id);
  return NextResponse.json({ ok: true });
}

import { NextResponse } from "next/server";
import { requireUser } from "@/lib/auth";
import { countGoing, getEvent, getRsvp, toggleRsvp } from "@/lib/db";

export async function POST(
  request: Request,
  { params }: { params: { id: string } }
) {
  const session = await requireUser().catch(() => null);
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const event = await getEvent(params.id);
  if (!event) return NextResponse.json({ error: "Event not found." }, { status: 404 });

  const deadlinePassed = new Date(event.rsvp_deadline).getTime() < Date.now();
  if (deadlinePassed) {
    return NextResponse.json({ error: "RSVP has closed for this event." }, { status: 400 });
  }

  const existing = await getRsvp(event.id, session.userId);
  // Prevent joining a full event (cancelling is always allowed).
  if (!existing || existing.status !== "going") {
    const going = await countGoing(event.id);
    if (going >= event.capacity) {
      return NextResponse.json({ error: "This event is full." }, { status: 409 });
    }
  }

  const rsvp = await toggleRsvp(event.id, session.userId);
  const goingCount = await countGoing(event.id);
  return NextResponse.json({ rsvp, goingCount, full: goingCount >= event.capacity });
}

import { NextResponse } from "next/server";
import { requireUser } from "@/lib/auth";
import { listPayments } from "@/lib/db";

export async function GET() {
  const session = await requireUser().catch(() => null);
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  const payments = await listPayments(session.userId);
  return NextResponse.json({ payments });
}

import { NextResponse } from "next/server";
import { requireUser } from "@/lib/auth";
import { createPayment, getProfile, updateProfile } from "@/lib/db";
import { createCheckoutSession, isStripeConfigured, tierAmount } from "@/lib/stripe";
import { MembershipTier } from "@/lib/types";

const VALID: MembershipTier[] = ["basic", "premium", "vip"];

export async function GET(request: Request) {
  const session = await requireUser().catch(() => null);
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const { searchParams } = new URL(request.url);
  const tier = searchParams.get("tier") as MembershipTier;
  if (!VALID.includes(tier)) {
    return NextResponse.json({ error: "Invalid membership tier." }, { status: 400 });
  }

  const profile = await getProfile(session.userId);
  if (!profile) return NextResponse.json({ error: "Profile not found." }, { status: 404 });

  const origin = new URL(request.url).origin;
  const successUrl = `${origin}/dashboard/payments?success=1`;
  const cancelUrl = `${origin}/dashboard/payments?cancelled=1`;

  // Real Stripe checkout when configured.
  if (isStripeConfigured) {
    const session_ = await createCheckoutSession({
      tier,
      userId: session.userId,
      userEmail: profile.email,
      successUrl,
      cancelUrl,
    });
    if (session_) {
      return NextResponse.json({ url: session_.url });
    }
  }

  // Demo checkout path (no Stripe credentials): record a paid membership immediately.
  await createPayment(session.userId, tier, tierAmount(tier), null, "paid");
  await updateProfile(session.userId, { membership_tier: tier });
  return NextResponse.json({ url: successUrl, demo: true });
}

import { NextResponse } from "next/server";
import { createPayment, getProfile, updateProfile } from "@/lib/db";
import { isStripeConfigured, verifyWebhookSignature } from "@/lib/stripe";
import { MembershipTier } from "@/lib/types";
import { findUserById } from "@/lib/db";

const VALID: MembershipTier[] = ["basic", "premium", "vip"];

export async function POST(request: Request) {
  const rawBody = await request.text();
  const signature = request.headers.get("stripe-signature") || "";

  // When Stripe is configured, verify the signature. Otherwise (demo mode),
  // process the posted payload directly so the flow stays exercisable.
  let event: { type: string; data?: { object?: Record<string, unknown> } } | null = null;

  if (isStripeConfigured) {
    event = verifyWebhookSignature(rawBody, signature);
    if (!event) {
      return NextResponse.json({ error: "Invalid signature." }, { status: 400 });
    }
  } else {
    try {
      event = JSON.parse(rawBody);
    } catch {
      return NextResponse.json({ error: "Invalid payload." }, { status: 400 });
    }
  }

  if (event.type === "checkout.session.completed") {
    const obj = (event.data?.object ?? {}) as {
      id?: string;
      client_reference_id?: string;
      metadata?: { tier?: string; user_id?: string };
      amount_total?: number;
    };
    const userId = obj.client_reference_id || obj.metadata?.user_id;
    const tier = obj.metadata?.tier as MembershipTier | undefined;
    const amount = typeof obj.amount_total === "number" ? obj.amount_total : 0;

    if (userId && tier && VALID.includes(tier)) {
      const profile = await getProfile(userId);
      if (profile) {
        await createPayment(
          userId,
          tier,
          amount || 0,
          obj.id ?? null,
          "paid"
        );
        await updateProfile(userId, { membership_tier: tier });
      }
    }
  }

  return NextResponse.json({ received: true });
}

// Keep findUserById import referenced for type clarity in real Stripe flows.
export { findUserById };

