"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import Button from "@/components/ui/Button";
import { Input, Select, Textarea } from "@/components/ui/Input";
import { useToast } from "@/components/ui/Toast";
import { INDUSTRIES, Profile } from "@/lib/types";

export default function OnboardingPage() {
  const router = useRouter();
  const { toast } = useToast();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");
  const [form, setForm] = useState({
    phone: "",
    occupation: "",
    industry: "",
    bio: "",
    pronouns: "",
    languages: "",
  });

  useEffect(() => {
    fetch("/api/profile")
      .then((r) => r.json())
      .then((data: { profile?: Profile }) => {
        const p = data.profile;
        if (!p) {
          router.replace("/login");
          return;
        }
        setForm({
          phone: p.phone ?? "",
          occupation: p.occupation ?? "",
          industry: p.industry ?? "",
          bio: p.bio ?? "",
          pronouns: p.pronouns ?? "",
          languages: p.languages.join(", "),
        });
        setLoading(false);
      })
      .catch(() => {
        setError("Unable to load your profile.");
        setLoading(false);
      });
  }, [router]);

  function set(key: keyof typeof form, value: string) {
    setForm((f) => ({ ...f, [key]: value }));
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setSaving(true);
    setError("");
    try {
      const res = await fetch("/api/profile", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          phone: form.phone,
          occupation: form.occupation,
          industry: form.industry || null,
          bio: form.bio,
          pronouns: form.pronouns,
          languages: form.languages
            .split(",")
            .map((l) => l.trim())
            .filter(Boolean),
        }),
      });
      if (!res.ok) {
        const data = await res.json();
        setError(data.error || "Unable to save.");
        setSaving(false);
        return;
      }
      toast("Profile saved. Welcome to the salon.", "success");
      router.push("/dashboard");
      router.refresh();
    } catch {
      setError("Network error. Please try again.");
      setSaving(false);
    }
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-ink flex items-center justify-center">
        <p className="font-satoshi text-sm text-ivory/50">Loading…</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-ink px-6 py-12">
      <div className="max-w-xl mx-auto">
        <p className="font-satoshi text-brass text-xs tracking-[0.3em] uppercase mb-4">
          Complete your profile
        </p>
        <h1 className="font-playfair text-4xl text-ivory mb-2">Onboarding</h1>
        <p className="font-satoshi text-sm text-ivory/60 mb-10">
          Tell the house a little about yourself. Your profile remains pending
          until an admin verifies your membership.
        </p>

        <form onSubmit={handleSubmit} className="space-y-6">
          <Input
            label="Phone"
            type="tel"
            value={form.phone}
            onChange={(e) => set("phone", e.target.value)}
            placeholder="+1 (310) 555-0100"
          />
          <Input
            label="Occupation"
            value={form.occupation}
            onChange={(e) => set("occupation", e.target.value)}
            placeholder="Partner, Venture Capital"
          />
          <Select
            label="Industry"
            value={form.industry}
            onChange={(e) => set("industry", e.target.value)}
            placeholder="Select an industry"
            options={INDUSTRIES.map((i) => ({ value: i, label: i }))}
          />
          <Textarea
            label="Bio"
            rows={3}
            value={form.bio}
            onChange={(e) => set("bio", e.target.value)}
            placeholder="A line or two about your interests."
          />
          <Input
            label="Pronouns"
            value={form.pronouns}
            onChange={(e) => set("pronouns", e.target.value)}
            placeholder="she/her, he/him, they/them"
          />
          <Input
            label="Languages (comma-separated)"
            value={form.languages}
            onChange={(e) => set("languages", e.target.value)}
            placeholder="English, French"
          />

          {error && <p className="font-satoshi text-sm text-[#C97A7A]">{error}</p>}

          <Button type="submit" loading={saving} className="w-full">
            Save & Continue
          </Button>
        </form>
      </div>
    </div>
  );
}

