async function load(): Promise<Database> {
  if (cache) return cache;
  if (!existsSync(DATA_FILE)) {
    cache = await seed();
    await persist(cache);
    return cache;
  }
  try {
    const raw = await fs.readFile(DATA_FILE, "utf-8");
    const parsed = JSON.parse(raw) as Partial<Database>;
    cache = {
      users: parsed.users ?? [],
      waitlist: parsed.waitlist ?? [],
      applications: parsed.applications ?? [],
      tiers: parsed.tiers ?? [],
      events: parsed.events ?? [],
      attendees: parsed.attendees ?? [],
      parlors: parsed.parlors ?? [],
      bookings: parsed.bookings ?? [],
      payments: parsed.payments ?? [],
      audit_logs: parsed.audit_logs ?? [],
    };
  } catch {
    cache = await seed();
    await persist(cache);
  }
  return cache;
}

async function persist(db: Database): Promise<void> {
  await fs.mkdir(path.dirname(DATA_FILE), { recursive: true });
  await fs.writeFile(DATA_FILE, JSON.stringify(db, null, 2));
}

function write<T>(mutator: (db: Database) => T): Promise<T> {
  const run = async () => {
    const db = await load();
    const result = mutator(db);
    await persist(db);
    return result;
  };
  const next = writeChain.then(run, run);
  writeChain = next.then(() => undefined, () => undefined);
  return next;
}

export async function getDB(): Promise<Database> {
  return load();
}

export async function resetDB(): Promise<Database> {
  cache = await seed();
  await persist(cache);
  return cache;
}

// ---- users ----
export async function findUserByEmail(email: string) {
  const db = await load();
  const norm = email.trim().toLowerCase();
  return db.users.find((u) => u.email === norm) ?? null;
}
export async function findUserById(id: string) {
  const db = await load();
  return db.users.find((u) => u.id === id) ?? null;
}
export async function createUser(input: {
  email: string;
  password: string;
  name: string;
  phone?: string | null;
  referral_source?: string | null;
  role?: Database["users"][number]["role"];
}) {
  const hash = await bcrypt.hash(input.password, 10);
  const now = new Date().toISOString();
  const user: Database["users"][number] = {
    id: crypto.randomUUID(),
    email: input.email.trim().toLowerCase(),
    name: input.name.trim(),
    password_hash: hash,
    phone: input.phone ?? null,
    referral_source: input.referral_source ?? null,
    role: input.role ?? "pending",
    membership_tier: null,
    membership_expires_at: null,
    avatar_url: null,
    created_at: now,
    updated_at: now,
  };
  await write((db) => {
    db.users.push(user);
  });
  return user;
}
export async function updateUserRole(
  userId: string,
  role: Database["users"][number]["role"],
  patch: Partial<Database["users"][number]> = {}
) {
  return write((db) => {
    const u = db.users.find((x) => x.id === userId);
    if (!u) return null;
    u.role = role;
    Object.assign(u, patch);
    u.updated_at = new Date().toISOString();
    return u;
  });
}
export async function listMembers() {
  const db = await load();
  return db.users.filter((u) => u.role === "member" || u.role === "admin");
}
export async function listAllUsers() {
  const db = await load();
  return db.users;
}

