  const exists = (await load()).waitlist.some((w) => w.email === norm);
  if (exists) return null;
  const entry: Database["waitlist"][number] = {
    id: crypto.randomUUID(),
    email: norm,
    created_at: new Date().toISOString(),
  };
  await write((db) => {
    db.waitlist.push(entry);
  });
  return entry;
}
