import Link from "next/link";
import { getCurrentProfile } from "@/lib/auth";
import { countGoing, listEvents, listVerifiedProfiles } from "@/lib/db";
import { formatCurrency, formatDate, lastInitial, tierAnnualLabel } from "@/lib/utils";
import { TIER_LABELS } from "@/lib/types";
import { redirect } from "next/navigation";

export default async function DashboardPage() {
  const { session, profile } = await getCurrentProfile();
  if (!session) redirect("/login");
  if (!profile) redirect("/onboarding");

  const [events, members] = await Promise.all([listEvents(), listVerifiedProfiles()]);
  const now = Date.now();
  const upcoming = events.filter((e) => new Date(e.date_time).getTime() >= now);
  const nextEvent = upcoming[0] ?? null;
  const nextGoing = nextEvent ? await countGoing(nextEvent.id) : 0;
  const directoryPreview = members
    .filter((m) => m.id !== session.userId)
    .slice(0, 3);

  return (
    <div className="p-6 md:p-10 max-w-6xl mx-auto">
      <p className="font-satoshi text-brass text-xs tracking-[0.3em] uppercase mb-3">
        The Salon
      </p>
      <h1 className="font-playfair text-4xl md:text-5xl text-ivory mb-8">
        Welcome, {profile.first_name}
      </h1>

      {/* Stats */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-12">
        <div className="border border-ivory/15 bg-charcoal-soft p-6">
          <p className="font-satoshi text-xs tracking-[0.25em] uppercase text-ivory/50 mb-2">
            Your Membership
          </p>
          <p className="font-playfair text-2xl text-ivory">
            {profile.membership_tier
              ? `${TIER_LABELS[profile.membership_tier]}`
              : "None selected"}
          </p>
          <p className="font-satoshi text-sm text-brass mt-1">
            {profile.membership_tier
              ? tierAnnualLabel(profile.membership_tier)
              : "Choose a tier in Payments"}
          </p>
        </div>
        <div className="border border-ivory/15 bg-charcoal-soft p-6">
          <p className="font-satoshi text-xs tracking-[0.25em] uppercase text-ivory/50 mb-2">
            Upcoming Events
          </p>
          <p className="font-playfair text-2xl text-ivory">{upcoming.length}</p>
          <Link
            href="/dashboard/events"
            className="font-satoshi text-sm text-brass hover:underline mt-1 inline-block"
          >
            View calendar →
          </Link>
        </div>
      </div>

      {/* Verification status */}
      <div className="border border-ivory/15 bg-charcoal-soft p-6 mb-12">
        <p className="font-satoshi text-xs tracking-[0.25em] uppercase text-ivory/50 mb-2">
          Verification
        </p>
        {profile.status === "verified" ? (
          <p className="font-satoshi text-base text-[#7DDA5A]">
            Verified — you are visible in the directory.
          </p>
        ) : profile.status === "suspended" ? (
          <p className="font-satoshi text-base text-[#C97A7A]">
            Suspended — contact the house steward.
          </p>
        ) : (
          <p className="font-satoshi text-base text-brass">
            Pending — your profile is under discreet review.
          </p>
        )}
      </div>

      {/* Next event */}
      {nextEvent ? (
        <div className="border border-brass/30 bg-charcoal-soft p-6 mb-12">
          <p className="font-satoshi text-xs tracking-[0.25em] uppercase text-ivory/50 mb-2">
            Next Event
          </p>
          <h2 className="font-playfair text-2xl text-ivory mb-2">{nextEvent.name}</h2>
          <p className="font-satoshi text-sm text-ivory/70 mb-1">
            {formatDate(nextEvent.date_time)} · {nextEvent.location}
          </p>
          <p className="font-satoshi text-sm text-ivory/50 mb-4">
            {nextGoing} attending · {nextEvent.capacity - nextGoing} seats remain
          </p>
          <Link
            href={`/dashboard/events/${nextEvent.id}`}
            className="inline-flex items-center font-satoshi text-sm tracking-[0.2em] uppercase text-brass border border-brass px-6 py-2 hover:bg-brass hover:text-ink transition-all"
          >
            View & RSVP
          </Link>
        </div>
      ) : (
        <div className="border border-ivory/15 bg-charcoal-soft p-6 mb-12">
          <p className="font-satoshi text-sm text-ivory/60">
            No upcoming events scheduled. Check back soon.
          </p>
        </div>
      )}

      {/* Directory preview */}
      <div className="mb-4 flex items-center justify-between">
        <h2 className="font-playfair text-2xl text-ivory">Members of the House</h2>
        <Link
          href="/dashboard/directory"
          className="font-satoshi text-sm text-brass hover:underline"
        >
          Browse all →
        </Link>
      </div>
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        {directoryPreview.map((m) => (
          <Link
            key={m.id}
            href={`/dashboard/directory/${m.id}`}
            className="border border-ivory/15 bg-charcoal-soft p-5 hover:border-brass/50 transition-colors"
          >
            <div className="w-12 h-12 rounded-full bg-brass/15 border border-brass/30 flex items-center justify-center mb-3">
              <span className="font-playfair text-lg text-brass">
                {m.first_name.charAt(0)}
                {lastInitial(m.last_name)}
              </span>
            </div>
            <p className="font-playfair text-lg text-ivory">
              {m.first_name} {lastInitial(m.last_name)}.
            </p>
            <p className="font-satoshi text-xs text-ivory/50">{m.occupation}</p>
          </Link>
        ))}
      </div>
    </div>
  );
}

