      <p className="font-satoshi text-brass text-xs tracking-[0.3em] uppercase mb-3">
        Your Profile
      </p>
      <h1 className="font-playfair text-4xl text-ivory mb-8">Profile</h1>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Avatar + status */}
        <div className="lg:col-span-1 space-y-6">
          <div className="border border-ivory/15 bg-charcoal-soft p-6">
            <div className="w-28 h-28 rounded-full bg-brass/10 border border-brass/30 flex items-center justify-center mx-auto mb-4">
              <svg width="28" height="28" fill="none" stroke="#C5A55A" viewBox="0 0 24 24" strokeWidth={1.5}>
                <circle cx="12" cy="8" r="4" />
                <path d="M4 21c0-4 4-6 8-6s8 2 8 6" />
              </svg>
            </div>
            <div className="text-center space-y-3">
              <p className="font-satoshi text-xs tracking-[0.25em] uppercase text-ivory/50">
                Status
              </p>
              {profile.status === "verified" ? (
                <span className="inline-block font-satoshi text-sm text-[#7DDA5A]">
                  Verified
                </span>
              ) : profile.status === "suspended" ? (
                <span className="inline-block font-satoshi text-sm text-[#C97A7A]">
                  Suspended
                </span>
              ) : (
                <span className="inline-block font-satoshi text-sm text-brass">
