                </span>
              )}
            </div>
          </div>
          <div className="border border-ivory/15 bg-charcoal-soft p-6 space-y-3">
            <div>
              <p className="font-satoshi text-xs tracking-[0.25em] uppercase text-ivory/50">
                Membership
              </p>
              <p className="font-playfair text-xl text-ivory">
                {profile.membership_tier
                  ? TIER_LABELS[profile.membership_tier as MembershipTier]
