        {INDUSTRIES.map((ind) => (
          <button
            key={ind}
            type="button"
            onClick={() => toggle(industry, setIndustry, ind)}
            className={classNames(
              "font-satoshi text-xs tracking-widest uppercase px-3 py-1.5 border transition-colors",
              industry.includes(ind)
                ? "border-brass bg-brass text-ink"
                : "border-ivory/20 text-ivory/60 hover:border-brass hover:text-brass"
            )}
          >
            {ind}
          </button>
        ))}
      </div>

      <div className="flex flex-wrap gap-2 mb-10">
        {(Object.keys(TIER_LABELS) as MembershipTier[]).map((t) => (
          <button
            key={t}
            type="button"
            onClick={() => toggle(tier, setTier, t)}
            className={classNames(
              "font-satoshi text-xs tracking-widest uppercase px-3 py-1.5 border transition-colors",
              tier.includes(t)
                ? "border-brass bg-brass text-ink"
                : "border-ivory/20 text-ivory/60 hover:border-brass hover:text-brass"
            )}
          >
            {TIER_LABELS[t]}
          </button>
        ))}
      </div>

      {loading ? (
        <p className="font-satoshi text-sm text-ivory/50">Loading…</p>
      ) : members.length === 0 ? (
        <p className="font-satoshi text-sm text-ivory/50">
          No verified members match your search.
        </p>
      ) : (
        <>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {members.slice(0, visible).map((m) => (
              <Link
                key={m.id}
                href={`/dashboard/directory/${m.id}`}
                className="border border-ivory/15 bg-charcoal-soft p-5 hover:border-brass/50 transition-colors"
              >
                <div className="flex items-center gap-3 mb-3">
                  <div className="w-12 h-12 rounded-full bg-brass/10 border border-brass/30 flex items-center justify-center">
                    <span className="font-playfair text-lg text-brass">
                      {m.first_name.charAt(0)}
                      {m.last_initial}
                    </span>
                  </div>
                  <div>
                    <p className="font-playfair text-lg text-ivory">
                      {m.first_name} {m.last_initial}.
                    </p>
                    <p className="font-satoshi text-xs text-ivory/50">
                      {m.occupation || "—"}
                    </p>
                  </div>
                </div>
                <div className="flex flex-wrap gap-2">
                  {m.industry && (
                    <span className="font-satoshi text-[10px] tracking-widest uppercase text-ivory/50 border border-ivory/15 px-2 py-0.5">
                      {m.industry}
                    </span>
                  )}
                  {m.membership_tier && (
                    <span className="font-satoshi text-[10px] tracking-widest uppercase text-brass border border-brass/30 px-2 py-0.5">
                      {TIER_LABELS[m.membership_tier]}
                    </span>
                  )}
                </div>
              </Link>
            ))}
          </div>
          {visible < members.length && (
            <div className="mt-8 text-center">
              <button
                type="button"
                onClick={() => setVisible((v) => v + PAGE_SIZE)}
                className="font-satoshi text-sm tracking-widest uppercase text-brass border border-brass px-6 py-2 hover:bg-brass hover:text-ink transition-all"
              >
                Load More
              </button>
            </div>
          )}
        </>
      )}
    </div>
  );
}

import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";
import { SESSION_COOKIE } from "./lib/session";

const PROTECTED_PREFIXES = [
  "/dashboard",
  "/members",
  "/events",
  "/parlors",
  "/payment",
  "/admin",
];

const PUBLIC_PREFIXES = ["/login", "/signup"];

export async function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl;

  const isProtected = PROTECTED_PREFIXES.some(
    (p) => pathname === p || pathname.startsWith(p + "/")
  );
  if (!isProtected) return NextResponse.next();

  const token = request.cookies.get(SESSION_COOKIE)?.value;

  if (!token) {
    const url = request.nextUrl.clone();
    url.pathname = "/login";
    url.searchParams.set("redirect", pathname);
    return NextResponse.redirect(url);
  }

  // Redirect already-authenticated users away from auth pages is handled by the
  // pages themselves; here we only enforce presence on protected routes.
  if (PUBLIC_PREFIXES.some((p) => pathname === p)) {
    return NextResponse.next();
  }

  return NextResponse.next();
}

export const config = {
  matcher: [
    "/dashboard/:path*",
    "/members/:path*",
    "/events/:path*",
    "/parlors/:path*",
    "/payment/:path*",
    "/admin/:path*",
    "/dashboard",
    "/members",
    "/events",
    "/parlors",
    "/payment",
    "/admin",
    "/login",
    "/signup",
  ],
};

