"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { getCurrentProfile } from "@/lib/auth"; // not used client-side; removed below
import { classNames, formatDateTime } from "@/lib/utils";
import { EventRow } from "@/lib/types";

type Tab = "upcoming" | "past";

export default function EventsPage() {
  const [tab, setTab] = useState<Tab>("upcoming");
  const [events, setEvents] = useState<EventRow[]>([]);
  const [loading, setLoading] = useState(true);
  const [isAdmin, setIsAdmin] = useState(false);

  useEffect(() => {
    fetch("/api/auth")
      .then((r) => r.json())
      .then((d) => setIsAdmin(d.session?.role === "admin"))
      .catch(() => undefined);
  }, []);

  useEffect(() => {
    setLoading(true);
    fetch(`/api/events?tab=${tab}`)
      .then((r) => r.json())
      .then((data) => {
        setEvents(data.events || []);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, [tab]);

  return (
    <div className="p-6 md:p-10 max-w-5xl mx-auto">
      <div className="flex items-center justify-between mb-8">
        <div>
          <p className="font-satoshi text-brass text-xs tracking-[0.3em] uppercase mb-3">
            The Calendar
          </p>
          <h1 className="font-playfair text-4xl text-ivory">Events</h1>
        </div>
        {isAdmin && (
          <Link
            href="/dashboard/events/create"
            className="font-satoshi text-sm tracking-[0.2em] uppercase text-brass border border-brass px-6 py-2 hover:bg-brass hover:text-ink transition-all"
          >
            Create Event
          </Link>
        )}
      </div>

      <div className="flex gap-1 mb-8 border-b border-ivory/15">
        {(["upcoming", "past"] as Tab[]).map((t) => (
          <button
            key={t}
            type="button"
            onClick={() => setTab(t)}
            className={classNames(
              "font-satoshi text-sm tracking-widest uppercase px-4 py-3 -mb-px border-b-2 transition-colors",
              tab === t
                ? "border-brass text-brass"
                : "border-transparent text-ivory/50 hover:text-ivory"
            )}
          >
            {t === "upcoming" ? "Upcoming" : "Past"}
          </button>
        ))}
      </div>

      {loading ? (
        <p className="font-satoshi text-sm text-ivory/50">Loading…</p>
      ) : events.length === 0 ? (
        <p className="font-satoshi text-sm text-ivory/50">
          {tab === "upcoming"
            ? "No upcoming events. Check back soon."
            : "No past events."}
        </p>
      ) : (
        <div className="space-y-4">
          {events.map((e) => (
            <Link
              key={e.id}
              href={`/dashboard/events/${e.id}`}
              className="block border border-ivory/15 bg-charcoal-soft p-6 hover:border-brass/50 transition-colors"
            >
              <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-2 mb-2">
                <h2 className="font-playfair text-xl text-ivory">{e.name}</h2>
                <span className="font-satoshi text-xs tracking-widest uppercase text-brass">
                  {formatDateTime(e.date_time)}
                </span>
              </div>
              <p className="font-satoshi text-sm text-ivory/60">
                {e.location}
              </p>
              {e.description && (
                <p className="font-satoshi text-sm text-ivory/50 mt-2 line-clamp-1">
                  {e.description}
                </p>
              )}
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}

"use client";

import { ReactNode, useEffect } from "react";

interface ModalProps {
  open: boolean;
  onClose: () => void;
  title?: string;
  children: ReactNode;
  footer?: ReactNode;
}

export default function Modal({ open, onClose, title, children, footer }: ModalProps) {
  useEffect(() => {
    if (!open) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") onClose();
    };
    window.addEventListener("keydown", onKey);
    document.body.style.overflow = "hidden";
    return () => {
      window.removeEventListener("keydown", onKey);
      document.body.style.overflow = "";
    };
  }, [open, onClose]);

  if (!open) return null;

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-ink/90 backdrop-blur-md"
      onClick={onClose}
    >
      <div
        className="relative w-full max-w-md bg-charcoal-soft border border-brass/30 p-8 animate-[fadeIn_0.2s_ease-out]"
        onClick={(e) => e.stopPropagation()}
      >
        {title && (
          <h3 className="font-playfair text-2xl text-ivory mb-6">{title}</h3>
        )}
        <div className="font-satoshi text-sm text-ivory/80 space-y-4">
          {children}
        </div>
        {footer && (
          <div className="mt-8 flex justify-end gap-3">{footer}</div>
        )}
        <button
          aria-label="Close"
          onClick={onClose}
          className="absolute top-4 right-4 text-ivory/40 hover:text-brass"
        >
          <svg width="20" height="20" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={1.5}>
            <path strokeLinecap="round" d="M6 6l12 12M18 6L6 18" />
          </svg>
        </button>
      </div>
    </div>
  );
}

import { ReactNode } from "react";
import { classNames } from "@/lib/utils";

type Tone = "brass" | "amber" | "green" | "red" | "muted";

const tones: Record<Tone, string> = {
  brass: "bg-brass/15 text-brass border-brass/40",
  amber: "bg-amber-400/15 text-amber-300 border-amber-400/40",
  green: "bg-emerald-500/15 text-emerald-300 border-emerald-500/40",
  red: "bg-red-500/15 text-red-300 border-red-500/40",
  muted: "bg-ivory/10 text-ivory/60 border-ivory/20",
};

export default function Badge({
  children,
  tone = "muted",
  className,
}: {
  children: ReactNode;
  tone?: Tone;
  className?: string;
}) {
  return (
    <span
      className={classNames(
        "inline-flex items-center px-2.5 py-1 border text-[10px] font-satoshi font-bold tracking-[0.2em] uppercase",
        tones[tone],
        className
      )}
    >
      {children}
    </span>
  );
}

import { ReactNode } from "react";
import { classNames } from "@/lib/utils";

interface Column<T> {
  key: string;
  header: string;
  render: (row: T) => ReactNode;
  className?: string;
}

export default function Table<T extends { id: string }>({
  columns,
  rows,
  empty = "No records yet.",
}: {
  columns: Column<T>[];
  rows: T[];
  empty?: string;
}) {
  return (
    <div className="overflow-x-auto border border-ivory/10">
      <table className="w-full text-left">
        <thead>
          <tr className="bg-brass/10 border-b border-brass/30">
            {columns.map((c) => (
              <th
                key={c.key}
                className={classNames(
                  "px-5 py-4 font-satoshi text-[11px] font-bold tracking-[0.2em] uppercase text-brass",
                  c.className
                )}
              >
                {c.header}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {rows.length === 0 ? (
            <tr>
              <td
                colSpan={columns.length}
                className="px-5 py-10 text-center font-satoshi text-sm text-ivory/40"
              >
                {empty}
              </td>
            </tr>
          ) : (
            rows.map((row, i) => (
              <tr
                key={row.id}
                className={classNames(
                  "border-b border-ivory/5",
                  i % 2 === 1 ? "bg-charcoal/50" : ""
                )}
              >
                {columns.map((c) => (
                  <td
                    key={c.key}
                    className={classNames(
                      "px-5 py-4 font-satoshi text-sm text-ivory/80",
                      c.className
                    )}
                  >
                    {c.render(row)}
                  </td>
                ))}
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}

