"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import Button from "@/components/ui/Button";
import { Input, Select, Textarea } from "@/components/ui/Input";
import { INDUSTRIES } from "@/lib/types";

// INDUSTRIES not needed here but kept import minimal — removed below
const _unused = INDUSTRIES;

export default function CreateEventPage() {
  const router = useRouter();
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({
    name: "",
    description: "",
    location: "",
    date_time: "",
    capacity: "",
    rsvp_deadline: "",
  });

  function set(key: keyof typeof form, value: string) {
    setForm((f) => ({ ...f, [key]: value }));
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError("");
    setLoading(true);
    try {
      const res = await fetch("/api/events", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...form,
          capacity: Number(form.capacity),
        }),
      });
      const data = await res.json();
      if (!res.ok) {
        setError(data.error || "Unable to create event.");
        setLoading(false);
        return;
      }
      router.push("/dashboard/events");
      router.refresh();
    } catch {
      setError("Network error. Please try again.");
      setLoading(false);
    }
  }

  const tomorrow = new Date(Date.now() + 86400000).toISOString().slice(0, 16);

  return (
    <div className="p-6 md:p-10 max-w-2xl mx-auto">
      <Link
        href="/dashboard/events"
        className="font-satoshi text-sm text-ivory/50 hover:text-brass transition-colors mb-6 inline-block"
      >
        ← Back to events
      </Link>
      <p className="font-satoshi text-brass text-xs tracking-[0.3em] uppercase mb-3">
        New Event
      </p>
      <h1 className="font-playfair text-4xl text-ivory mb-8">Create Event</h1>

      <form onSubmit={handleSubmit} className="space-y-6">
        <Input
          label="Event Name"
          required
          value={form.name}
          onChange={(e) => set("name", e.target.value)}
          placeholder="Salon No. 2 — A Reading"
        />
        <Input
          label="Location"
          required
          value={form.location}
          onChange={(e) => set("location", e.target.value)}
          placeholder="The Salon — West Hollywood"
        />
        <Textarea
          label="Description"
          rows={3}
          value={form.description}
          onChange={(e) => set("description", e.target.value)}
        />
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <Input
            label="Date & Time"
            type="datetime-local"
            required
            value={form.date_time}
            onChange={(e) => set("date_time", e.target.value)}
            min={tomorrow}
          />
          <Input
            label="RSVP Deadline"
            type="datetime-local"
            required
            value={form.rsvp_deadline}
            onChange={(e) => set("rsvp_deadline", e.target.value)}
            min={tomorrow}
          />
        </div>
        <Input
          label="Capacity"
          type="number"
          min={1}
          required
          value={form.capacity}
          onChange={(e) => set("capacity", e.target.value)}
          placeholder="24"
        />

        {error && <p className="font-satoshi text-sm text-[#C97A7A]">{error}</p>}

        <div className="flex gap-3">
          <Button type="submit" loading={loading}>
            Create Event
          </Button>
          <Button type="button" variant="ghost" onClick={() => router.push("/dashboard/events")}>
            Cancel
          </Button>
        </div>
      </form>
    </div>
  );
}

