"use client";

import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import Button from "@/components/ui/Button";
import { useToast } from "@/components/ui/Toast";
import { formatDateTime } from "@/lib/utils";
import { EventRow, Rsvp } from "@/lib/types";

export default function EventDetailPage() {
  const params = useParams<{ id: string }>();
  const router = useRouter();
  const { toast } = useToast();
  const [event, setEvent] = useState<EventRow | null>(null);
  const [goingCount, setGoingCount] = useState(0);
  const [myRsvp, setMyRsvp] = useState<Rsvp | null>(null);
  const [deadlinePassed, setDeadlinePassed] = useState(false);
  const [full, setFull] = useState(false);
  const [loading, setLoading] = useState(true);
  const [toggling, setToggling] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    if (!params.id) return;
    fetch(`/api/events/${params.id}`)
      .then((r) => r.json())
      .then((data) => {
        if (data.error) {
          setError(data.error);
          setLoading(false);
          return;
        }
        setEvent(data.event);
        setGoingCount(data.goingCount);
        setMyRsvp(data.myRsvp);
        setDeadlinePassed(data.deadlinePassed);
        setFull(data.full);
        setLoading(false);
      })
      .catch(() => {
        setError("Unable to load event.");
        setLoading(false);
      });
  }, [params.id]);

  async function handleRsvp() {
    if (!event) return;
    setToggling(true);
    try {
      const res = await fetch(`/api/events/${event.id}/rsvp`, {
        method: "POST",
      });
      const data = await res.json();
      if (!res.ok) {
        toast(data.error || "Unable to update RSVP.", "error");
        setToggling(false);
        return;
      }
      setMyRsvp(data.rsvp);
      setGoingCount(data.goingCount);
      setFull(data.full);
      toast(
        data.rsvp.status === "going" ? "You're going." : "RSVP cancelled.",
        "success"
      );
      setToggling(false);
    } catch {
      toast("Network error.", "error");
      setToggling(false);
    }
  }

  if (loading) {
    return (
      <div className="p-10">
        <p className="font-satoshi text-sm text-ivory/50">Loading…</p>
      </div>
    );
  }
  if (error || !event) {
    return (
      <div className="p-10">
        <p className="font-satoshi text-sm text-[#C97A7A]">{error || "Event not found."}</p>
        <Link
          href="/dashboard/events"
          className="mt-4 inline-block font-satoshi text-sm text-brass hover:underline"
        >
          ← Back to events
        </Link>
      </div>
    );
  }

  const isGoing = myRsvp?.status === "going";
  const isPast = new Date(event.date_time).getTime() < Date.now();

  return (
    <div className="p-6 md:p-10 max-w-3xl mx-auto">
      <Link
        href="/dashboard/events"
        className="font-satoshi text-sm text-ivory/50 hover:text-brass transition-colors mb-6 inline-block"
      >
        ← Back to events
      </Link>

      <p className="font-satoshi text-brass text-xs tracking-[0.3em] uppercase mb-3">
        {isPast ? "Past Event" : "Upcoming"}
      </p>
      <h1 className="font-playfair text-4xl text-ivory mb-4">{event.name}</h1>
      <p className="font-satoshi text-sm text-ivory/60 mb-1">
        {formatDateTime(event.date_time)}
      </p>
      <p className="font-satoshi text-sm text-ivory/60 mb-6">{event.location}</p>

      {event.description && (
        <p className="font-satoshi text-base text-ivory/80 leading-relaxed mb-8">
          {event.description}
        </p>
      )}

      <div className="border border-ivory/15 bg-charcoal-soft p-6 mb-8">
        <div className="grid grid-cols-2 gap-6">
          <div>
            <p className="font-satoshi text-xs tracking-[0.25em] uppercase text-ivory/50 mb-1">
              Attending
            </p>
            <p className="font-playfair text-3xl text-ivory">{goingCount}</p>
          </div>
          <div>
            <p className="font-satoshi text-xs tracking-[0.25em] uppercase text-ivory/50 mb-1">
              Capacity
            </p>
            <p className="font-playfair text-3xl text-ivory">{event.capacity}</p>
          </div>
        </div>
        <p className="font-satoshi text-xs text-ivory/40 mt-4">
          Attendee names are private. Only the count is shown.
        </p>
      </div>

      {!isPast && (
        <div className="flex flex-wrap items-center gap-4">
          {deadlinePassed ? (
            <p className="font-satoshi text-sm text-[#C97A7A]">
              RSVP has closed for this event.
            </p>
          ) : full && !isGoing ? (
            <p className="font-satoshi text-sm text-brass">This event is full.</p>
          ) : (
            <Button
              onClick={handleRsvp}
              loading={toggling}
              variant={isGoing ? "ghost" : "primary"}
            >
              {isGoing ? "Cancel RSVP" : "RSVP"}
            </Button>
          )}
          {isGoing && !deadlinePassed && (
            <span className="font-satoshi text-sm text-[#7DDA5A]">You're attending.</span>
          )}
        </div>
      )}
    </div>
  );
}

import { NextResponse } from "next/server";
import { addWaitlistEmail, listWaitlist } from "@/lib/db";

export async function POST(request: Request) {
  try {
    const body = await request.json().catch(() => ({}));
    const email = typeof body.email === "string" ? body.email : "";
    const normalized = email.trim().toLowerCase();
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(normalized)) {
      return NextResponse.json(
        { error: "Please enter a valid email address." },
        { status: 400 }
      );
    }

    const entry = await addWaitlistEmail(normalized);
    if (!entry) {
      return NextResponse.json(
        { error: "This email is already on our list." },
        { status: 409 }
      );
    }
    return NextResponse.json(
      { success: true, message: "You've been added to the waiting list. We'll be in touch." },
      { status: 201 }
    );
  } catch {
    return NextResponse.json(
      { error: "Something went wrong. Please try again." },
      { status: 500 }
    );
  }
}

export async function GET() {
  const waitlist = await listWaitlist();
  return NextResponse.json({ count: waitlist.length });
}

import { NextResponse } from "next/server";
import { registerUser, setSessionCookie, signSession, AuthError } from "@/lib/auth";
import { createApplication } from "@/lib/db";

export async function POST(request: Request) {
  try {
    const body = await request.json().catch(() => ({}));
    const email = String(body.email ?? "").trim();
    const password = String(body.password ?? "");
    const name = String(body.name ?? "").trim();
    const phone = body.phone ? String(body.phone).trim() : null;
    const referral_source = body.referral_source ? String(body.referral_source) : null;

    if (!name) return NextResponse.json({ error: "Full name is required." }, { status: 400 });
    if (!email) return NextResponse.json({ error: "Email is required." }, { status: 400 });
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) return NextResponse.json({ error: "Please enter a valid email." }, { status: 400 });
    if (password.length < 6) return NextResponse.json({ error: "Password must be at least 6 characters." }, { status: 400 });

    const session = await registerUser({ email, password, name, phone, referral_source });
    await createApplication({
      user_id: session.userId,
      full_name: name,
      email,
      phone,
      referral_source,
    });

    const token = await signSession(session);
    const res = NextResponse.json({ ok: true, redirect: "/dashboard" });
    return setSessionCookie(res, token);
  } catch (e) {
    if (e instanceof AuthError) {
      return NextResponse.json({ error: e.message }, { status: 400 });
    }
    return NextResponse.json({ error: "Something went wrong. Please try again." }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { authenticate, setSessionCookie, signSession, AuthError } from "@/lib/auth";

export async function POST(request: Request) {
  try {
    const body = await request.json().catch(() => ({}));
    const email = String(body.email ?? "").trim();
    const password = String(body.password ?? "");
    const redirect = String(body.redirect ?? "/dashboard");

    if (!email || !password) {
      return NextResponse.json({ error: "Email and password are required." }, { status: 400 });
    }

    const session = await authenticate(email, password);
    const token = await signSession(session);
    const res = NextResponse.json({ ok: true, redirect });
    return setSessionCookie(res, token);
  } catch (e) {
    if (e instanceof AuthError) {
      return NextResponse.json({ error: e.message }, { status: 401 });
    }
    return NextResponse.json({ error: "Something went wrong. Please try again." }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { clearSessionCookie } from "@/lib/auth";

export async function POST() {
  const res = NextResponse.json({ ok: true, redirect: "/" });
  return clearSessionCookie(res);
}

import { NextResponse } from "next/server";
import {
  ensureDemoAccount,
  ensureDemoAdmin,
  setSessionCookie,
  signSession,
} from "@/lib/auth";

export async function POST(request: Request) {
  try {
    const body = await request.json().catch(() => ({}));
    const asAdmin = body.role === "admin";
    const session = asAdmin ? await ensureDemoAdmin() : await ensureDemoAccount();
    const token = await signSession(session);
    const res = NextResponse.json({
      ok: true,
      redirect: asAdmin ? "/admin" : "/dashboard",
    });
    return setSessionCookie(res, token);
  } catch {
    return NextResponse.json(
      { error: "Could not start the demo session." },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { listMembers } from "@/lib/db";
import { getSession } from "@/lib/auth";

export async function GET(request: Request) {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }
  const { searchParams } = new URL(request.url);
  const q = searchParams.get("q")?.trim().toLowerCase() ?? "";

  const members = await listMembers();
  const filtered = q
    ? members.filter((m) => m.name.toLowerCase().includes(q) || m.email.toLowerCase().includes(q))
    : members;

  return NextResponse.json({
    members: filtered.map((m) => ({
      id: m.id,
      name: m.name,
      email: m.email,
      membership_tier: m.membership_tier,
      phone: m.phone ?? null,
      is_self: m.id === session.userId,
    })),
  });
}

import { NextResponse } from "next/server";
import {
  listEvents,
  countAttendees,
  isAttending,
} from "@/lib/db";
import { getSession } from "@/lib/auth";

export async function GET() {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const events = await listEvents();
  const out = await Promise.all(
    events.map(async (e) => ({
      id: e.id,
      title: e.title,
      description: e.description,
      date: e.date,
      time: e.time,
      end_time: e.end_time,
      location: e.location,
      capacity: e.capacity,
      is_private: e.is_private,
      attendee_count: await countAttendees(e.id),
      attending: await isAttending(e.id, session.userId),
      past: new Date(e.date).getTime() < Date.now(),
    }))
  );

  return NextResponse.json({ events: out });
}

import { NextResponse } from "next/server";
import { getEvent, setRsvp } from "@/lib/db";
import { getSession } from "@/lib/auth";

export async function POST(request: Request) {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }
  if (session.role !== "member" && session.role !== "admin") {
    return NextResponse.json(
      { error: "Active membership required to RSVP." },
      { status: 403 }
    );
  }

  const body = await request.json().catch(() => ({}));
  const eventId = String(body.event_id ?? "");
  const action = body.action === "cancel" ? "cancel" : "rsvp";

  const event = await getEvent(eventId);
  if (!event) {
    return NextResponse.json({ error: "Event not found." }, { status: 404 });
  }
  if (new Date(event.date).getTime() < Date.now()) {
    return NextResponse.json({ error: "This event has already passed." }, { status: 400 });
  }

  const result = await setRsvp(eventId, session.userId, action);
  if (!result.ok && action === "rsvp") {
    return NextResponse.json({ error: "This event is at capacity." }, { status: 409 });
  }
  return NextResponse.json(result);
}

import { NextResponse } from "next/server";
import { listParlors } from "@/lib/db";
import { getSession } from "@/lib/auth";

export async function GET() {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }
  const parlors = await listParlors();
  return NextResponse.json({
    parlors: parlors.map((p) => ({
      id: p.id,
      name: p.name,
      description: p.description,
      capacity: p.capacity,
      price_cents: p.price_cents ?? null,
    })),
  });
}

import { NextResponse } from "next/server";
import {
  listParlors,
  isSlotAvailable,
  createBooking,
} from "@/lib/db";
import { getSession } from "@/lib/auth";
import { TIME_SLOTS } from "@/types";

export async function POST(request: Request) {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }
  if (session.role !== "member" && session.role !== "admin") {
    return NextResponse.json(
      { error: "Active membership required to book a parlor." },
      { status: 403 }
    );
  }

  const body = await request.json().catch(() => ({}));
  const parlor_id = String(body.parlor_id ?? "");
  const date = String(body.date ?? "");
  const start_time = String(body.start_time ?? "");
  const duration = Number(body.duration ?? 1);

  if (!parlor_id || !date || !start_time) {
    return NextResponse.json({ error: "Parlor, date, and start time are required." }, { status: 400 });
  }
  if (!TIME_SLOTS.includes(start_time)) {
    return NextResponse.json({ error: "Invalid time slot." }, { status: 400 });
  }
  if (![1, 2, 3].includes(duration)) {
    return NextResponse.json({ error: "Duration must be 1, 2, or 3 hours." }, { status: 400 });
  }
  const parsed = new Date(date);
  if (Number.isNaN(parsed.getTime())) {
    return NextResponse.json({ error: "Invalid date." }, { status: 400 });
  }
  if (parsed.getTime() < new Date(new Date().toDateString()).getTime()) {
    return NextResponse.json({ error: "Cannot book in the past." }, { status: 400 });
  }

  const parlor = (await listParlors()).find((p) => p.id === parlor_id);
  if (!parlor) {
    return NextResponse.json({ error: "Parlor not found." }, { status: 404 });
  }

  const available = await isSlotAvailable(parlor_id, date, start_time, duration);
  if (!available) {
    return NextResponse.json({ error: "That time slot is already booked." }, { status: 409 });
  }

  const booking = await createBooking({
    parlor_id,
    user_id: session.userId,
    date: parsed.toISOString(),
    start_time,
    duration,
  });

  return NextResponse.json({
    ok: true,
    booking: { ...booking, parlor: parlor.name },
    message: `${parlor.name} booked. Check your email for confirmation.`,
  });
}

