import { NextResponse } from "next/server";
import {
  getTierByName,
  createPayment,
  updateUserRole,
  findUserById,
} from "@/lib/db";
import { getSession } from "@/lib/auth";
import { createCheckoutSession, isStripeConfigured } from "@/lib/stripe";

const DEFAULT_TIER = "Founding Member";

export async function POST(request: Request) {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }
  if (session.role !== "pending_payment" && session.role !== "member") {
    return NextResponse.json(
      { error: "Dues are not yet requested for this account." },
      { status: 400 }
    );
  }

  const body = await request.json().catch(() => ({}));
  const tierName = String(body.tier ?? DEFAULT_TIER);
  const tier = await getTierByName(tierName);
  if (!tier) {
    return NextResponse.json({ error: "Unknown membership tier." }, { status: 400 });
  }

  const user = await findUserById(session.userId);
  if (!user) {
    return NextResponse.json({ error: "Account not found." }, { status: 404 });
  }

  const appUrl = process.env.NEXT_PUBLIC_APP_URL ?? "http://localhost:3000";

  if (isStripeConfigured) {
    const created = await createCheckoutSession({
      tierName: tier.name,
      amountCents: tier.price_cents,
      userId: session.userId,
      userEmail: user.email,
      successUrl: `${appUrl}/dashboard?payment=success`,
      cancelUrl: `${appUrl}/payment?canceled=true`,
    });
    if (created) {
      await createPayment({
        user_id: session.userId,
        stripe_session_id: created.sessionId,
        amount_cents: tier.price_cents,
        currency: "usd",
        status: "pending",
        membership_tier: tier.name,
      });
      return NextResponse.json({ ok: true, url: created.url });
    }
  }

  // Demo / no-Stripe path: simulate a successful payment in-app so the flow
  // stays explorable without real Stripe credentials.
  const expiresAt = new Date(Date.now() + 365 * 86400000).toISOString();
  await createPayment({
    user_id: session.userId,
    stripe_session_id: null,
    stripe_payment_intent: null,
    amount_cents: tier.price_cents,
    currency: "usd",
    status: "completed",
    membership_tier: tier.name,
    paid_at: new Date().toISOString(),
    expires_at: expiresAt,
  });
  await updateUserRole(session.userId, "member", {
    membership_tier: tier.name,
    membership_expires_at: expiresAt,
  });

  return NextResponse.json({ ok: true, redirect: "/dashboard?payment=success" });
}

import { NextResponse } from "next/server";
import { verifyWebhookSignature } from "@/lib/stripe";
import {
  createPayment,
  findUserById,
  updateUserRole,
  listAllPayments,
} from "@/lib/db";

export async function POST(request: Request) {
  const rawBody = await request.text();
  const signature = request.headers.get("stripe-signature") ?? "";

  const event = verifyWebhookSignature(rawBody, signature);
  if (!event) {
    return NextResponse.json({ error: "Invalid signature" }, { status: 400 });
  }

  if (event.type === "checkout.session.completed") {
    const session = event.data.object as {
      id: string;
      client_reference_id?: string;
      metadata?: { tier?: string; user_id?: string };
      payment_intent?: string | null;
      amount_total?: number;
    };

    const userId = session.metadata?.user_id ?? session.client_reference_id ?? "";
    const tier = session.metadata?.tier ?? "Founding Member";
    const user = await findUserById(userId);
    if (user) {
      const existing = (await listAllPayments()).find(
        (p) => p.stripe_session_id === session.id
      );
      if (!existing) {
        const expiresAt = new Date(Date.now() + 365 * 86400000).toISOString();
        await createPayment({
          user_id: userId,
          stripe_session_id: session.id,
          stripe_payment_intent:
            typeof session.payment_intent === "string" ? session.payment_intent : null,
          amount_cents: session.amount_total ?? 0,
          currency: "usd",
          status: "completed",
          membership_tier: tier,
          paid_at: new Date().toISOString(),
          expires_at: expiresAt,
        });
        await updateUserRole(userId, "member", {
          membership_tier: tier,
          membership_expires_at: expiresAt,
        });
      }
    }
  }

  return NextResponse.json({ received: true });
}

"use client";

import { useState, useTransition } from "react";
import { useRouter } from "next/navigation";
import { useToast } from "@/components/ui/Toast";

export function MemberActions({ memberId }: { memberId: string }) {
  const router = useRouter();
  const { toast } = useToast();
  const [pending, start] = useTransition();
  const [busy, setBusy] = useState("");

  async function call(
    action: "verify" | "suspend" | "delete",
    endpoint: string,
    method: "PUT" | "DELETE",
    confirmMsg: string
  ) {
    if (!confirm(confirmMsg)) return;
    setBusy(action);
    start(async () => {
      try {
        const res = await fetch(endpoint, { method });
        const data = await res.json();
        if (!res.ok) {
          toast(data.error || "Action failed.", "error");
          setBusy("");
          return;
        }
        toast(`Member ${action}d.`, "success");
        router.refresh();
      } catch {
        toast("Network error.", "error");
      }
      setBusy("");
    });
  }

  return (
    <div className="flex items-center gap-3">
      <button
        type="button"
        disabled={pending}
        onClick={() =>
          call("verify", `/api/admin/members/${memberId}/verify`, "PUT", "Verify this member?")
        }
        className="font-satoshi text-xs uppercase tracking-widest text-[#7DDA5A] hover:underline disabled:opacity-50"
        title="Verify"
      >
        {busy === "verify" ? "…" : "Verify"}
      </button>
      <button
        type="button"
        disabled={pending}
        onClick={() =>
          call("suspend", `/api/admin/members/${memberId}/suspend`, "PUT", "Suspend this member?")
        }
        className="font-satoshi text-xs uppercase tracking-widest text-brass hover:underline disabled:opacity-50"
        title="Suspend"
      >
        {busy === "suspend" ? "…" : "Suspend"}
      </button>
      <button
        type="button"
        disabled={pending}
        onClick={() =>
          call("delete", `/api/admin/members/${memberId}/delete`, "DELETE", "Permanently delete this member?")
        }
        className="font-satoshi text-xs uppercase tracking-widest text-[#C97A7A] hover:underline disabled:opacity-50"
        title="Delete"
      >
        {busy === "delete" ? "…" : "Delete"}
      </button>
    </div>
  );
}

export function EventDeleteAction({ eventId }: { eventId: string }) {
  const router = useRouter();
  const { toast } = useToast();
  const [pending, start] = useTransition();

  return (
    <button
      type="button"
      disabled={pending}
      onClick={() => {
        if (!confirm("Delete this event and all RSVPs?")) return;
        start(async () => {
          try {
            const res = await fetch(`/api/events/${eventId}`, { method: "DELETE" });
            const data = await res.json();
            if (!res.ok) {
              toast(data.error || "Delete failed.", "error");
              return;
            }
            toast("Event deleted.", "success");
            router.refresh();
          } catch {
            toast("Network error.", "error");
          }
        });
      }}
      className="font-satoshi text-xs uppercase tracking-widest text-[#C97A7A] hover:underline disabled:opacity-50"
    >
      {pending ? "…" : "Delete"}
    </button>
  );
}

import { NextResponse } from "next/server";
import {
  getApplication,
  updateApplicationStatus,
  findUserById,
  updateUserRole,
  logAudit,
} from "@/lib/db";
import { requireAdmin } from "@/lib/auth";

export async function POST(
  request: Request,
  { params }: { params: Promise<{ id: string }> }
) {
  let session;
  try {
    session = await requireAdmin();
  } catch {
    return NextResponse.json({ error: "Unauthorized" }, { status: 403 });
  }

  const { id } = await params;
  const body = await request.json().catch(() => ({}));
  const action = body.action === "reject" ? "reject" : "approve";
  const rejectionReason = body.rejection_reason ? String(body.rejection_reason) : null;

  const app = await getApplication(id);
  if (!app) {
    return NextResponse.json({ error: "Application not found." }, { status: 404 });
  }

  if (action === "approve") {
    await updateApplicationStatus(id, "approved", session.userId);
    if (app.user_id) {
      await updateUserRole(app.user_id, "pending_payment", {
        membership_tier: "Founding Member",
      });
    }
    await logAudit({
      action: "application_approved",
      admin_id: session.userId,
      target_id: id,
      description: `Approved application for ${app.full_name}.`,
    });
    return NextResponse.json({ ok: true, status: "approved" });
  }

  await updateApplicationStatus(id, "rejected", session.userId, rejectionReason ?? undefined);
  if (app.user_id) {
    await updateUserRole(app.user_id, "pending", { membership_tier: null });
  }
  await logAudit({
    action: "application_rejected",
    admin_id: session.userId,
    target_id: id,
    description: `Rejected application for ${app.full_name}.`,
  });
  return NextResponse.json({ ok: true, status: "rejected" });
}

import { NextResponse } from "next/server";
import { createEvent } from "@/lib/db";
import { requireAdmin } from "@/lib/auth";

export async function POST(request: Request) {
  let session;
  try {
    session = await requireAdmin();
  } catch {
    return NextResponse.json({ error: "Unauthorized" }, { status: 403 });
  }

  const body = await request.json().catch(() => ({}));
  const title = String(body.title ?? "").trim();
  const description = String(body.description ?? "").trim();
  const date = String(body.date ?? "");
  const time = String(body.time ?? "19:00");
  const location = String(body.location ?? "").trim();
  const capacity = Number(body.capacity ?? 0);

  if (!title || !date || !location || !capacity) {
    return NextResponse.json(
      { error: "Title, date, location, and capacity are required." },
      { status: 400 }
    );
  }
  const parsed = new Date(date);
  if (Number.isNaN(parsed.getTime())) {
    return NextResponse.json({ error: "Invalid date." }, { status: 400 });
  }

  const ev = await createEvent({
    title,
    description,
    date: parsed.toISOString(),
    time,
    end_time: body.end_time ? String(body.end_time) : null,
    location,
    capacity,
    image_url: null,
    is_private: true,
    created_by: session.userId,
  });

  return NextResponse.json({ ok: true, event: ev });
}

