"use client";

import { useEffect, useMemo, useState } from "react";
import Link from "next/link";
import Navbar from "@/components/layout/Navbar";
import Badge from "@/components/ui/Badge";
import Modal from "@/components/ui/Modal";
import { initials } from "@/lib/utils";

interface Member {
  id: string;
  name: string;
  email: string;
  membership_tier: string | null;
  phone: string | null;
  is_self: boolean;
}

function tierTone(tier: string | null) {
  if (tier === "Benefactor") return "brass" as const;
  if (tier === "Patron") return "amber" as const;
  return "muted" as const;
}

export default function MembersPage() {
  const [members, setMembers] = useState<Member[]>([]);
  const [q, setQ] = useState("");
  const [selected, setSelected] = useState<Member | null>(null);

  useEffect(() => {
    let active = true;
    const t = setTimeout(async () => {
      const res = await fetch(`/api/members?q=${encodeURIComponent(q)}`);
      const data = await res.json();
      if (active && res.ok) setMembers(data.members ?? []);
    }, 300);
    return () => {
      active = false;
      clearTimeout(t);
    };
  }, [q]);

  const visible = useMemo(() => members.slice(0, 60), [members]);

  return (
    <div className="min-h-screen bg-ink">
      <Navbar name="Member" />
      <main className="max-w-6xl mx-auto px-6 py-12">
        <div className="flex flex-col sm:flex-row sm:items-end sm:justify-between gap-4 mb-8">
          <div>
            <p className="font-satoshi text-xs tracking-[0.3em] uppercase text-brass mb-2">
              The Directory
            </p>
            <h1 className="font-playfair text-4xl text-ivory">Members</h1>
          </div>
          <div className="relative w-full sm:w-80">
            <input
              value={q}
              onChange={(e) => setQ(e.target.value)}
              placeholder="Search by name or email"
              className="w-full bg-charcoal-soft border border-ivory/15 px-4 py-3 pl-10 text-ivory font-satoshi text-sm placeholder:text-ivory/35 focus:border-brass transition-colors"
            />
            <svg
              className="absolute left-3 top-3.5 w-4 h-4 text-ivory/40"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
              strokeWidth={1.5}
            >
              <circle cx="11" cy="11" r="7" />
              <path d="M21 21l-4-4" strokeLinecap="round" />
            </svg>
          </div>
        </div>

        {visible.length === 0 ? (
          <p className="font-satoshi text-sm text-ivory/50">No members found.</p>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {visible.map((m) => (
              <div
                key={m.id}
                className="border border-ivory/10 bg-charcoal-soft p-6 hover:border-brass/40 transition-colors"
              >
                <div className="flex items-center gap-4">
                  <span className="w-16 h-16 rounded-full bg-brass/15 border border-brass/40 text-brass flex items-center justify-center font-satoshi font-bold">
                    {initials(m.name)}
                  </span>
                  <div className="min-w-0">
                    <p className="font-playfair text-lg text-ivory truncate">
                      {m.name}
                      {m.is_self && (
                        <span className="ml-2 font-satoshi text-[10px] tracking-[0.2em] uppercase text-brass">
                          You
                        </span>
                      )}
                    </p>
                    {m.membership_tier && (
                      <div className="mt-2">
                        <Badge tone={tierTone(m.membership_tier)}>
                          {m.membership_tier}
                        </Badge>
                      </div>
                    )}
                  </div>
                </div>
                <button
                  onClick={() => setSelected(m)}
                  className="mt-5 w-full font-satoshi text-xs tracking-[0.2em] uppercase text-ivory/70 border border-ivory/20 py-2.5 hover:border-brass hover:text-brass transition-colors"
                >
                  Connect
                </button>
              </div>
            ))}
          </div>
        )}

        <Modal
          open={!!selected}
          onClose={() => setSelected(null)}
          title={selected ? selected.name : ""}
          footer={
            <button
              onClick={() => setSelected(null)}
              className="font-satoshi text-xs tracking-[0.2em] uppercase text-ivory/60 hover:text-brass"
            >
              Close
            </button>
          }
        >
          {selected && (
            <div className="space-y-3">
              <div>
                <p className="text-[10px] tracking-[0.2em] uppercase text-ivory/40">
                  Email
                </p>
                <a
                  href={`mailto:${selected.email}`}
                  className="text-brass hover:underline"
                >
                  {selected.email}
                </a>
              </div>
              {selected.phone && (
                <div>
                  <p className="text-[10px] tracking-[0.2em] uppercase text-ivory/40">
                    Phone
                  </p>
                  <p>{selected.phone}</p>
                </div>
              )}
              {selected.membership_tier && (
                <div>
                  <p className="text-[10px] tracking-[0.2em] uppercase text-ivory/40">
                    Tier
                  </p>
                  <p>{selected.membership_tier}</p>
                </div>
              )}
              <p className="text-xs text-ivory/40 pt-2">
                Contact is shared at each member&rsquo;s discretion.
              </p>
            </div>
          )}
        </Modal>

        <p className="mt-10 font-satoshi text-xs text-ivory/40">
          <Link href="/dashboard" className="text-brass hover:underline">
            ← Back to dashboard
          </Link>
        </p>
      </main>
    </div>
  );
}

"use client";

import { useState } from "react";

const TIERS = [
  { value: "basic", label: "Basic — $1,200/yr" },
  { value: "premium", label: "Premium — $2,200/yr" },
  { value: "vip", label: "VIP — $3,500/yr" },
];

export default function WaitlistForm() {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [referral, setReferral] = useState("");
  const [tier, setTier] = useState("");
  const [status, setStatus] = useState<"idle" | "loading" | "success" | "error">("idle");
  const [message, setMessage] = useState("");

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!name || !email || !tier) return;

    setStatus("loading");
    try {
      const res = await fetch("/api/waitlist", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name, email, referral, tier }),
      });
      const data = await res.json();
      if (res.ok) {
        setStatus("success");
        setMessage(data.message || "Your interest has been received.");
        setName("");
        setEmail("");
        setReferral("");
        setTier("");
      } else {
        setStatus("error");
        setMessage(data.error || "Something went wrong.");
      }
    } catch {
      setStatus("error");
      setMessage("Network error. Please try again.");
    }
  }

  const fieldClass =
    "w-full bg-charcoal-soft border border-ivory/15 px-5 py-4 text-ivory font-satoshi placeholder:text-ivory/35 focus:border-brass transition-colors";
  const labelClass =
    "block font-satoshi text-xs tracking-[0.25em] uppercase text-ivory/60 mb-2";

  return (
    <section id="waitlist" className="relative py-28 px-6 bg-ink border-t border-brass/10">
      <div className="max-w-xl mx-auto">
        <div className="text-center mb-12">
          <p className="font-satoshi text-brass text-xs tracking-[0.3em] uppercase mb-6">
            Membership Interest
          </p>
          <h2 className="font-playfair text-4xl md:text-5xl text-ivory mb-6">
            Submit <span className="text-brass-gradient">Interest</span>
          </h2>
          <div className="salon-divider w-32 mx-auto mb-6" />
          <p className="font-satoshi text-base text-ivory/70 leading-relaxed">
            Founding membership is limited. Submit your interest and you will be
            the first contacted when invitations open. No public list — only a
            quiet note from the house.
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label htmlFor="name" className={labelClass}>
              Full Name
            </label>
            <input
              id="name"
              type="text"
              required
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Your name"
              className={fieldClass}
            />
          </div>

          <div>
            <label htmlFor="email" className={labelClass}>
              Email
            </label>
            <input
              id="email"
              type="email"
              required
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="you@domain.com"
              className={fieldClass}
            />
          </div>

          <div>
            <label htmlFor="referral" className={labelClass}>
              LinkedIn / Referral — how did you hear about us?
            </label>
            <input
              id="referral"
              type="text"
              value={referral}
              onChange={(e) => setReferral(e.target.value)}
              placeholder="linkedin.com/in/… or a member&rsquo;s name"
              className={fieldClass}
            />
          </div>

          <div>
            <label htmlFor="tier" className={labelClass}>
              Membership Tier Interest
            </label>
            <select
              id="tier"
              required
              value={tier}
              onChange={(e) => setTier(e.target.value)}
              className={`${fieldClass} appearance-none cursor-pointer`}
            >
              <option value="" disabled>
                Select a tier
              </option>
              {TIERS.map((t) => (
                <option key={t.value} value={t.value} className="bg-charcoal-soft text-ivory">
                  {t.label}
                </option>
              ))}
            </select>
          </div>

          <button
            type="submit"
            disabled={status === "loading"}
            className="w-full bg-brass text-ink py-4 font-satoshi text-sm font-bold tracking-[0.25em] uppercase hover:bg-brass-bright transition-all duration-300 disabled:opacity-50"
          >
            {status === "loading" ? "Submitting…" : "Submit Interest"}
          </button>
        </form>

        {message && (
          <p
            className={`mt-6 font-satoshi text-sm ${
              status === "success" ? "text-brass" : "text-[#C97A7A]"
            }`}
          >
            {message}
          </p>
        )}
      </div>
    </section>
  );
}

