    setSuccess("");
    setStartTime("");
    setDuration("1");
    const today = new Date();
    setDate(today.toISOString().slice(0, 10));
  }

  async function confirm() {
    if (!open) return;
    setBusy(true);
    setError("");
    setSuccess("");
