                icon="calendar"
                label="Upcoming Events"
                value={`${upcoming.length}`}
              />
              <Tile
                href="/members"
                icon="users"
                label="Member Directory"
                value="Browse"
              />
              <Tile
                href="/parlors"
                icon="door"
                label="Book a Parlor"
                value="Reserve"
              />
            </section>

            {bookings.length > 0 && (
              <section>
                <h2 className="font-playfair text-2xl text-ivory mb-5">
