  initialAttending,
  initialCount,
  capacity,
  past,
}: {
  eventId: string;
  initialAttending: boolean;
  initialCount: number;
  capacity: number;
  past: boolean;
}) {
  const [attending, setAttending] = useState(initialAttending);
  const [count, setCount] = useState(initialCount);
  const [busy, setBusy] = useState(false);
  const [confirmCancel, setConfirmCancel] = useState(false);
  const [error, setError] = useState("");

  async function rsvp() {
    setBusy(true);
    setError("");
    const res = await fetch("/api/events/rsvp", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ event_id: eventId, action: "rsvp" }),
    });
    const data = await res.json();
    if (res.ok) {
      setAttending(true);
      setCount(data.count);
    } else {
      setError(data.error ?? "Could not RSVP.");
    }
    setBusy(false);
  }

  async function cancel() {
    setBusy(true);
    setError("");
    const res = await fetch("/api/events/rsvp", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ event_id: eventId, action: "cancel" }),
    });
    const data = await res.json();
    if (res.ok) {
      setAttending(false);
      setCount(data.count);
    } else {
      setError(data.error ?? "Could not cancel.");
    }
    setConfirmCancel(false);
    setBusy(false);
  }

  if (past) {
    return <span className="font-satoshi text-xs text-ivory/40">This event has passed.</span>;
  }

  return (
