// Shared domain types for the Goon MVP.
//
// The app persists to a local JSON-file store (lib/db.ts) in the sandbox and
// preview, and can be pointed at Postgres via Prisma in production. These
// types describe the on-disk shape used throughout.

export type UserRole = "pending" | "pending_payment" | "member" | "admin";

export interface SessionUser {
  userId: string;
  role: UserRole;
  email: string;
  name: string;
  membership_tier: string | null;
}

export interface User {
  id: string;
  email: string;
  name: string;
  password_hash: string;
  phone: string | null;
  referral_source: string | null;
  role: UserRole;
  membership_tier: string | null;
  membership_expires_at: string | null;
  avatar_url: string | null;
  created_at: string;
  updated_at: string;
}

export type ApplicationStatus = "pending" | "approved" | "rejected";

export interface MembershipApplication {
  id: string;
  user_id: string | null;
  full_name: string;
  email: string;
  phone: string | null;
  referral_source: string | null;
  status: ApplicationStatus;
  reviewed_by: string | null;
  reviewed_at: string | null;
  rejection_reason: string | null;
  created_at: string;
}

export interface Tier {
  id: string;
  name: string;
  price_cents: number;
  description: string;
  benefits: string[];
  is_active: boolean;
  created_at: string;
}

export interface EventRow {
  id: string;
  title: string;
  description: string;
  date: string;
  time: string;
  end_time: string | null;
  location: string;
  capacity: number;
  image_url: string | null;
  is_private: boolean;
  created_by: string;
  created_at: string;
  updated_at: string;
}

export interface Attendee {
  id: string;
  event_id: string;
  user_id: string;
  created_at: string;
}

export interface Parlor {
  id: string;
  name: string;
  description: string;
  capacity: number;
  price_cents: number | null;
  image_url: string | null;
  is_active: boolean;
  created_at: string;
}

export type BookingStatus = "confirmed" | "cancelled";

export interface Booking {
  id: string;
  parlor_id: string;
  user_id: string;
  date: string;
  start_time: string;
  end_time: string;
  duration: number;
  status: BookingStatus;
  created_at: string;
}

export type PaymentStatus = "pending" | "completed" | "refunded" | "failed";

export interface Payment {
  id: string;
  user_id: string;
  stripe_session_id: string | null;
  stripe_payment_intent: string | null;
  amount_cents: number;
  currency: string;
  status: PaymentStatus;
  membership_tier: string;
  paid_at: string | null;
  expires_at: string | null;
  created_at: string;
}

export interface WaitlistEntry {
  id: string;
  email: string;
  created_at: string;
}

export interface AuditLog {
  id: string;
  action: string;
  admin_id: string | null;
  target_id: string | null;
  description: string;
  created_at: string;
}

export interface Database {
  users: User[];
  waitlist: WaitlistEntry[];
  applications: MembershipApplication[];
  tiers: Tier[];
  events: EventRow[];
  attendees: Attendee[];
  parlors: Parlor[];
  bookings: Booking[];
  payments: Payment[];
  audit_logs: AuditLog[];
}

export const REFERRAL_SOURCES = [
  "Friend",
  "Event",
  "Social",
  "Press",
  "Other",
] as const;

export const TIME_SLOTS = [
  "09:00",
  "10:00",
  "11:00",
  "12:00",
  "13:00",
  "14:00",
  "15:00",
  "16:00",
  "17:00",
  "18:00",
  "19:00",
  "20:00",
  "21:00",
] as const;

import { redirect } from "next/navigation";
import Navbar from "@/components/layout/Navbar";
import PaymentClient from "@/components/PaymentClient";
import { getSession } from "@/lib/auth";
import { findUserById, listTiers } from "@/lib/db";

export default async function PaymentPage({
  searchParams,
}: {
  searchParams: Promise<{ canceled?: string }>;
}) {
  const session = await getSession();
  if (!session) redirect("/login?redirect=/payment");
  const user = await findUserById(session.userId);
  if (!user) redirect("/login");

  // Members who already have a tier have nothing to pay here.
  if (user.role === "member" && user.membership_tier) {
    redirect("/dashboard");
  }

  const params = await searchParams;
  const tiers = await listTiers();

  return (
    <div className="min-h-screen bg-ink">
      <Navbar
        name={user.name}
        membershipTier={user.membership_tier}
        isAdmin={user.role === "admin"}
      />
      <main className="max-w-xl mx-auto px-6 py-12">
        <PaymentClient
          tiers={tiers.map((t) => ({
            id: t.id,
            name: t.name,
            price_cents: t.price_cents,
            description: t.description,
            benefits: t.benefits,
          }))}
          defaultTier="Founding Member"
          canceled={params.canceled === "true"}
        />
      </main>
    </div>
  );
}

import { NextResponse } from "next/server";
import { getSession } from "@/lib/auth";
import { findUserById } from "@/lib/db";

export async function GET() {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ user: null });
  }
  const user = await findUserById(session.userId);
  if (!user) {
    return NextResponse.json({ user: null });
  }
  return NextResponse.json({
    user: {
      id: user.id,
      email: user.email,
      name: user.name,
      role: user.role,
      membership_tier: user.membership_tier,
      membership_expires_at: user.membership_expires_at,
    },
  });
