import { NextResponse } from "next/server";
import { getSession } from "@/lib/auth";
import { findUserById, updateUserRole } from "@/lib/db";

export async function GET() {
  const session = await getSession();
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  const user = await findUserById(session.userId);
  if (!user) return NextResponse.json({ error: "Not found" }, { status: 404 });
  return NextResponse.json({
    user: {
      id: user.id,
      name: user.name,
      email: user.email,
      phone: user.phone,
      referral_source: user.referral_source,
      role: user.role,
      membership_tier: user.membership_tier,
      membership_expires_at: user.membership_expires_at,
    },
  });
}

export async function PUT(request: Request) {
  const session = await getSession();
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const body = await request.json().catch(() => ({}));
  const name = typeof body.name === "string" ? body.name.trim() : "";
  const phone = typeof body.phone === "string" ? body.phone.trim() : null;

  if (!name) {
    return NextResponse.json({ error: "Name is required." }, { status: 400 });
  }

  const updated = await updateUserRole(session.userId, session.role, {
    name,
    phone: phone || null,
  });
  if (!updated) return NextResponse.json({ error: "Not found" }, { status: 404 });
  return NextResponse.json({
    user: {
      id: updated.id,
      name: updated.name,
      email: updated.email,
      phone: updated.phone,
      role: updated.role,
      membership_tier: updated.membership_tier,
    },
  });
}

"use client";

import { useState } from "react";
import { Input } from "@/components/ui/Input";
import { useToast } from "@/components/ui/Toast";

interface ProfileFormProps {
  initial: {
    name: string;
    email: string;
    phone: string | null;
    referral_source: string | null;
    membership_tier: string | null;
    role: string;
  };
}

export default function ProfileForm({ initial }: ProfileFormProps) {
  const { toast } = useToast();
  const [name, setName] = useState(initial.name);
  const [phone, setPhone] = useState(initial.phone ?? "");
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");

  async function save(e: React.FormEvent) {
    e.preventDefault();
    setSaving(true);
    setError("");
    try {
      const res = await fetch("/api/profile", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name, phone }),
      });
      const data = await res.json();
      if (res.ok) {
        toast("Profile updated.", "success");
      } else {
        setError(data.error ?? "Could not save.");
      }
    } catch {
      setError("Network error.");
    } finally {
      setSaving(false);
    }
  }

  return (
    <form onSubmit={save} className="space-y-5">
      <Input
        id="name"
        label="Full Name"
        required
        value={name}
        onChange={(e) => setName(e.target.value)}
      />
      <Input
        id="email"
        label="Email"
        value={initial.email}
        disabled
        hint="Email cannot be changed here. Contact the steward."
      />
      <Input
        id="phone"
        label="Phone"
        type="tel"
        value={phone}
        onChange={(e) => setPhone(e.target.value)}
        placeholder="+1 (310) 555-0000"
      />
      {error && <p className="font-satoshi text-sm text-[#C97A7A]">{error}</p>}
      <button
        type="submit"
        disabled={saving}
        className="bg-brass text-ink px-8 py-3 font-satoshi text-xs tracking-[0.2em] uppercase hover:bg-brass-bright transition-colors disabled:opacity-50"
      >
        {saving ? "Saving…" : "Save Changes"}
      </button>
    </form>
  );
}

