export type UserRole =
  | "pending"
  | "pending_payment"
  | "member"
  | "admin";

export type ApplicationStatus = "pending" | "approved" | "rejected";
export type PaymentStatus = "pending" | "completed" | "failed" | "refunded";
export type BookingStatus = "confirmed" | "cancelled";

export interface User {
  id: string;
  email: string;
  name: string;
  password_hash: string;
  phone?: string | null;
  referral_source?: string | null;
  role: UserRole;
  membership_tier?: string | null;
  membership_expires_at?: string | null;
  avatar_url?: string | null;
  created_at: string;
  updated_at: string;
}

export interface WaitlistEntry {
  id: string;
  email: string;
  created_at: string;
}

export interface MembershipApplication {
  id: string;
  user_id?: string | null;
  full_name: string;
  email: string;
  phone?: string | null;
  referral_source?: string | null;
  status: ApplicationStatus;
  reviewed_by?: string | null;
  reviewed_at?: string | null;
  rejection_reason?: string | null;
  created_at: string;
}

export interface MembershipTierRow {
  id: string;
  name: string;
  price_cents: number;
  description: string;
  benefits: string[];
  is_active: boolean;
  created_at: string;
}

export interface EventRow {
  id: string;
  title: string;
  description: string;
  date: string;
  time: string;
  end_time?: string | null;
  location: string;
  capacity: number;
  image_url?: string | null;
  is_private: boolean;
  created_by: string;
  created_at: string;
  updated_at: string;
}

export interface EventAttendee {
  id: string;
  user_id: string;
  event_id: string;
  created_at: string;
}

export interface Parlor {
  id: string;
  name: string;
  description: string;
  capacity: number;
  price_cents?: number | null;
  image_url?: string | null;
  is_active: boolean;
  created_at: string;
}

export interface ParlorBooking {
  id: string;
  parlor_id: string;
  user_id: string;
  date: string;
  start_time: string;
  end_time: string;
  duration: number;
  status: BookingStatus;
  created_at: string;
}

export interface Payment {
  id: string;
  user_id: string;
  stripe_session_id?: string | null;
  stripe_payment_intent?: string | null;
  amount_cents: number;
  currency: string;
  status: PaymentStatus;
  membership_tier: string;
  paid_at?: string | null;
  expires_at?: string | null;
  created_at: string;
}

export interface AuditLog {
  id: string;
  action: string;
  admin_id?: string | null;
  target_id?: string | null;
  description: string;
  created_at: string;
}

export interface SessionUser {
  userId: string;
  role: UserRole;
  email: string;
  name: string;
  membership_tier?: string | null;
}

export interface Database {
  users: User[];
  waitlist: WaitlistEntry[];
  applications: MembershipApplication[];
  tiers: MembershipTierRow[];
  events: EventRow[];
  attendees: EventAttendee[];
  parlors: Parlor[];
  bookings: ParlorBooking[];
  payments: Payment[];
  audit_logs: AuditLog[];
}

export const REFERRAL_SOURCES = [
  "Friend",
  "Social",
  "Event",
  "Other",
] as const;

export const TIME_SLOTS = (() => {
  const slots: string[] = [];
  for (let h = 9; h <= 20; h++) {
    slots.push(`${String(h).padStart(2, "0")}:00`);
  }
  return slots;
})();

// True when the given env value is present AND not a placeholder used by the
// sandbox/preview. The demo deploy ships with placeholder-but-truthy values
// like "https://placeholder.example.com"; those must NOT enable real backends.
export function isRealEnv(value: string | undefined): boolean {
  if (!value) return false;
  const v = value.trim();
  if (!v) return false;
  return !/placeholder|example\.com|change-me|x{5,}/i.test(v);
}

// Shared cookie/session constants. Kept separate from lib/auth.ts so the
// Edge middleware can import the cookie name without pulling in `jose`.

export const SESSION_COOKIE = "goon_session";
export const COOKIE_MAX_AGE = 60 * 60 * 24 * 30; // 30 days

import { SignJWT, jwtVerify } from "jose";
import { cookies } from "next/headers";
import bcrypt from "bcryptjs";
import { NextResponse } from "next/server";
import {
  createUser,
  findUserByEmail,
  findUserById,
  updateUserRole,
} from "./db";
import { SESSION_COOKIE, COOKIE_MAX_AGE } from "./session";
import type { SessionUser, UserRole } from "@/types";

function secret(): Uint8Array {
  const raw =
    process.env.AUTH_SECRET ||
    process.env.SECRET_KEY ||
    "goon-dev-secret-change-in-production-please";
  return new TextEncoder().encode(raw);
}

export async function signSession(payload: SessionUser): Promise<string> {
  return new SignJWT({ ...payload })
    .setProtectedHeader({ alg: "HS256" })
    .setIssuedAt()
    .setExpirationTime(`${COOKIE_MAX_AGE}s`)
    .sign(secret());
}

export async function verifySession(token: string): Promise<SessionUser | null> {
  try {
    const { payload } = await jwtVerify(token, secret());
    const userId = payload.userId as string | undefined;
    const role = payload.role as UserRole | undefined;
    const email = payload.email as string | undefined;
    const name = payload.name as string | undefined;
    if (!userId || !role || !email || !name) return null;
    return {
      userId,
      role,
      email,
      name,
      membership_tier: (payload.membership_tier as string | null) ?? null,
    };
  } catch {
    return null;
  }
}

export async function getSession(): Promise<SessionUser | null> {
  const store = await cookies();
  const token = store.get(SESSION_COOKIE)?.value;
  if (!token) return null;
  const session = await verifySession(token);
  if (!session) return null;
  // Refresh role/tier from store in case it changed (e.g. after payment).
  const user = await findUserById(session.userId);
  if (!user) return null;
  return {
    userId: user.id,
    role: user.role,
    email: user.email,
    name: user.name,
    membership_tier: user.membership_tier ?? null,
  };
}

export class RedirectError {
  constructor(public destination: string) {}
}
export class AuthError extends Error {}

export async function requireUser(): Promise<SessionUser> {
  const session = await getSession();
  if (!session) throw new RedirectError("/login?redirect=/dashboard");
  return session;
}

export async function requireMember(): Promise<SessionUser> {
  const session = await requireUser();
  if (session.role !== "member" && session.role !== "admin") {
    throw new RedirectError("/payment");
  }
  return session;
}

export async function requireAdmin(): Promise<SessionUser> {
  const session = await requireUser();
  if (session.role !== "admin") throw new RedirectError("/dashboard");
  return session;
}

/** Set the session cookie on a NextResponse (route handlers). */
export function setSessionCookie(res: NextResponse, token: string): NextResponse {
  res.cookies.set(SESSION_COOKIE, token, {
    httpOnly: true,
    sameSite: "lax",
    secure: process.env.NODE_ENV === "production",
    path: "/",
    maxAge: COOKIE_MAX_AGE,
  });
  return res;
}

export function clearSessionCookie(res: NextResponse): NextResponse {
  res.cookies.set(SESSION_COOKIE, "", {
    httpOnly: true,
    sameSite: "lax",
    secure: process.env.NODE_ENV === "production",
    path: "/",
    maxAge: 0,
  });
  return res;
}

export async function authenticate(email: string, password: string): Promise<SessionUser> {
  const user = await findUserByEmail(email);
  if (!user) throw new AuthError("No account found for that email.");
  const ok = await bcrypt.compare(password, user.password_hash);
  if (!ok) throw new AuthError("Incorrect password. Please try again.");
  return {
    userId: user.id,
    role: user.role,
    email: user.email,
    name: user.name,
    membership_tier: user.membership_tier ?? null,
  };
}

export async function registerUser(input: {
  email: string;
  password: string;
  name: string;
  phone?: string | null;
  referral_source?: string | null;
}): Promise<SessionUser> {
  const existing = await findUserByEmail(input.email);
  if (existing) throw new AuthError("An account with that email already exists.");
  const user = await createUser({
    email: input.email,
    password: input.password,
    name: input.name,
    phone: input.phone ?? null,
    referral_source: input.referral_source ?? null,
    role: "pending",
  });
  return {
    userId: user.id,
    role: user.role,
    email: user.email,
    name: user.name,
    membership_tier: null,
  };
}

