export async function findUserByEmail(email: string) {
  const db = await load();
  const norm = email.trim().toLowerCase();
  return db.users.find((u) => u.email === norm) ?? null;
}
export async function findUserById(id: string) {
  const db = await load();
  return db.users.find((u) => u.id === id) ?? null;
}
export async function createUser(input: {
  email: string;
  password: string;
  name: string;
  phone?: string | null;
  referral_source?: string | null;
  role?: Database["users"][number]["role"];
}) {
  const hash = await bcrypt.hash(input.password, 10);
  const now = new Date().toISOString();
  const user: Database["users"][number] = {
    id: crypto.randomUUID(),
    email: input.email.trim().toLowerCase(),
    name: input.name.trim(),
    password_hash: hash,
    phone: input.phone ?? null,
    referral_source: input.referral_source ?? null,
    role: input.role ?? "pending",
    membership_tier: null,
    membership_expires_at: null,
    avatar_url: null,
    created_at: now,
    updated_at: now,
  };
  await write((db) => {
    db.users.push(user);
  });
  return user;
}
export async function updateUserRole(
  userId: string,
  role: Database["users"][number]["role"],
  patch: Partial<Database["users"][number]> = {}
) {
  return write((db) => {
    const u = db.users.find((x) => x.id === userId);
    if (!u) return null;
    u.role = role;
    Object.assign(u, patch);
    u.updated_at = new Date().toISOString();
    return u;
  });
}
