import { createBrowserClient } from "@supabase/ssr";
import { isRealEnv } from "@/lib/env";

const SUPABASE_URL = process.env.NEXT_PUBLIC_SUPABASE_URL;
const SUPABASE_ANON_KEY = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;

export const isSupabaseConfigured =
  isRealEnv(SUPABASE_URL) && isRealEnv(SUPABASE_ANON_KEY);

/** Browser-side Supabase client. Real when configured, null otherwise. */
export function createBrowserSupabase() {
  if (!isSupabaseConfigured) return null;
  return createBrowserClient(SUPABASE_URL as string, SUPABASE_ANON_KEY as string);
}

// True when the given env value is present AND not a placeholder used by the
// sandbox/preview. The demo deploy ships with placeholder-but-truthy values
// like "https://placeholder.example.com"; those must NOT enable real backends.
export function isRealEnv(value: string | undefined): boolean {
  if (!value) return false;
  const v = value.trim();
  if (!v) return false;
  return !/placeholder|example\.com|change-me|x{5,}/i.test(v);
}

import Stripe from "stripe";
import { isRealEnv } from "@/lib/env";

const STRIPE_SECRET_KEY = process.env.STRIPE_SECRET_KEY;

export const isStripeConfigured = isRealEnv(STRIPE_SECRET_KEY);

export function stripeClient(): Stripe | null {
  if (!isStripeConfigured) return null;
  return new Stripe(STRIPE_SECRET_KEY as string, {
    apiVersion: "2024-12-18.acacia" as Stripe.LatestApiVersion,
  });
}

export async function createCheckoutSession(opts: {
  tierName: string;
  amountCents: number;
  userId: string;
  userEmail: string;
  successUrl: string;
  cancelUrl: string;
}): Promise<{ url: string; sessionId: string } | null> {
  const stripe = stripeClient();
  if (!stripe) return null;

  const session = await stripe.checkout.sessions.create({
    mode: "payment",
    customer_email: opts.userEmail,
    line_items: [
      {
        price_data: {
          currency: "usd",
          product_data: { name: `Goon Membership — ${opts.tierName}` },
          unit_amount: opts.amountCents,
        },
        quantity: 1,
      },
    ],
    client_reference_id: opts.userId,
    metadata: { tier: opts.tierName, user_id: opts.userId },
    success_url: opts.successUrl,
    cancel_url: opts.cancelUrl,
  });

  return { url: session.url!, sessionId: session.id };
}

export function verifyWebhookSignature(rawBody: string, signature: string): Stripe.Event | null {
  const secret = process.env.STRIPE_WEBHOOK_SECRET;
  const stripe = stripeClient();
  if (!stripe || !secret) return null;
  try {
    return stripe.webhooks.constructEvent(rawBody, signature, secret);
  } catch {
    return null;
  }
}

import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";
import { verifySession } from "./lib/auth";
import { SESSION_COOKIE } from "./lib/session";

const PROTECTED_PREFIXES = [
  "/dashboard",
  "/dashboard/directory",
  "/dashboard/events",
  "/dashboard/payments",
  "/admin",
];

export async function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl;

  const isProtected = PROTECTED_PREFIXES.some(
    (p) => pathname === p || pathname.startsWith(p + "/")
  );
  if (!isProtected) return NextResponse.next();

  const token = request.cookies.get(SESSION_COOKIE)?.value;
  const session = token ? await verifySession(token) : null;

  if (!session) {
    const url = request.nextUrl.clone();
    url.pathname = "/login";
    url.searchParams.set("redirect", pathname);
    return NextResponse.redirect(url);
  }

  if ((pathname === "/admin" || pathname.startsWith("/admin/")) && session.role !== "admin") {
    const url = request.nextUrl.clone();
    url.pathname = "/dashboard";
    return NextResponse.redirect(url);
  }

  return NextResponse.next();
}

