"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { Input } from "@/components/ui/Input";
import Button from "@/components/ui/Button";

export default function LoginPage() {
  const router = useRouter();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError("");
    setLoading(true);
    try {
      const params = new URLSearchParams(window.location.search);
      const redirect = params.get("redirect") ?? "/dashboard";
      const res = await fetch("/api/auth", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email, password, redirect }),
      });
      const data = await res.json();
      if (res.ok && data.ok) {
        router.push(data.redirect ?? "/dashboard");
        router.refresh();
      } else {
        setError(data.error ?? "Could not sign in.");
      }
    } catch {
      setError("Network error. Please try again.");
    } finally {
      setLoading(false);
    }
  }

  async function tryDemo() {
    setError("");
    setLoading(true);
    try {
      const res = await fetch("/api/auth/demo", { method: "POST" });
      const data = await res.json();
      if (res.ok && data.ok) {
        router.push(data.redirect ?? "/dashboard");
        router.refresh();
      } else {
        setError(data.error ?? "Could not start demo.");
      }
    } finally {
      setLoading(false);
    }
  }

  return (
    <main className="min-h-screen flex items-center justify-center px-6 bg-ink">
      <div className="w-full max-w-md">
        <div className="text-center mb-10">
          <Link href="/" className="font-archivo text-3xl text-ivory tracking-tight">
            GOON
          </Link>
          <p className="mt-2 font-satoshi text-xs tracking-[0.3em] uppercase text-brass">
            Member Login
          </p>
        </div>

        <div className="border border-brass/20 bg-charcoal-soft p-8">
          <form onSubmit={handleSubmit} className="space-y-5">
            <Input
              id="email"
              type="email"
              label="Email"
              required
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="you@domain.com"
            />
            <Input
              id="password"
              type="password"
              label="Password"
              required
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="••••••••"
            />
            {error && <p className="font-satoshi text-sm text-[#C97A7A]">{error}</p>}
            <Button type="submit" loading={loading} className="w-full">
              Sign In
            </Button>
          </form>

          <div className="mt-6 pt-6 border-t border-ivory/10 space-y-3">
            <button
              type="button"
              onClick={tryDemo}
              disabled={loading}
              className="w-full text-center font-satoshi text-xs tracking-[0.2em] uppercase text-brass border border-brass/40 py-3 hover:bg-brass hover:text-ink transition-colors"
            >
              Try the live demo →
            </button>
            <p className="font-satoshi text-xs text-ivory/40 text-center">
              Demo: demo@demo.app · demo123
            </p>
          </div>
        </div>

        <p className="mt-6 text-center font-satoshi text-sm text-ivory/60">
          Not a member?{" "}
          <Link href="/signup" className="text-brass hover:underline">
            Apply for membership
          </Link>
        </p>
      </div>
    </main>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { Input, Select } from "@/components/ui/Input";
import Button from "@/components/ui/Button";
import { REFERRAL_SOURCES } from "@/types";

export default function SignupPage() {
  const router = useRouter();
  const [form, setForm] = useState({
    name: "",
    email: "",
    password: "",
    phone: "",
    referral_source: "",
  });
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  function set<K extends keyof typeof form>(key: K, value: string) {
    setForm((f) => ({ ...f, [key]: value }));
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError("");
    setLoading(true);
    try {
      const res = await fetch("/api/auth/signup", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: form.name,
          email: form.email,
          password: form.password,
          phone: form.phone || null,
          referral_source: form.referral_source || null,
        }),
      });
      const data = await res.json();
      if (res.ok && data.ok) {
        router.push(data.redirect ?? "/dashboard");
        router.refresh();
      } else {
        setError(data.error ?? "Could not create account.");
      }
    } catch {
      setError("Network error. Please try again.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <main className="min-h-screen flex items-center justify-center px-6 py-16 bg-ink">
      <div className="w-full max-w-md">
        <div className="text-center mb-10">
          <Link href="/" className="font-archivo text-3xl text-ivory tracking-tight">
            GOON
          </Link>
          <p className="mt-2 font-satoshi text-xs tracking-[0.3em] uppercase text-brass">
            Apply for Membership
          </p>
        </div>

        <div className="border border-brass/20 bg-charcoal-soft p-8">
          <form onSubmit={handleSubmit} className="space-y-5">
            <Input
              id="name"
              label="Full Name"
              required
              value={form.name}
              onChange={(e) => set("name", e.target.value)}
              placeholder="Your name"
            />
            <Input
              id="email"
              type="email"
              label="Email"
              required
              value={form.email}
              onChange={(e) => set("email", e.target.value)}
              placeholder="you@domain.com"
            />
            <Input
              id="password"
              type="password"
              label="Password"
              required
              value={form.password}
              onChange={(e) => set("password", e.target.value)}
              placeholder="At least 6 characters"
            />
            <Input
              id="phone"
              type="tel"
              label="Phone (optional)"
              value={form.phone}
              onChange={(e) => set("phone", e.target.value)}
              placeholder="+1 (310) 555-0000"
            />
            <Select
              id="referral"
              label="How did you hear about us?"
              placeholder="Select a source"
              value={form.referral_source}
              onChange={(e) => set("referral_source", e.target.value)}
              options={REFERRAL_SOURCES.map((s) => ({ value: s, label: s }))}
            />
            {error && <p className="font-satoshi text-sm text-[#C97A7A]">{error}</p>}
            <Button type="submit" loading={loading} className="w-full">
              Apply for Membership
            </Button>
          </form>
          <p className="mt-6 font-satoshi text-xs text-ivory/45 leading-relaxed">
            Creating an account submits a membership application for review.
            Dues are only collected after approval.
          </p>
        </div>

        <p className="mt-6 text-center font-satoshi text-sm text-ivory/60">
          Already a member?{" "}
          <Link href="/login" className="text-brass hover:underline">
            Sign in
          </Link>
        </p>
      </div>
    </main>
  );
}

import { NextResponse } from "next/server";
import {
  authenticate,
  AuthError,
  clearSessionCookie,
  setSessionCookie,
  signSession,
  getSession,
} from "@/lib/auth";

/** GET /api/auth — current session probe (used by client pages). */
export async function GET() {
  const session = await getSession();
  return NextResponse.json({ session });
}

/** POST /api/auth — email+password login. */
export async function POST(request: Request) {
  let body: { email?: string; password?: string; redirect?: string };
  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: "Invalid request." }, { status: 400 });
  }
  const email = body.email?.trim();
  const password = body.password;
  if (!email || !password) {
    return NextResponse.json({ error: "Email and password are required." }, { status: 400 });
  }
  try {
    const sessionUser = await authenticate(email, password);
    const token = await signSession(sessionUser);
    const res = NextResponse.json({ ok: true, redirect: body.redirect || "/dashboard" });
    setSessionCookie(res, token);
    return res;
  } catch (err) {
    if (err instanceof AuthError) {
      return NextResponse.json({ error: err.message }, { status: 401 });
    }
    return NextResponse.json({ error: "Something went wrong. Please try again." }, { status: 500 });
  }
}

/** DELETE /api/auth — logout. */
export async function DELETE() {
  const res = NextResponse.json({ ok: true, redirect: "/" });
  clearSessionCookie(res);
  return res;
}

import { NextResponse } from "next/server";
import {
  AuthError,
  registerUser,
  setSessionCookie,
  signSession,
} from "@/lib/auth";
import { createApplication } from "@/lib/db";

export async function POST(request: Request) {
  try {
    const body = await request.json().catch(() => ({}));
    const email = String(body.email ?? "").trim();
    const password = String(body.password ?? "");
    const name = String(body.name ?? "").trim();
    const phone = body.phone ? String(body.phone).trim() : null;
    const referral_source = body.referral_source ? String(body.referral_source) : null;

    if (!name) return NextResponse.json({ error: "Full name is required." }, { status: 400 });
    if (!email) return NextResponse.json({ error: "Email is required." }, { status: 400 });
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) return NextResponse.json({ error: "Please enter a valid email." }, { status: 400 });
    if (password.length < 6) return NextResponse.json({ error: "Password must be at least 6 characters." }, { status: 400 });

    const session = await registerUser({ email, password, name, phone, referral_source });
    await createApplication({
      user_id: session.userId,
      full_name: name,
      email,
      phone,
      referral_source,
    });

    const token = await signSession(session);
    const res = NextResponse.json({ ok: true, redirect: "/dashboard" });
    return setSessionCookie(res, token);
  } catch (e) {
    if (e instanceof AuthError) {
      return NextResponse.json({ error: e.message }, { status: 400 });
    }
    return NextResponse.json({ error: "Something went wrong. Please try again." }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { ensureDemoAccount, setSessionCookie, signSession } from "@/lib/auth";

/** One-click demo login. Seeds the demo account if missing, then starts a session. */
export async function POST() {
  const sessionUser = await ensureDemoAccount();
  const token = await signSession(sessionUser);
  const res = NextResponse.json({ ok: true, redirect: "/dashboard" });
  setSessionCookie(res, token);
  return res;
}

