export async function POST(request: Request) {
  const session = await getSession();
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  if (session.role !== "admin") {
    return NextResponse.json({ error: "Only administrators may create events." }, { status: 403 });
  }
  const body = await request.json().catch(() => ({}));
  const title = String(body.title ?? "").trim();
  const description = String(body.description ?? "").trim();
  const date = String(body.date ?? "");
  const time = String(body.time ?? "19:00");
  const location = String(body.location ?? "").trim();
  const capacity = Number(body.capacity ?? 0);

  if (!title || !date || !location || !capacity) {
    return NextResponse.json({ error: "Title, date, location, and capacity are required." }, { status: 400 });
  }
  const parsed = new Date(date);
  if (Number.isNaN(parsed.getTime())) {
    return NextResponse.json({ error: "Invalid date." }, { status: 400 });
  }

  const { createEvent } = await import("@/lib/db");
  const ev = await createEvent({
    title,
    description,
    date: parsed.toISOString(),
    time,
    end_time: body.end_time ? String(body.end_time) : null,
    location,
    capacity,
    image_url: null,
    is_private: true,
    created_by: session.userId,
  });
  return NextResponse.json({ ok: true, event: ev }, { status: 201 });
}

import { NextResponse } from "next/server";
import { getSession } from "@/lib/auth";
import { getEvent, setRsvp } from "@/lib/db";

export async function POST(request: Request) {
  const session = await getSession();
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  if (session.role !== "member" && session.role !== "admin") {
    return NextResponse.json({ error: "Active membership required to RSVP." }, { status: 403 });
  }

  const body = await request.json().catch(() => ({}));
  const eventId = String(body.event_id ?? "");
  const action = body.action === "cancel" ? "cancel" : "rsvp";

  const event = await getEvent(eventId);
  if (!event) return NextResponse.json({ error: "Event not found." }, { status: 404 });
  if (new Date(event.date).getTime() < Date.now()) {
    return NextResponse.json({ error: "This event has already passed." }, { status: 400 });
  }

  const result = await setRsvp(eventId, session.userId, action);
  if (!result.ok && action === "rsvp") {
    return NextResponse.json({ error: "This event is at capacity." }, { status: 409 });
  }
  return NextResponse.json(result);
}

import { NextResponse } from "next/server";
import { requireUser } from "@/lib/auth";
import { listMembers } from "@/lib/db";

/** GET /api/directory — browse verified members (discretion-first: first name + last initial). */
export async function GET(request: Request) {
  const session = await requireUser().catch(() => null);
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  if (session.role !== "member" && session.role !== "admin") {
    return NextResponse.json({ error: "Active membership required." }, { status: 403 });
  }

  const { searchParams } = new URL(request.url);
  const q = searchParams.get("q")?.trim().toLowerCase() ?? "";

  const members = await listMembers();
  const filtered = q
    ? members.filter((m) => m.name.toLowerCase().includes(q) || m.email.toLowerCase().includes(q))
    : members;

  return NextResponse.json({
    members: filtered.map((m) => {
      const [first, ...rest] = m.name.split(" ");
      const lastInitial = rest.length ? rest[rest.length - 1].charAt(0).toUpperCase() : "";
      return {
        id: m.id,
        first_name: first,
        last_initial: lastInitial,
        membership_tier: m.membership_tier,
        is_self: m.id === session.userId,
      };
    }),
  });
}

