import { NextResponse } from "next/server";
import { getSession } from "@/lib/auth";
import {
  createPayment,
  findUserById,
  getTierByName,
  updateUserRole,
} from "@/lib/db";
import { createCheckoutSession, isStripeConfigured } from "@/lib/stripe";

const VALID_TIERS = ["Basic", "Premium", "VIP"];

export async function POST(request: Request) {
  const session = await getSession();
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  if (session.role !== "pending_payment" && session.role !== "member") {
    return NextResponse.json({ error: "Dues are not yet requested for this account." }, { status: 400 });
  }

  const body = await request.json().catch(() => ({}));
  const tierName = String(body.tier ?? "Basic");
  if (!VALID_TIERS.includes(tierName)) {
    return NextResponse.json({ error: "Unknown membership tier." }, { status: 400 });
  }

  const tier = await getTierByName(tierName);
  if (!tier) return NextResponse.json({ error: "Unknown membership tier." }, { status: 400 });

  const user = await findUserById(session.userId);
  if (!user) return NextResponse.json({ error: "Account not found." }, { status: 404 });

  const appUrl = process.env.NEXT_PUBLIC_APP_URL ?? "http://localhost:3000";

  if (isStripeConfigured) {
    const created = await createCheckoutSession({
      tierName: tier.name,
      amountCents: tier.price_cents,
      userId: session.userId,
      userEmail: user.email,
      successUrl: `${appUrl}/dashboard/payments?success=1`,
      cancelUrl: `${appUrl}/dashboard/payments?canceled=1`,
    });
    if (created) {
      await createPayment({
        user_id: session.userId,
        stripe_session_id: created.sessionId,
        stripe_payment_intent: null,
        amount_cents: tier.price_cents,
        currency: "usd",
        status: "pending",
        membership_tier: tier.name,
        paid_at: null,
        expires_at: null,
      });
      return NextResponse.json({ ok: true, url: created.url });
    }
  }

  // Demo / no-Stripe path: simulate a successful payment in-app.
  const expiresAt = new Date(Date.now() + 365 * 86400000).toISOString();
  await createPayment({
    user_id: session.userId,
    stripe_session_id: null,
    stripe_payment_intent: null,
    amount_cents: tier.price_cents,
    currency: "usd",
    status: "completed",
    membership_tier: tier.name,
    paid_at: new Date().toISOString(),
    expires_at: expiresAt,
  });
  await updateUserRole(session.userId, "member", {
    membership_tier: tier.name,
    membership_expires_at: expiresAt,
  });

  return NextResponse.json({ ok: true, redirect: "/dashboard/payments?success=1" });
}

import { NextResponse } from "next/server";
import { verifyWebhookSignature } from "@/lib/stripe";
import {
  createPayment,
  findUserById,
  listAllPayments,
  updateUserRole,
} from "@/lib/db";

export async function POST(request: Request) {
  const rawBody = await request.text();
  const signature = request.headers.get("stripe-signature") ?? "";

  const event = verifyWebhookSignature(rawBody, signature);
  if (!event) {
    return NextResponse.json({ error: "Invalid signature" }, { status: 400 });
  }

  if (event.type === "checkout.session.completed") {
    const session = event.data.object as {
      id: string;
      client_reference_id?: string;
      metadata?: { tier?: string; user_id?: string };
      payment_intent?: string | null;
      amount_total?: number;
    };

    const userId = session.metadata?.user_id ?? session.client_reference_id ?? "";
    const tier = session.metadata?.tier ?? "Basic";
    const user = await findUserById(userId);
    if (user) {
      const existing = (await listAllPayments()).find((p) => p.stripe_session_id === session.id);
      if (!existing) {
        const expiresAt = new Date(Date.now() + 365 * 86400000).toISOString();
        await createPayment({
          user_id: userId,
          stripe_session_id: session.id,
          stripe_payment_intent: typeof session.payment_intent === "string" ? session.payment_intent : null,
          amount_cents: session.amount_total ?? 0,
          currency: "usd",
          status: "completed",
          membership_tier: tier,
          paid_at: new Date().toISOString(),
          expires_at: expiresAt,
        });
        await updateUserRole(userId, "member", {
          membership_tier: tier,
          membership_expires_at: expiresAt,
        });
      }
    }
  }

  return NextResponse.json({ received: true });
}

