import { NextResponse } from "next/server";
import {
  ensureDemoAccount,
  ensureDemoAdmin,
  setSessionCookie,
  signSession,
} from "@/lib/auth";

export async function POST(request: Request) {
  try {
    const contentType = request.headers.get("content-type") ?? "";
    const isJson = contentType.includes("application/json");

    const body = isJson
      ? await request.json().catch(() => ({}))
      : Object.fromEntries(new URLSearchParams(await request.text()));
    const asAdmin = body.role === "admin";

    const session = asAdmin ? await ensureDemoAdmin() : await ensureDemoAccount();
    const token = await signSession(session);
    const target = asAdmin ? "/admin" : "/dashboard";

    if (isJson) {
      const res = NextResponse.json({ ok: true, redirect: target });
      return setSessionCookie(res, token);
    }

    const res = NextResponse.redirect(new URL(target, request.url), 303);
    res.cookies.set("goon_session", token, {
      httpOnly: true,
      sameSite: "lax",
      secure: process.env.NODE_ENV === "production",
      path: "/",
      maxAge: 60 * 60 * 24 * 30,
    });
    return res;
  } catch {
    return NextResponse.json(
      { error: "Could not start the demo session." },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { requireAdmin } from "@/lib/auth";
import {
  listAllPayments,
  listAllUsers,
  listApplications,
  listEvents,
  countAttendees,
} from "@/lib/db";

export async function GET() {
  const session = await requireAdmin().catch(() => null);
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const [users, payments, events, applications] = await Promise.all([
    listAllUsers(),
    listAllPayments(),
    listEvents(),
    listApplications("pending"),
  ]);

  const revenue = payments.filter((p) => p.status === "completed").reduce((s, p) => s + p.amount_cents, 0);
  const members = users.filter((u) => u.role === "member").length;
  const pending = applications.length;
  const upcoming = events.filter((e) => new Date(e.date).getTime() >= Date.now()).length;

  return NextResponse.json({
    stats: { members, pending, revenue, upcoming },
    members: users,
    payments,
    events: await Promise.all(events.map(async (e) => ({ ...e, attendees: await countAttendees(e.id) }))),
    applications,
  });
}

