        <path d="M16 5.5a3.5 3.5 0 010 6M22 21c0-3-2-5-5-5.5" />
      </svg>
    );
  return (
    <svg {...c}>
      <path d="M4 21h16M6 21V4a1 1 0 011-1h10a1 1 0 011 1v17" />
      <circle cx="14" cy="12" r="0.5" fill="currentColor" />
    </svg>
  );
}

