"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { Input } from "@/components/ui/Input";
import { useToast } from "@/components/ui/Toast";

interface ProfileData {
  id: string;
  name: string;
  email: string;
  phone: string | null;
  referral_source: string | null;
  role: string;
  membership_tier: string | null;
  membership_expires_at: string | null;
  created_at: string;
}

export default function ProfilePage() {
  const router = useRouter();
  const { toast } = useToast();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");
  const [profile, setProfile] = useState<ProfileData | null>(null);
  const [name, setName] = useState("");
  const [phone, setPhone] = useState("");

  useEffect(() => {
    fetch("/api/profile")
      .then((r) => r.json())
      .then((data) => {
        if (data.user) {
          setProfile(data.user);
          setName(data.user.name);
          setPhone(data.user.phone ?? "");
        } else {
          router.replace("/login?redirect=/dashboard/profile");
        }
        setLoading(false);
      })
      .catch(() => {
        setError("Unable to load your profile.");
        setLoading(false);
      });
  }, [router]);

  async function save(e: React.FormEvent) {
    e.preventDefault();
    setSaving(true);
    setError("");
    try {
      const res = await fetch("/api/profile", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name, phone }),
      });
      const data = await res.json();
      if (res.ok) {
        toast("Profile updated.", "success");
      } else {
        setError(data.error ?? "Could not save.");
      }
    } catch {
      setError("Network error.");
    } finally {
      setSaving(false);
    }
  }

  if (loading) {
    return (
      <main className="max-w-2xl mx-auto px-6 py-12">
        <p className="font-satoshi text-sm text-ivory/50">Loading…</p>
      </main>
    );
  }
  if (!profile) return null;

  return (
    <main className="max-w-2xl mx-auto px-6 py-12">
      <p className="font-satoshi text-xs tracking-[0.3em] uppercase text-brass mb-2">Account</p>
      <h1 className="font-playfair text-4xl text-ivory mb-8">Profile</h1>

      <div className="border border-ivory/10 bg-charcoal-soft p-8 mb-8">
        <form onSubmit={save} className="space-y-5">
          <Input id="name" label="Full Name" required value={name} onChange={(e) => setName(e.target.value)} />
          <Input
            id="email"
            label="Email"
            value={profile.email}
            disabled
            hint="Email cannot be changed here. Contact the steward."
          />
          <Input
            id="phone"
            label="Phone"
            type="tel"
            value={phone}
            onChange={(e) => setPhone(e.target.value)}
            placeholder="+1 (310) 555-0000"
          />
          {error && <p className="font-satoshi text-sm text-[#C97A7A]">{error}</p>}
          <button
            type="submit"
            disabled={saving}
            className="bg-brass text-ink px-8 py-3 font-satoshi text-xs tracking-[0.2em] uppercase hover:bg-brass-bright transition-colors disabled:opacity-50"
          >
            {saving ? "Saving…" : "Save Changes"}
          </button>
        </form>
      </div>

      <div className="border border-ivory/10 bg-charcoal-soft p-6 space-y-3 font-satoshi text-sm">
        <Row label="Status" value={profile.role} />
        <Row label="Membership tier" value={profile.membership_tier ?? "—"} />
        <Row label="Referral source" value={profile.referral_source ?? "—"} />
        <Row label="Joined" value={new Date(profile.created_at).toLocaleDateString()} />
      </div>
    </main>
  );
}

function Row({ label, value }: { label: string; value: string }) {
  return (
    <div className="flex justify-between">
      <span className="text-ivory/50">{label}</span>
      <span className="text-ivory/85">{value}</span>
    </div>
  );
}

"use client";

import { createContext, useCallback, useContext, useEffect, useState, ReactNode } from "react";

type ToastKind = "success" | "error" | "info";
interface Toast {
  id: number;
  kind: ToastKind;
  message: string;
}

const ToastContext = createContext<{ toast: (message: string, kind?: ToastKind) => void } | null>(null);

export function useToast() {
  const ctx = useContext(ToastContext);
  if (!ctx) return { toast: () => undefined };
  return ctx;
}

const accent: Record<ToastKind, string> = {
  success: "border-brass text-brass",
  error: "border-[#8B3A3A] text-[#C97A7A]",
  info: "border-ivory/40 text-ivory",
};

export function ToastProvider({ children }: { children: ReactNode }) {
  const [toasts, setToasts] = useState<Toast[]>([]);
  const toast = useCallback((message: string, kind: ToastKind = "info") => {
    setToasts((t) => [...t, { id: Date.now() + Math.random(), kind, message }]);
  }, []);

  useEffect(() => {
    if (toasts.length === 0) return;
    const timers = toasts.map((t) =>
      setTimeout(() => setToasts((cur) => cur.filter((c) => c.id !== t.id)), 3500)
    );
    return () => timers.forEach(clearTimeout);
  }, [toasts]);

  return (
    <ToastContext.Provider value={{ toast }}>
      {children}
      <div className="fixed bottom-6 right-6 z-50 flex flex-col gap-2 max-w-sm">
        {toasts.map((t) => (
          <div
            key={t.id}
            className={`bg-charcoal-soft border ${accent[t.kind]} px-5 py-3 font-satoshi text-sm`}
            role="status"
          >
            {t.message}
          </div>
        ))}
      </div>
    </ToastContext.Provider>
  );
}

