"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import Navbar from "@/components/layout/Navbar";
import Modal from "@/components/ui/Modal";
import { Select } from "@/components/ui/Input";
import { TIME_SLOTS } from "@/types";
import { formatTime } from "@/lib/utils";

interface Parlor {
  id: string;
  name: string;
  description: string;
  capacity: number;
  price_cents: number | null;
}

export default function BookingsPage() {
  const [parlors, setParlors] = useState<Parlor[]>([]);
  const [open, setOpen] = useState<Parlor | null>(null);
  const [date, setDate] = useState("");
  const [startTime, setStartTime] = useState("");
  const [duration, setDuration] = useState("1");
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  useEffect(() => {
    fetch("/api/parlors")
      .then((r) => r.json())
      .then((d) => setParlors(d.parlors ?? []));
  }, []);

  function openBooking(p: Parlor) {
    setOpen(p);
    setError("");
    setSuccess("");
    setStartTime("");
    setDuration("1");
    setDate(new Date().toISOString().slice(0, 10));
  }

  async function confirm() {
    if (!open) return;
    setBusy(true);
    setError("");
    setSuccess("");
    const res = await fetch("/api/parlors", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        parlor_id: open.id,
        date,
        start_time: startTime,
        duration: Number(duration),
      }),
    });
    const data = await res.json();
    if (res.ok && data.ok) {
      setSuccess(data.message ?? "Parlor booked.");
      setOpen(null);
    } else {
      setError(data.error ?? "Could not book.");
    }
    setBusy(false);
  }

  return (
    <div className="min-h-screen bg-ink">
      <Navbar name="Member" />
      <main className="max-w-5xl mx-auto px-6 py-12">
        <div className="mb-8">
          <p className="font-satoshi text-xs tracking-[0.3em] uppercase text-brass mb-2">
            The House
          </p>
          <h1 className="font-playfair text-4xl text-ivory">Parlors</h1>
        </div>

        {success && (
          <div className="mb-6 border border-brass/30 bg-brass/10 px-5 py-3 font-satoshi text-sm text-brass">
            {success}
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {parlors.map((p) => (
            <div
              key={p.id}
              className="border border-ivory/10 bg-charcoal-soft p-6 hover:border-brass/40 transition-colors"
            >
              <h3 className="font-playfair text-2xl text-ivory">{p.name}</h3>
              <p className="font-satoshi text-sm text-ivory/60 mt-2 leading-relaxed">
                {p.description}
              </p>
              <div className="mt-4 flex items-center gap-4 font-satoshi text-xs tracking-[0.15em] uppercase text-ivory/50">
                <span>Up to {p.capacity} guests</span>
                <span>·</span>
                <span>Included in membership</span>
              </div>
              <button
                onClick={() => openBooking(p)}
                className="mt-5 border border-brass text-brass px-6 py-2.5 font-satoshi text-xs tracking-[0.2em] uppercase hover:bg-brass hover:text-ink transition-colors"
              >
                Book Now
              </button>
            </div>
          ))}
        </div>

        <Modal
          open={!!open}
          onClose={() => setOpen(null)}
          title={open ? `Book ${open.name}` : ""}
          footer={
            <>
              <button
                onClick={() => setOpen(null)}
                className="font-satoshi text-xs tracking-[0.2em] uppercase text-ivory/60 hover:text-brass"
              >
                Cancel
              </button>
              <button
                onClick={confirm}
                disabled={busy || !startTime}
                className="bg-brass text-ink px-6 py-2.5 font-satoshi text-xs tracking-[0.2em] uppercase hover:bg-brass-bright transition-colors disabled:opacity-50"
              >
                {busy ? "Booking…" : "Confirm Booking"}
              </button>
            </>
          }
        >
          <div className="space-y-4">
            <div>
              <label className="block font-satoshi text-xs tracking-[0.2em] uppercase text-ivory/60 mb-2">
                Date
              </label>
              <input
                type="date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="w-full bg-charcoal border border-ivory/15 px-4 py-3 text-ivory font-satoshi focus:border-brass"
              />
            </div>
            <Select
              label="Start time"
              placeholder="Select a time"
              value={startTime}
              onChange={(e) => setStartTime(e.target.value)}
              options={TIME_SLOTS.map((t) => ({ value: t, label: formatTime(t) }))}
            />
            <Select
              label="Duration"
              value={duration}
              onChange={(e) => setDuration(e.target.value)}
              options={[
                { value: "1", label: "1 hour" },
                { value: "2", label: "2 hours" },
                { value: "3", label: "3 hours" },
              ]}
            />
            {error && <p className="font-satoshi text-sm text-[#C97A7A]">{error}</p>}
          </div>
        </Modal>

        <p className="mt-10 font-satoshi text-xs text-ivory/40">
          <Link href="/dashboard" className="text-brass hover:underline">
            ← Back to dashboard
          </Link>
        </p>
      </main>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import Badge from "@/components/ui/Badge";
import { initials } from "@/lib/utils";

interface Member {
  id: string;
  first_name: string;
  last_initial: string;
  membership_tier: string | null;
  is_self: boolean;
}

function tierTone(tier: string | null) {
  if (tier === "VIP") return "brass" as const;
  if (tier === "Premium") return "amber" as const;
  return "muted" as const;
}

export default function DirectoryPage() {
  const [members, setMembers] = useState<Member[]>([]);
  const [q, setQ] = useState("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let active = true;
    const t = setTimeout(async () => {
      const res = await fetch(`/api/directory?q=${encodeURIComponent(q)}`);
      const data = await res.json();
      if (active && res.ok) setMembers(data.members ?? []);
      setLoading(false);
    }, 250);
    return () => {
      active = false;
      clearTimeout(t);
    };
  }, [q]);

  return (
    <main className="max-w-6xl mx-auto px-6 py-12">
      <div className="flex flex-col sm:flex-row sm:items-end sm:justify-between gap-4 mb-8">
        <div>
          <p className="font-satoshi text-xs tracking-[0.3em] uppercase text-brass mb-2">The Directory</p>
          <h1 className="font-playfair text-4xl text-ivory">Members</h1>
        </div>
        <div className="relative w-full sm:w-80">
          <input
            value={q}
            onChange={(e) => setQ(e.target.value)}
            placeholder="Search by name"
            className="w-full bg-charcoal-soft border border-ivory/15 px-4 py-3 pl-10 text-ivory font-satoshi text-sm placeholder:text-ivory/35 focus:border-brass transition-colors"
          />
          <svg className="absolute left-3 top-3.5 w-4 h-4 text-ivory/40" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={1.5}>
            <circle cx="11" cy="11" r="7" />
            <path d="M21 21l-4-4" strokeLinecap="round" />
          </svg>
        </div>
      </div>

      <p className="font-satoshi text-xs text-ivory/40 mb-6">
        Discretion first — only first names and last initials are shown.
      </p>

      {loading ? (
        <p className="font-satoshi text-sm text-ivory/50">Loading…</p>
      ) : members.length === 0 ? (
        <p className="font-satoshi text-sm text-ivory/50">No members found.</p>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {members.map((m) => (
            <div
              key={m.id}
              className="border border-ivory/10 bg-charcoal-soft p-6 hover:border-brass/40 transition-colors"
            >
              <div className="flex items-center gap-4">
                <span className="w-14 h-14 rounded-full bg-brass/15 border border-brass/40 text-brass flex items-center justify-center font-satoshi font-bold">
                  {initials(`${m.first_name} ${m.last_initial}`)}
                </span>
                <div className="min-w-0">
                  <p className="font-playfair text-lg text-ivory truncate">
                    {m.first_name} {m.last_initial}.
                    {m.is_self && (
                      <span className="ml-2 font-satoshi text-[10px] tracking-[0.2em] uppercase text-brass">You</span>
                    )}
                  </p>
                  {m.membership_tier && (
                    <div className="mt-2">
                      <Badge tone={tierTone(m.membership_tier)}>{m.membership_tier}</Badge>
                    </div>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </main>
  );
}

"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import Badge from "@/components/ui/Badge";
import { formatDate, formatTime, isPast } from "@/lib/utils";

interface EventItem {
  id: string;
  title: string;
  description: string;
  date: string;
  time: string;
  end_time: string | null;
  location: string;
  capacity: number;
  attendee_count: number;
  attending: boolean;
  past: boolean;
}

export default function EventsPage() {
  const [events, setEvents] = useState<EventItem[]>([]);
  const [busy, setBusy] = useState<string | null>(null);
  const [error, setError] = useState("");

  async function load() {
    const res = await fetch("/api/events");
    const data = await res.json();
    if (res.ok) setEvents(data.events ?? []);
  }

  useEffect(() => {
    load();
  }, []);

  async function rsvp(ev: EventItem) {
    setBusy(ev.id);
    setError("");
    const res = await fetch("/api/events/rsvp", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ event_id: ev.id, action: "rsvp" }),
    });
    const data = await res.json();
    if (res.ok) {
      setEvents((cur) => cur.map((e) => (e.id === ev.id ? { ...e, attending: true, attendee_count: data.count } : e)));
    } else {
      setError(data.error ?? "Could not RSVP.");
    }
    setBusy(null);
  }

  async function cancel(ev: EventItem) {
    setBusy(ev.id);
    setError("");
    const res = await fetch("/api/events/rsvp", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ event_id: ev.id, action: "cancel" }),
    });
    const data = await res.json();
    if (res.ok) {
      setEvents((cur) => cur.map((e) => (e.id === ev.id ? { ...e, attending: false, attendee_count: data.count } : e)));
    } else {
      setError(data.error ?? "Could not cancel.");
    }
    setBusy(null);
  }

  return (
    <main className="max-w-4xl mx-auto px-6 py-12">
      <div className="mb-8">
        <p className="font-satoshi text-xs tracking-[0.3em] uppercase text-brass mb-2">The Calendar</p>
        <h1 className="font-playfair text-4xl text-ivory">Events</h1>
      </div>

      {error && <p className="mb-4 font-satoshi text-sm text-[#C97A7A]">{error}</p>}

      <div className="space-y-4">
        {events.length === 0 && (
          <p className="font-satoshi text-sm text-ivory/50">No events scheduled yet.</p>
        )}
        {events.map((ev) => {
          const past = ev.past || isPast(ev.date);
          return (
            <div
              key={ev.id}
              className={`border border-ivory/10 bg-charcoal-soft p-6 flex flex-col md:flex-row md:items-center gap-6 ${past ? "opacity-50" : ""}`}
            >
              <div className="flex-1 min-w-0">
                <Link href={`/dashboard/events/${ev.id}`} className="font-playfair text-xl text-ivory hover:text-brass transition-colors">
                  {ev.title}
                </Link>
                <p className="font-satoshi text-xs text-ivory/50 mt-1">
                  {formatTime(ev.time)}
                  {ev.end_time ? ` – ${formatTime(ev.end_time)}` : ""} · {ev.location}
                </p>
                <p className="font-satoshi text-xs text-ivory/40 mt-2">
                  {formatDate(ev.date)} · {ev.attendee_count}/{ev.capacity} attending
                </p>
              </div>
              <div className="shrink-0">
                {past ? (
                  <Badge tone="muted">Past</Badge>
                ) : ev.attending ? (
                  <button
                    onClick={() => cancel(ev)}
                    disabled={busy === ev.id}
                    className="bg-brass text-ink px-6 py-2.5 font-satoshi text-xs tracking-[0.2em] uppercase hover:bg-brass-bright transition-colors disabled:opacity-50"
                  >
                    Attending
                  </button>
                ) : (
                  <button
                    onClick={() => rsvp(ev)}
                    disabled={busy === ev.id}
                    className="border border-brass text-brass px-6 py-2.5 font-satoshi text-xs tracking-[0.2em] uppercase hover:bg-brass hover:text-ink transition-colors disabled:opacity-50"
                  >
                    RSVP
                  </button>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </main>
  );
}

import Link from "next/link";
import Badge from "@/components/ui/Badge";
import { findUserById, getSession } from "@/lib/auth";
import {
  countAttendees,
  getEvent,
  isAttending,
  listAttendees,
} from "@/lib/db";
import { formatDate, formatTime, initials, isPast } from "@/lib/utils";
import EventRsvpButton from "@/components/EventRsvpButton";
import { redirect } from "next/navigation";

export default async function EventDetailPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const session = await getSession();
  if (!session) redirect("/login?redirect=/dashboard/events");
  const user = await findUserById(session.userId);
  if (!user) redirect("/login");
  if (user.role === "pending_payment") redirect("/payment");

  const { id } = await params;
  const event = await getEvent(id);
  if (!event) redirect("/dashboard/events");

  const attendees = await listAttendees(event.id);
  const count = await countAttendees(event.id);
  const attending = await isAttending(event.id, session.userId);
  const past = isPast(event.date);

  return (
    <main className="max-w-3xl mx-auto px-6 py-12">
      <Link href="/dashboard/events" className="font-satoshi text-xs tracking-[0.2em] uppercase text-brass hover:underline">
        ← All events
      </Link>

      <div className="mt-6">
        <div className="flex items-center gap-3 mb-3">
          <Badge tone={past ? "muted" : "brass"}>{formatDate(event.date)}</Badge>
          <span className="font-satoshi text-xs text-ivory/50">
            {formatTime(event.time)}
            {event.end_time ? ` – ${formatTime(event.end_time)}` : ""}
          </span>
        </div>
        <h1 className="font-playfair text-4xl text-ivory mb-3">{event.title}</h1>
        <p className="font-satoshi text-sm text-ivory/60 mb-6">
          {event.location} · Capacity {event.capacity}
        </p>
        <p className="font-satoshi text-base text-ivory/80 leading-relaxed mb-8">{event.description}</p>

        <div className="border-t border-ivory/10 pt-6">
          <EventRsvpButton
            eventId={event.id}
            initialAttending={attending}
            initialCount={count}
            capacity={event.capacity}
            past={past}
          />
        </div>

        {attendees.length > 0 && (
          <div className="mt-10">
            <h2 className="font-playfair text-xl text-ivory mb-4">Who&rsquo;s attending</h2>
            <div className="flex flex-wrap gap-3">
              {attendees.map((a) => (
                <span
                  key={a.id}
                  className="inline-flex items-center gap-2 border border-ivory/10 bg-charcoal-soft px-3 py-2"
                >
                  <span className="w-7 h-7 rounded-full bg-brass/15 border border-brass/40 text-brass flex items-center justify-center font-satoshi text-[10px] font-bold">
                    {initials(a.name)}
                  </span>
                  <span className="font-satoshi text-sm text-ivory/80">{a.name}</span>
                </span>
              ))}
            </div>
          </div>
        )}
      </div>
    </main>
  );
}

"use client";

import { useState } from "react";

export default function EventRsvpButton({
  eventId,
  initialAttending,
  initialCount,
  capacity,
  past,
}: {
  eventId: string;
  initialAttending: boolean;
  initialCount: number;
  capacity: number;
  past: boolean;
}) {
  const [attending, setAttending] = useState(initialAttending);
  const [count, setCount] = useState(initialCount);
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState("");

  async function call(action: "rsvp" | "cancel") {
    setBusy(true);
    setError("");
    const res = await fetch("/api/events/rsvp", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ event_id: eventId, action }),
    });
    const data = await res.json();
    if (res.ok) {
      setAttending(action === "rsvp");
      setCount(data.count);
    } else {
      setError(data.error ?? "Could not update RSVP.");
    }
    setBusy(false);
  }

  if (past) {
    return <span className="font-satoshi text-xs text-ivory/40">This event has passed.</span>;
  }

  return (
    <div className="flex items-center gap-4">
      {attending ? (
        <button
          onClick={() => call("cancel")}
          disabled={busy}
          className="bg-brass text-ink px-8 py-3 font-satoshi text-xs tracking-[0.2em] uppercase hover:bg-brass-bright transition-colors disabled:opacity-50"
        >
          Attending
        </button>
      ) : (
        <button
          onClick={() => call("rsvp")}
          disabled={busy}
          className="border border-brass text-brass px-8 py-3 font-satoshi text-xs tracking-[0.2em] uppercase hover:bg-brass hover:text-ink transition-colors disabled:opacity-50"
        >
          RSVP
        </button>
      )}
      <span className="font-satoshi text-sm text-ivory/60">
        {count}/{capacity} attending
      </span>
      {error && <span className="font-satoshi text-sm text-[#C97A7A]">{error}</span>}
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Select } from "@/components/ui/Input";

interface Tier {
  id: string;
  name: string;
  price_cents: number;
  description: string;
  benefits: string[];
}

export default function PaymentClient({
  tiers,
  defaultTier,
  canceled,
  stripeEnabled,
}: {
  tiers: Tier[];
  defaultTier: string;
  canceled: boolean;
  stripeEnabled: boolean;
}) {
  const router = useRouter();
  const [tier, setTier] = useState(defaultTier);
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState(canceled ? "Payment was canceled." : "");

  const selected = tiers.find((t) => t.name === tier) ?? tiers[0];

  async function pay() {
    setBusy(true);
    setError("");
    try {
      const res = await fetch("/api/payments/checkout", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ tier: selected.name }),
      });
      const data = await res.json();
      if (res.ok && data.ok) {
        if (data.url) {
          window.location.href = data.url;
        } else {
          router.push(data.redirect ?? "/dashboard?payment=success");
          router.refresh();
        }
      } else {
        setError(data.error ?? "Payment failed.");
      }
    } catch {
      setError("Network error. Please try again.");
    } finally {
      setBusy(false);
    }
  }

  return (
    <div className="border border-brass/20 bg-charcoal-soft p-8">
      <div className="text-center mb-8">
        <p className="font-satoshi text-xs tracking-[0.3em] uppercase text-brass mb-3">
          Complete Your Membership
        </p>
        <h1 className="font-playfair text-3xl text-ivory">Pay Dues</h1>
      </div>

      {tiers.length > 1 && (
        <div className="mb-6">
          <Select
            label="Membership Tier"
            value={tier}
            onChange={(e) => setTier(e.target.value)}
            options={tiers.map((t) => ({ value: t.name, label: t.name }))}
          />
        </div>
      )}

      {selected && (
        <div className="border border-ivory/10 bg-ink/40 p-6 mb-6">
          <div className="flex items-baseline justify-between mb-3">
            <h2 className="font-playfair text-xl text-ivory">{selected.name}</h2>
            <span className="font-archivo text-2xl text-brass">
              ${(selected.price_cents / 100).toLocaleString()}
              <span className="font-satoshi text-sm text-ivory/50">/yr</span>
            </span>
          </div>
          <p className="font-satoshi text-sm text-ivory/70 leading-relaxed mb-4">
            {selected.description}
          </p>
          <ul className="space-y-2">
            {selected.benefits.map((b) => (
              <li
                key={b}
                className="font-satoshi text-sm text-ivory/70 flex items-start gap-2"
              >
                <span className="text-brass mt-0.5">·</span>
                {b}
              </li>
            ))}
          </ul>
        </div>
      )}

      {error && <p className="mb-4 font-satoshi text-sm text-[#C97A7A]">{error}</p>}

      <button
        onClick={pay}
        disabled={busy}
        className="w-full bg-brass text-ink py-4 font-satoshi text-sm font-bold tracking-[0.25em] uppercase hover:bg-brass-bright transition-colors disabled:opacity-50"
      >
        {busy ? "Processing…" : "Pay with Card"}
      </button>
      <p className="mt-4 text-center font-satoshi text-xs text-ivory/40">
        {stripeEnabled
          ? "Secure checkout via Stripe."
          : "Demo mode — payment is simulated. No real card is charged."}
      </p>
    </div>
  );
}

import { redirect } from "next/navigation";
import PaymentClient from "@/components/PaymentClient";
import { getSession } from "@/lib/auth";
import { findUserById, listTiers } from "@/lib/db";
import { isStripeConfigured } from "@/lib/stripe";

export default async function PaymentPage({
  searchParams,
}: {
  searchParams: Promise<{ canceled?: string }>;
}) {
  const session = await getSession();
  if (!session) redirect("/login?redirect=/payment");
  const user = await findUserById(session.userId);
  if (!user) redirect("/login");

  const params = await searchParams;
  const tiers = await listTiers();
  const defaultTier =
    user.membership_tier && tiers.some((t) => t.name === user.membership_tier)
      ? user.membership_tier
      : "Founding Member";

  return (
    <main className="min-h-screen flex items-center justify-center px-6 py-16 bg-ink">
      <div className="w-full max-w-lg">
        <PaymentClient
          tiers={tiers.map((t) => ({
            id: t.id,
            name: t.name,
            price_cents: t.price_cents,
            description: t.description,
            benefits: t.benefits,
          }))}
          defaultTier={defaultTier}
          canceled={params.canceled === "true"}
          stripeEnabled={isStripeConfigured}
        />
      </div>
    </main>
  );
}

import { NextResponse } from "next/server";
import { verifyWebhookSignature } from "@/lib/stripe";
import {
  createPayment,
  findUserById,
  updateUserRole,
  listAllPayments,
} from "@/lib/db";

export async function POST(request: Request) {
  const rawBody = await request.text();
  const signature = request.headers.get("stripe-signature") ?? "";

  const event = verifyWebhookSignature(rawBody, signature);
  if (!event) {
    return NextResponse.json({ error: "Invalid signature" }, { status: 400 });
  }

  if (event.type === "checkout.session.completed") {
    const session = event.data.object as {
      id: string;
      client_reference_id?: string;
      metadata?: { tier?: string; user_id?: string };
      payment_intent?: string | null;
      amount_total?: number;
    };

    const userId = session.metadata?.user_id ?? session.client_reference_id ?? "";
    const tier = session.metadata?.tier ?? "Founding Member";
    const user = await findUserById(userId);
    if (user) {
      const existing = (await listAllPayments()).find(
        (p) => p.stripe_session_id === session.id
      );
      if (!existing) {
        const expiresAt = new Date(Date.now() + 365 * 86400000).toISOString();
        await createPayment({
          user_id: userId,
          stripe_session_id: session.id,
          stripe_payment_intent:
            typeof session.payment_intent === "string" ? session.payment_intent : null,
          amount_cents: session.amount_total ?? 0,
          currency: "usd",
          status: "completed",
          membership_tier: tier,
          paid_at: new Date().toISOString(),
          expires_at: expiresAt,
        });
        await updateUserRole(userId, "member", {
          membership_tier: tier,
          membership_expires_at: expiresAt,
        });
      }
    }
  }

  return NextResponse.json({ received: true });
}

"use client";

import { useEffect, useState } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { useToast } from "@/components/ui/Toast";
import { formatCurrency, formatDate } from "@/lib/utils";

interface Payment {
  id: string;
  amount_cents: number;
  currency: string;
  status: string;
  membership_tier: string;
  paid_at: string | null;
  created_at: string;
}

const TIERS = [
  { name: "Basic", price_cents: 120000, perks: ["Access to The Salon", "Members-only events", "House concierge"] },
  { name: "Premium", price_cents: 220000, perks: ["Everything in Basic", "Priority event RSVP", "Private dining access"] },
  { name: "VIP", price_cents: 350000, perks: ["Everything in Premium", "Founding table at cellar dinners", "Dedicated concierge line"] },
];

export default function PaymentsPage() {
  const router = useRouter();
  const params = useSearchParams();
  const { toast } = useToast();
  const [payments, setPayments] = useState<Payment[]>([]);
  const [currentTier, setCurrentTier] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [busy, setBusy] = useState<string | null>(null);

  useEffect(() => {
    Promise.all([
      fetch("/api/profile").then((r) => r.json()),
      fetch("/api/payments").then((r) => r.json()),
    ])
      .then(([p, pay]) => {
        setCurrentTier(p.user?.membership_tier ?? null);
        setPayments(pay.payments ?? []);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, []);

  useEffect(() => {
    if (params.get("success")) {
      toast("Membership updated.", "success");
      router.replace("/dashboard/payments");
    } else if (params.get("canceled")) {
      toast("Checkout canceled.", "info");
      router.replace("/dashboard/payments");
    }
  }, [params, router, toast]);

  async function checkout(tierName: string) {
    setBusy(tierName);
    try {
      const res = await fetch("/api/payments/checkout", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ tier: tierName }),
      });
      const data = await res.json();
      if (res.ok && data.ok) {
        if (data.url) {
          window.location.href = data.url;
        } else {
          router.push(data.redirect ?? "/dashboard/payments?success=1");
          router.refresh();
        }
      } else {
        toast(data.error ?? "Checkout failed.", "error");
      }
    } catch {
      toast("Network error.", "error");
    }
    setBusy(null);
  }

  if (loading) {
    return (
      <main className="max-w-5xl mx-auto px-6 py-12">
        <p className="font-satoshi text-sm text-ivory/50">Loading…</p>
      </main>
    );
  }

  return (
    <main className="max-w-5xl mx-auto px-6 py-12">
      <p className="font-satoshi text-xs tracking-[0.3em] uppercase text-brass mb-2">Membership</p>
      <h1 className="font-playfair text-4xl text-ivory mb-8">Payments</h1>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-12">
        {TIERS.map((t) => {
          const isCurrent = currentTier === t.name;
          return (
            <div
              key={t.name}
              className={`border p-6 bg-charcoal-soft flex flex-col ${isCurrent ? "border-brass" : "border-ivory/15"}`}
            >
              <div className="flex items-center justify-between mb-2">
                <h2 className="font-playfair text-2xl text-ivory">{t.name}</h2>
                {isCurrent && (
                  <span className="font-satoshi text-[10px] tracking-widest uppercase text-brass border border-brass px-2 py-0.5">
                    Current
                  </span>
                )}
              </div>
              <p className="font-playfair text-3xl text-brass mb-4">
                {formatCurrency(t.price_cents)}
                <span className="font-satoshi text-sm text-ivory/50"> /yr</span>
              </p>
              <ul className="space-y-2 mb-6 flex-1">
                {t.perks.map((p) => (
                  <li key={p} className="font-satoshi text-sm text-ivory/70 flex items-start gap-2">
                    <span className="text-brass mt-0.5">·</span>
                    {p}
                  </li>
                ))}
              </ul>
              {isCurrent ? (
                <button disabled className="w-full font-satoshi text-xs tracking-[0.2em] uppercase text-ivory/40 border border-ivory/15 py-3">
                  Your Tier
                </button>
              ) : (
                <button
                  onClick={() => checkout(t.name)}
                  disabled={busy === t.name}
                  className={`w-full font-satoshi text-xs tracking-[0.2em] uppercase py-3 transition-colors disabled:opacity-50 ${
                    currentTier ? "border border-brass text-brass hover:bg-brass hover:text-ink" : "bg-brass text-ink border border-brass hover:bg-brass-bright"
                  }`}
                >
                  {busy === t.name ? "Processing…" : `Select ${t.name}`}
                </button>
              )}
            </div>
          );
        })}
      </div>

      <h2 className="font-playfair text-2xl text-ivory mb-4">Payment History</h2>
      {payments.length === 0 ? (
        <p className="font-satoshi text-sm text-ivory/50">No payments yet. Select a tier above to begin.</p>
      ) : (
        <div className="border border-ivory/15 overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b border-ivory/15 bg-ink">
                {["Date", "Tier", "Amount", "Status"].map((h) => (
                  <th key={h} className="text-left font-satoshi text-xs tracking-widest uppercase text-ivory/50 px-4 py-3">{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {payments.map((p) => (
                <tr key={p.id} className="border-b border-ivory/10 last:border-0">
                  <td className="px-4 py-3 font-satoshi text-sm text-ivory/80">{formatDate(p.paid_at ?? p.created_at)}</td>
                  <td className="px-4 py-3 font-satoshi text-sm text-ivory/80">{p.membership_tier}</td>
                  <td className="px-4 py-3 font-satoshi text-sm text-ivory/80">{formatCurrency(p.amount_cents)}</td>
                  <td className="px-4 py-3 font-satoshi text-sm">
                    <span className={p.status === "completed" ? "text-[#7DDA5A]" : p.status === "refunded" ? "text-[#C97A7A]" : "text-ivory/50"}>
                      {p.status}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </main>
  );
}

