html {
  scroll-behavior: smooth;
}

body {
  background-color: #0A0A0B;
  color: #F5F0EB;
  font-family: 'Satoshi', system-ui, sans-serif;
  -webkit-font-smoothing: antialiased;
}

/* Brass gradient text utility */
.text-brass-gradient {
  background: linear-gradient(135deg, #C5A55A 0%, #D8B978 50%, #C5A55A 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* Subtle brass border glow */
.brass-glow {
  box-shadow: 0 0 20px rgba(197, 165, 90, 0.12);
}

/* Divider line */
.salon-divider {
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(197,165,90,0.45), transparent);
}

/* Custom scrollbar */
::-webkit-scrollbar { width: 6px; }
::-webkit-scrollbar-track { background: #0A0A0B; }
::-webkit-scrollbar-thumb { background: #333; border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: #C5A55A; }

input:focus { outline: none; }

