"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { Input, Select } from "@/components/ui/Input";
import Button from "@/components/ui/Button";
import { REFERRAL_SOURCES } from "@/types";

export default function SignupPage() {
  const router = useRouter();
  const [form, setForm] = useState({
    name: "",
    email: "",
    password: "",
    phone: "",
    referral_source: "",
  });
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  function set<K extends keyof typeof form>(key: K, value: string) {
    setForm((f) => ({ ...f, [key]: value }));
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError("");
    setLoading(true);
    try {
      const res = await fetch("/api/auth/signup", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: form.name,
          email: form.email,
          password: form.password,
          phone: form.phone || null,
          referral_source: form.referral_source || null,
        }),
      });
      const data = await res.json();
      if (res.ok && data.ok) {
        router.push(data.redirect ?? "/dashboard");
        router.refresh();
      } else {
        setError(data.error ?? "Could not create account.");
      }
    } catch {
      setError("Network error. Please try again.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <main className="min-h-screen flex items-center justify-center px-6 py-16 bg-ink">
      <div className="w-full max-w-md">
        <div className="text-center mb-10">
          <Link href="/" className="font-archivo text-3xl text-ivory tracking-tight">
            GOON
          </Link>
          <p className="mt-2 font-satoshi text-xs tracking-[0.3em] uppercase text-brass">
            Request Membership
          </p>
        </div>

        <div className="border border-brass/20 bg-charcoal-soft p-8">
          <form onSubmit={handleSubmit} className="space-y-5">
            <Input
              id="name"
              label="Full Name"
              required
              value={form.name}
              onChange={(e) => set("name", e.target.value)}
              placeholder="Your name"
            />
            <Input
              id="email"
              type="email"
              label="Email"
              required
              value={form.email}
              onChange={(e) => set("email", e.target.value)}
              placeholder="you@domain.com"
            />
            <Input
              id="password"
              type="password"
              label="Password"
              required
              value={form.password}
              onChange={(e) => set("password", e.target.value)}
              placeholder="At least 6 characters"
            />
            <Input
              id="phone"
              type="tel"
              label="Phone (optional)"
              value={form.phone}
              onChange={(e) => set("phone", e.target.value)}
              placeholder="+1 (310) 555-0000"
            />
            <Select
              id="referral"
              label="How did you hear about us?"
              placeholder="Select a source"
              value={form.referral_source}
              onChange={(e) => set("referral_source", e.target.value)}
              options={REFERRAL_SOURCES.map((s) => ({ value: s, label: s }))}
            />
            {error && (
              <p className="font-satoshi text-sm text-[#C97A7A]">{error}</p>
            )}
            <Button type="submit" loading={loading} className="w-full">
              Create Account
            </Button>
          </form>
          <p className="mt-6 font-satoshi text-xs text-ivory/45 leading-relaxed">
            Creating an account submits a membership application for review.
            Dues are only collected after approval.
          </p>
        </div>

        <p className="mt-6 text-center font-satoshi text-sm text-ivory/60">
          Already a member?{" "}
          <Link href="/login" className="text-brass hover:underline">
            Sign in
          </Link>
        </p>
      </div>
    </main>
  );
}

import { ReactNode } from "react";
import Link from "next/link";
import { findUserById, getSession } from "@/lib/auth";
import { redirect } from "next/navigation";
import { initials } from "@/lib/utils";
import SidebarNav from "@/components/layout/SidebarNav";

const NAV = [
  { href: "/dashboard", label: "Home" },
  { href: "/dashboard/profile", label: "Profile" },
  { href: "/dashboard/directory", label: "Directory" },
  { href: "/dashboard/events", label: "Events" },
  { href: "/dashboard/bookings", label: "Parlors" },
  { href: "/dashboard/payments", label: "Payments" },
  { href: "/dashboard/forum", label: "Forum" },
];

export default async function DashboardLayout({ children }: { children: ReactNode }) {
  const session = await getSession();
  if (!session) redirect("/login?redirect=/dashboard");
  const user = await findUserById(session.userId);
  if (!user) redirect("/login");
  if (user.role === "pending_payment") redirect("/payment");

  const nav = [...NAV];
  if (user.role === "admin") nav.push({ href: "/admin", label: "Admin" });

  return (
    <div className="min-h-screen bg-ink flex flex-col md:flex-row">
      <aside className="hidden md:flex md:w-[240px] md:shrink-0 md:flex-col md:border-r md:border-brass/20 md:bg-charcoal md:sticky md:top-0 md:h-screen">
        <div className="px-6 py-6 border-b border-brass/15">
          <Link href="/dashboard" className="font-archivo text-xl text-ivory">
            GOON
          </Link>
          <p className="mt-1 font-satoshi text-[10px] tracking-[0.25em] uppercase text-ivory/40 truncate">
            {user.name}
          </p>
        </div>
        <SidebarNav nav={nav} />
        <form action="/api/auth/logout" method="POST" className="px-3 mt-2">
          <button
            type="submit"
            className="w-full text-left px-4 py-3 font-satoshi text-sm tracking-wide text-ivory/40 hover:text-[#C97A7A] transition-colors"
          >
            Sign Out
          </button>
        </form>
      </aside>

      <div className="flex-1 min-w-0">
        <header className="md:hidden flex items-center justify-between border-b border-brass/20 bg-charcoal px-5 py-4 sticky top-0 z-30">
          <Link href="/dashboard" className="font-archivo text-xl text-ivory">
            GOON
          </Link>
          <Link href="/dashboard/profile">
            <span className="w-9 h-9 rounded-full bg-brass/15 border border-brass/40 text-brass flex items-center justify-center font-satoshi text-xs font-bold">
              {initials(user.name)}
            </span>
          </Link>
        </header>
        {children}
      </div>
    </div>
  );
}

import Link from "next/link";
import { redirect } from "next/navigation";
import Badge from "@/components/ui/Badge";
import { getSession } from "@/lib/auth";
import {
  findUserById,
  listEvents,
  countAttendees,
} from "@/lib/db";
import { formatDate, formatTime, isPast } from "@/lib/utils";

export default async function DashboardPage({
  searchParams,
}: {
  searchParams: Promise<{ payment?: string }>;
}) {
  const session = await getSession();
  if (!session) redirect("/login?redirect=/dashboard");
  const user = await findUserById(session.userId);
  if (!user) redirect("/login");
  if (user.role === "pending_payment") redirect("/payment");

  const params = await searchParams;
  const showSuccess = params.payment === "success";

  const allEvents = await listEvents();
  const upcoming = allEvents.filter((e) => !isPast(e.date)).slice(0, 3);
  const upcomingWithCounts = await Promise.all(
    upcoming.map(async (e) => ({ event: e, count: await countAttendees(e.id) }))
  );

  const statusBadge =
    user.role === "admin" ? (
      <Badge tone="brass">Administrator</Badge>
    ) : user.role === "member" ? (
      <Badge tone="green">Active Member</Badge>
    ) : (
      <Badge tone="amber">Under Review</Badge>
    );

  return (
    <main className="max-w-6xl mx-auto px-6 py-12 space-y-12">
      {showSuccess && (
        <div className="bg-brass/10 border border-brass/30 px-6 py-3 text-center font-satoshi text-sm text-brass">
          Welcome to the house — your membership is active.
        </div>
      )}

      <section>
        <p className="font-satoshi text-xs tracking-[0.3em] uppercase text-brass mb-3">
          Welcome
        </p>
        <div className="flex flex-col sm:flex-row sm:items-end sm:justify-between gap-4">
          <h1 className="font-playfair text-4xl md:text-5xl text-ivory">
            {user.name}
          </h1>
          <div className="flex items-center gap-3">
            {statusBadge}
            {user.membership_tier && (
              <span className="font-satoshi text-sm text-ivory/60">
                {user.membership_tier}
              </span>
            )}
          </div>
        </div>
        {user.membership_expires_at && (
          <p className="mt-2 font-satoshi text-sm text-ivory/45">
            Membership renews {formatDate(user.membership_expires_at)}.
          </p>
        )}
      </section>

      {user.role === "pending" ? (
        <div className="border border-brass/20 bg-charcoal-soft p-8">
          <h2 className="font-playfair text-2xl text-ivory mb-3">
            Your application is under review.
          </h2>
          <p className="font-satoshi text-sm text-ivory/70 leading-relaxed">
            The house steward reviews each application personally. You will be
            contacted at <span className="text-brass">{user.email}</span> when
            your membership is approved. There is nothing more to do here.
          </p>
        </div>
      ) : (
        <>
          <section className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <Tile
              href="/dashboard/events"
              label="Upcoming Events"
              value={`${upcoming.length}`}
            />
            <Tile
              href="/dashboard/directory"
              label="Member Directory"
              value="Browse"
            />
            <Tile
              href="/dashboard/bookings"
              label="Book a Parlor"
              value="Reserve"
            />
          </section>

          <section>
            <div className="flex items-center justify-between mb-5">
              <h2 className="font-playfair text-2xl text-ivory">
                Coming up at the house
              </h2>
              <Link
                href="/dashboard/events"
                className="font-satoshi text-xs tracking-[0.2em] uppercase text-brass hover:underline"
              >
                All events
              </Link>
            </div>
            {upcoming.length === 0 ? (
              <p className="font-satoshi text-sm text-ivory/50">
                No events scheduled yet.
              </p>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                {upcomingWithCounts.map(({ event, count }) => (
                  <Link
                    key={event.id}
                    href={`/dashboard/events/${event.id}`}
                    className="block border border-ivory/10 bg-charcoal-soft p-6 hover:border-brass/50 transition-colors"
                  >
                    <p className="font-satoshi text-xs tracking-[0.2em] uppercase text-brass">
                      {formatDate(event.date)} · {formatTime(event.time)}
                    </p>
                    <p className="font-playfair text-lg text-ivory mt-2">
                      {event.title}
                    </p>
                    <p className="font-satoshi text-xs text-ivory/50 mt-2">
                      {count} attending
                    </p>
                  </Link>
                ))}
              </div>
            )}
          </section>
        </>
      )}
    </main>
  );
}

function Tile({
  href,
  label,
  value,
}: {
  href: string;
  label: string;
  value: string;
}) {
  return (
    <Link
      href={href}
      className="group border border-ivory/10 bg-charcoal-soft p-8 hover:border-brass/50 hover:-translate-y-0.5 transition-all duration-300"
    >
      <p className="font-satoshi text-xs tracking-[0.2em] uppercase text-ivory/50">
        {label}
      </p>
      <p className="font-playfair text-3xl text-ivory mt-1 group-hover:text-brass transition-colors">
        {value}
      </p>
    </Link>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { Input } from "@/components/ui/Input";
import Badge from "@/components/ui/Badge";
import { useToast } from "@/components/ui/Toast";
import { formatDate } from "@/lib/utils";

interface ProfileData {
  id: string;
  name: string;
  email: string;
  phone: string | null;
  referral_source: string | null;
  role: string;
  membership_tier: string | null;
  membership_expires_at: string | null;
  created_at: string;
}

export default function ProfilePage() {
  const router = useRouter();
  const { toast } = useToast();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");
  const [profile, setProfile] = useState<ProfileData | null>(null);
  const [name, setName] = useState("");
  const [phone, setPhone] = useState("");

  useEffect(() => {
    fetch("/api/profile")
      .then((r) => r.json())
      .then((data) => {
        if (data.user) {
          setProfile(data.user);
          setName(data.user.name);
          setPhone(data.user.phone ?? "");
        } else {
          router.replace("/login?redirect=/dashboard/profile");
        }
        setLoading(false);
      })
      .catch(() => {
        setError("Unable to load your profile.");
        setLoading(false);
      });
  }, [router]);

  async function save(e: React.FormEvent) {
    e.preventDefault();
    setSaving(true);
    setError("");
    try {
      const res = await fetch("/api/profile", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name, phone }),
      });
      const data = await res.json();
      if (res.ok) {
        toast("Profile updated.", "success");
      } else {
        setError(data.error ?? "Could not save.");
      }
    } catch {
      setError("Network error.");
    } finally {
      setSaving(false);
    }
  }

  if (loading) {
    return (
      <main className="max-w-2xl mx-auto px-6 py-12">
        <p className="font-satoshi text-sm text-ivory/50">Loading…</p>
      </main>
    );
  }
  if (!profile) return null;

  const statusTone =
    profile.role === "admin" ? "brass" : profile.role === "member" ? "green" : "amber";

  return (
    <main className="max-w-2xl mx-auto px-6 py-12">
      <p className="font-satoshi text-xs tracking-[0.3em] uppercase text-brass mb-2">
        Account
      </p>
      <h1 className="font-playfair text-4xl text-ivory mb-8">Profile</h1>

      <div className="border border-ivory/10 bg-charcoal-soft p-8 mb-8">
        <div className="flex flex-wrap items-center gap-3 mb-6">
          <Badge tone={statusTone}>{profile.role}</Badge>
          {profile.membership_tier && (
            <span className="font-satoshi text-sm text-ivory/70">
              {profile.membership_tier}
            </span>
          )}
        </div>

        <form onSubmit={save} className="space-y-5">
          <Input
            id="name"
            label="Full Name"
            required
            value={name}
            onChange={(e) => setName(e.target.value)}
          />
          <Input
            id="email"
            label="Email"
            value={profile.email}
            disabled
            hint="Email cannot be changed here. Contact the steward."
          />
          <Input
            id="phone"
            label="Phone"
            type="tel"
            value={phone}
            onChange={(e) => setPhone(e.target.value)}
            placeholder="+1 (310) 555-0000"
          />
          {error && <p className="font-satoshi text-sm text-[#C97A7A]">{error}</p>}
          <button
            type="submit"
            disabled={saving}
            className="bg-brass text-ink px-8 py-3 font-satoshi text-xs tracking-[0.2em] uppercase hover:bg-brass-bright transition-colors disabled:opacity-50"
          >
            {saving ? "Saving…" : "Save Changes"}
          </button>
        </form>
      </div>

      <div className="border border-ivory/10 bg-charcoal-soft p-6 space-y-3 font-satoshi text-sm">
        <div className="flex justify-between">
          <span className="text-ivory/50">Referral source</span>
          <span className="text-ivory/85">{profile.referral_source ?? "—"}</span>
        </div>
        <div className="flex justify-between">
          <span className="text-ivory/50">Joined</span>
          <span className="text-ivory/85">{formatDate(profile.created_at)}</span>
        </div>
        {profile.membership_expires_at && (
          <div className="flex justify-between">
            <span className="text-ivory/50">Membership renews</span>
            <span className="text-ivory/85">{formatDate(profile.membership_expires_at)}</span>
          </div>
        )}
      </div>

      <p className="mt-8">
        <Link
          href="/dashboard"
          className="font-satoshi text-xs text-brass hover:underline"
        >
          ← Back to dashboard
        </Link>
      </p>
    </main>
  );
}

