export default async function AdminApplicationDetailPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;
  const app = await getApplication(id);
  if (!app) notFound();

  const rows: { label: string; value: string }[] = [
    { label: "Email", value: app.email },
    { label: "Phone", value: app.phone ?? "—" },
    { label: "Referral source", value: app.referral_source ?? "—" },
    { label: "Submitted", value: formatDate(app.created_at) },
    ...(app.reviewed_at
      ? [{ label: "Reviewed", value: formatDate(app.reviewed_at) }]
      : []),
    ...(app.rejection_reason
      ? [{ label: "Rejection reason", value: app.rejection_reason }]
      : []),
  ];

  return (
    <main className="p-6 md:p-10 max-w-2xl">
      <Link
        href="/admin/applications"
        className="font-satoshi text-xs tracking-[0.2em] uppercase text-brass hover:underline"
      >
        ← Applications
      </Link>

      <div className="mt-4 flex items-center gap-3 mb-6">
        <h1 className="font-playfair text-3xl text-ivory">{app.full_name}</h1>
        <Badge tone={statusTone(app.status)}>{app.status}</Badge>
      </div>

      <div className="border border-ivory/10 bg-charcoal-soft p-6 mb-8">
        <dl className="space-y-4">
          {rows.map((r) => (
            <div key={r.label} className="flex flex-col">
              <dt className="font-satoshi text-[10px] tracking-[0.2em] uppercase text-ivory/40">
                {r.label}
              </dt>
              <dd className="font-satoshi text-sm text-ivory/85 mt-1">
                {r.value}
              </dd>
            </div>
          ))}
        </dl>
      </div>

      {app.status === "pending" && (
        <div className="flex gap-3">
          <form
            action={async () => {
              "use server";
              const { updateApplicationStatus, logAudit, updateUserRole } =
                await import("@/lib/db");
              const { getSession } = await import("@/lib/auth");
              const session = await getSession();
              if (!session || session.role !== "admin") return;
              await updateApplicationStatus(id, "approved", session.userId);
              if (app.user_id) {
                await updateUserRole(app.user_id, "pending_payment", {
                  membership_tier: "Basic",
                });
              }
            }}
          >
            <button
              type="submit"
              className="bg-brass text-ink px-6 py-3 font-satoshi text-xs tracking-[0.2em] uppercase hover:bg-brass-bright transition-colors"
            >
              Approve
            </button>
          </form>
          <form
            action={async (formData: FormData) => {
              "use server";
              const reason = formData.get("reason") as string;
              const { updateApplicationStatus } = await import("@/lib/db");
              const { getSession } = await import("@/lib/auth");
              const session = await getSession();
              if (!session || session.role !== "admin") return;
              await updateApplicationStatus(
                id,
                "rejected",
                session.userId,
                reason || undefined
              );
            }}
          >
            <input
              type="text"
              name="reason"
              placeholder="Rejection reason (optional)"
              className="w-full mb-2 bg-charcoal-soft border border-ivory/15 px-4 py-2 text-ivory font-satoshi text-sm"
            />
            <button
              type="submit"
              className="bg-[#8B3A3A] text-ivory px-6 py-3 font-satoshi text-xs tracking-[0.2em] uppercase hover:brightness-110 transition-colors"
            >
              Reject
            </button>
          </form>
        </div>
      )}
    </main>
  );
}

